;/* CityRail Help: Apple-style FAQ / changelog owner. */
(function(){
  'use strict';
  if(window.CityRailHelp && window.CityRailHelp.version) return;
  function card(title, body){
    return '<section style="border:1px solid rgba(255,255,255,.10);background:rgba(255,255,255,.055);border-radius:16px;padding:14px 16px;">'
      + '<h3 style="margin:0 0 7px;font-size:15px;line-height:1.35;font-weight:800;color:rgba(255,255,255,.94);letter-spacing:0;">' + title + '</h3>'
      + '<div style="font-size:13px;line-height:1.68;color:rgba(255,255,255,.66);">' + body + '</div></section>';
  }
  function modal(title, html){
    let root=document.getElementById('cityrail-info-modal');
    if(!root){
      root=document.createElement('div');
      root.id='cityrail-info-modal';
      root.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.42);display:none;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(28px) saturate(170%);-webkit-backdrop-filter:blur(28px) saturate(170%);';
      root.innerHTML='<div style="width:min(820px,94vw);max-height:min(82vh,760px);overflow:auto;background:rgba(28,28,30,.82);color:#f5f5f7;border:1px solid rgba(255,255,255,.16);border-radius:24px;box-shadow:0 34px 100px rgba(0,0,0,.46),inset 0 1px 0 rgba(255,255,255,.08);padding:24px 26px 26px;font-family:-apple-system,BlinkMacSystemFont,\'SF Pro Display\',\'PingFang SC\',sans-serif;">'
        + '<div style="position:sticky;top:-24px;z-index:1;display:flex;align-items:center;justify-content:space-between;gap:16px;margin:-24px -26px 18px;padding:22px 26px 16px;background:rgba(28,28,30,.86);backdrop-filter:blur(22px) saturate(160%);-webkit-backdrop-filter:blur(22px) saturate(160%);border-bottom:1px solid rgba(255,255,255,.08);">'
        + '<div><div style="font-size:12px;font-weight:700;letter-spacing:.12em;color:rgba(255,255,255,.38);text-transform:uppercase;">CityRail Help</div><h2 data-role="title" style="margin:5px 0 0;font-size:24px;line-height:1.15;font-weight:850;letter-spacing:0;"></h2></div>'
        + '<button type="button" data-role="close" aria-label="关闭" style="width:34px;height:34px;border:1px solid rgba(255,255,255,.12);border-radius:50%;background:rgba(255,255,255,.08);color:rgba(255,255,255,.82);font-size:18px;line-height:1;cursor:pointer;">×</button>'
        + '</div><div data-role="body" style="display:grid;gap:10px;font-size:13px;line-height:1.65;color:rgba(255,255,255,.72);"></div></div>';
      document.body.appendChild(root);
      root.addEventListener('click',function(e){ if(e.target===root || (e.target&&e.target.getAttribute('data-role')==='close')) root.style.display='none'; });
      document.addEventListener('keydown',function(e){ if(e.key==='Escape'&&root.style.display!=='none') root.style.display='none'; });
    }
    root.querySelector('[data-role="title"]').textContent=title;
    root.querySelector('[data-role="body"]').innerHTML=html;
    root.style.display='flex';
  }
  const faq=[
    card('进入游戏按钮在哪里？点了以后会发生什么？','首页中央的“进入游戏”会进入城市选择/游戏界面。如果你已经登录、注册或使用邀请码进入，按钮会直接把你带到当前游戏流程；如果页面只显示地图，说明已经在游戏内，可以从顶部工具栏继续操作。'),
    card('选择城市后为什么不是自动出现线路？','城市只决定地图中心、客流画像和站名风格，不会替你预置线路。进入城市后请点击顶部“新建线路”，在地图上放站并连接成线；这样每个城市都能按你自己的规划展开。'),
    card('“新建线路”怎么用？','点击“新建线路”，填写线路名称和颜色后开始施画。左键在地图上放置车站，右键可以放置只改变走向的节点；完成一条线后再确认线路配置，系统才会把它纳入运营模拟。'),
    card('车站和节点有什么区别？','车站会产生候车、上下车、换乘和客流统计；节点只是调整线路弯曲和走向，不承载乘客。想让线路更贴合道路或河流时用节点，想服务客流点时用车站。'),
    card('底部播放按钮和速度条怎么用？','底部“▶”用于开始/暂停仿真，左侧时间显示当前运营时刻，速度条控制模拟倍速。刚建线调试时建议用较低倍速，确认列车能进站、折返和载客后再拉高速度。'),
    card('控制中心是看什么的？','“控制中心”是全网运营仪表盘，可以看总客流、候车、客强、线路状态、重点车站和告警。发现某条线拥挤、站台爆满或车站压力异常时，先打开控制中心定位问题。'),
    card('线路配置和快慢车配置有什么用？','“线路配置”用于调整车型、编组、速度、发车间隔、首末班和快慢车。普通线先保证稳定运行；长距离、大站客流明显时，再启用快车、越行站和待避组织。'),
    card('怎么修改已经建好的线路？','点击线路或线路上的车站进入配置/详情面板，可以继续添加车站、添加节点、调整线路参数。修改后系统会重建线路拓扑、地图路径和列车运行路径，避免旧路径残留。'),
    card('怎么删除节点？','在线路配置中进入添加节点/车站的编辑视图后，线路上的三角形节点可以被选中删除；删除节点只改变线路走向，不删除车站和客流。删除后系统会重新整理节点顺序。'),
    card('怎么建设支线？','先点击一座既有车站，车站详情里会出现“建设支线”。选择支线车型、编组和速度后开始施画，左键继续放支线车站，右键放节点；支线会和主线在分出站形成换乘关系。'),
    card('设置里的保存、读取、导入、导出怎么选？','“保存/读取”使用当前浏览器本地存档，适合日常继续玩；“导出/导入”使用 JSON 文件，适合备份、换浏览器、发给别人或恢复大版本前的线网。'),
    card('刚进入游戏为什么只有地图，没有线路？','CityRail 不预置固定线路，城市底图只是你的画布。点击“新建线路”后在地图上放置车站和节点，或读取已有存档，线路、车站和列车才会出现。'),
    card('新手应该先做什么？','先画一条短而直的主线，连接住宅、办公、学校、商场或交通枢纽等不同功能区。线路闭合前不要急着开很高速度，先确认站距、换乘和终点折返都正常。'),
    card('为什么我的车站突然很多人排队？','客流来自城市功能区、时间段和换乘路径。早晚高峰会放大通勤需求，换乘站和大型枢纽更容易积压；如果候车一直上升，通常要加车、缩短发车间隔、提高编组或调整线路走向。'),
    card('全网总客流、全网候车、全网客强分别是什么意思？','全网总客流表示系统当前累计承接的客流规模；全网候车是还在站内等待上车的人；全网客强约等于已送达客流除以线网总长度，用来判断单位线路长度承受了多少客流压力。'),
    card('为什么客强会变，不是线路越长越好吗？','客强是“客流 / 线网长度”的密度指标。盲目拉长线路会稀释指标，但不一定改善运营；真正有效的是把线路接到有需求的地方，并让列车能稳定把人送走。'),
    card('列车为什么会堵在站外或一直停站？','常见原因是前方站台被占用、终点折返没有释放、发车间隔过密，或快慢车越行关系没有足够空间。可以在 ATS 里观察列车状态，必要时放行、扣车、调整发班或增加越行站。'),
    card('快车和普通车到底怎么用？','快车适合长线路和客流集中的大站，不适合所有站都设成快车停靠。现实逻辑是快车跳过小站节省时间，普通车服务沿线小站；如果没有越行条件，快车也可能被前方普通车拖住。'),
    card('越行站和待避有什么关系？','越行站可以理解为有额外到发线或站台能力的车站。普通车在这里让出主线，快车通过或先发；如果线路上没有合适越行站，快慢车混跑就很容易互相干扰。'),
    card('运行图里的红线和蓝线怎么看？','红色代表普通车，蓝色代表快车。斜线越平表示速度越慢，密集交叉或贴得很近说明追踪间隔紧张；如果蓝线长期贴在红线后面，说明快车优势没有发挥出来。'),
    card('站距应该怎么控制？','站距太短会让列车频繁启停，旅行速度下降；站距太长又会漏掉沿线客流。市区主线通常适合密一点，郊区或机场线可以拉长站距，并配合快车提升长距离效率。'),
    card('线路越长越好吗？','不一定。超长线路会带来更长周转时间，终点折返压力也会变大；如果中段客流很弱，长线可能只是增加运营成本。可以考虑分段、支线或换乘，而不是一条线包打天下。'),
    card('什么时候应该新建线路，什么时候只加车？','如果同一条线路的站台和区间都拥挤，先加车或缩短间隔。若客流来自另一片城区，或者大量乘客绕路换乘，就更适合新建线路或增加换乘通道。'),
    card('列车数量是不是越多越好？','不是。列车太少会候车爆炸，太多会追踪过密、站外等待和折返拥堵。观察 ATS 和运行图，如果列车已经首尾相接，再加车通常只会更堵。'),
    card('发车间隔怎么判断合理？','看候车增长速度和列车是否能顺畅进站。候车持续上升但线路不堵，说明间隔偏大；列车频繁站外等待、运行图线条挤在一起，说明间隔已经太小。'),
    card('为什么换乘站压力特别大？','换乘站会叠加多条线路的进站、出站和换乘人流。现实里换乘通道、站台宽度和线网结构都会影响效率；游戏里可以通过增加并行线路、优化换乘位置或分流客流来缓解。'),
    card('为什么有些乘客看起来绕远路？','乘客会基于可达线路、换乘和目的地选择路径。线网早期选择少时，绕路是正常现象；当你补齐横向线、环线或更直接的换乘点后，路径会更接近现实城市出行。'),
    card('环线有什么用？','环线适合承担外围分流和跨区换乘，能减少所有人都挤进中心换乘站。但环线如果站距过密、速度过低，也可能变成慢速观光线，需要和放射线形成互补。'),
    card('支线会不会拖慢主线？','会有可能。支线列车汇入主线时会占用运行间隔，如果发车组织不合理，主线会被支线打乱。支线适合低密度区域，客流大时更应该考虑独立线路或更清晰的交路。'),
    card('为什么终点折返会成为瓶颈？','终点站需要列车停车、清客、换向再发车。发车过密时，后车会在终点前排队；可以降低发车密度、增加折返余量，或把线路延伸/改造成更均衡的交路。'),
    card('机场线和市区线有什么不同？','机场线通常站距更长、客流更集中，适合较高速度和快车逻辑。市区线更强调覆盖和换乘，过分追求高速反而可能错过大量短途客流。'),
    card('为什么地图上拖动车站后数据会变？','车站位置改变会影响线路长度、站距、换乘关系和周边功能区吸引力。系统会重算线网长度与相关缓存，所以控制中心里的长度、客强和部分客流结构可能随之变化。'),
    card('什么时候需要看线路统计，什么时候看控制中心？','线路统计适合看单条线的长度、客流、拥挤度和车辆配置。控制中心适合看全网状态、候车、重点车站和运行风险；一个是体检表，一个是实时指挥屏。'),
    card('为什么控制中心数字有时不是每一秒都跳？','控制中心会按快照刷新，避免大存档里每个指标都高频重绘。数据仍在模拟，只是 UI 会合并更新，优先保证地图、调度和列车运行不卡顿。'),
    card('模拟速度调很高会影响判断吗？','会。高倍速会让问题更快暴露，但也更容易错过拥堵形成的过程。调试线路时建议先用中低倍速观察几轮高峰，再把速度拉高做长期压力测试。'),
    card('为什么有时看起来没有乘客上车？','可能是列车已满、乘客方向不匹配、当前站没有这条线方向的候车，或前序缓存还在刷新。先看车站候车方向和列车载客量，再判断是不是线路组织问题。'),
    card('删除线路或车站会影响存档吗？','会影响相关列车、线路路径、换乘关系和等待乘客。操作前最好先保存或导出；如果删除后发现客流异常，重新读取存档比手动恢复更稳。'),
    card('为什么有些功能需要等待一小会儿刷新？','大地图、大客流和长线路会触发缓存与分批计算。游戏会把部分重计算推迟到空闲帧，避免一次性卡住界面；这属于性能保护，不代表数据丢失。'),
    card('保存、读取、导入、导出有什么区别？','保存/读取使用浏览器本地存档，适合日常继续玩。导出会生成 JSON 文件，适合备份或发给别人；导入则读取这个文件并恢复线路、车站、列车和客流状态。'),
    card('大存档卡顿怎么办？','先降低模拟速度，关闭不需要的面板，再检查是否有过密线路、过多列车或大量乘客长期无法上车。游戏会做缓存和低频渲染，但过度堆车、无效线路和极端客流仍会消耗性能。')
  ];
  const changelog=[
    card('v64','线路长度前加“总线网长度”；设置面板删除“存档与诊断”标题和箭头；新增 English mode 开关。'),
    card('v63','修复时间显示归一化，xx:60 自动进位为下一小时 xx:00；设置面板中“导出/导入”按钮替换为“更新日志/常见问题”。'),
    card('v62','清理旧折返/车头调试模块；控制中心新增线网总长度；进站客流改为全网总客流口径。'),
    card('v61','终点折返改为独立状态机，避免列车在终点站长期停靠不折返。'),
    card('v59','既有线路增减节点/车站后，统一重建线路拓扑、地图路径和列车运行路径。')
  ];
  window.CityRailHelp={version:'v178-apple-help',showFaq:function(){modal('常见问题',faq.join(''));},showChangelog:function(){modal('更新日志',changelog.join(''));}};
  window.cityrailShowFaq=window.CityRailHelp.showFaq;
  window.cityrailShowChangelog=window.CityRailHelp.showChangelog;
})();

