      visitorId:visitorId(),
      sessionId:sessionId(),
      path:W.location.pathname||'/',
      build:W.CITYRAIL_BUILD_VERSION||'local',
      loggedIn:!!storeGet('cityrail_auth_token'),
      device:deviceKind(),
