      const latlngs = (Array.isArray(nodes) ? nodes : []).map(n => [num(n && n.lat, NaN), num(n && n.lng, NaN)]).filter(p => Number.isFinite(p[0]) && Number.isFinite(p[1]));
      const poly = W.linePolylines && W.linePolylines[line.id];
