  function safeUser(user) {
    const value = String(user || '').trim();
    return value || 'guest';
  }

  function readJSON(key, fallback) {
    try {
      const raw = localStorage.getItem(key);
      return raw ? JSON.parse(raw) : fallback;
    } catch {
      return fallback;
    }
  }

  function writeJSON(key, value) {
    try { localStorage.setItem(key, JSON.stringify(value)); } catch {}
  }

  function stateKey(user) { return STATE_PREFIX + safeUser(user); }
  function newUserKey(user) { return NEW_USER_PREFIX + safeUser(user); }
  function taskAutoKey(user) { return TASK_AUTO_PREFIX + safeUser(user); }

  function getCurrentUser() {
    try { return safeUser(localStorage.getItem(CURRENT_USER_KEY)); }
    catch { return 'guest'; }
  }

  function setUser(user) {
    const name = safeUser(user);
    try { localStorage.setItem(CURRENT_USER_KEY, name); } catch {}
    return name;
  }

  function markNewUser(user) {
    const name = setUser(user);
    try { localStorage.setItem(newUserKey(name), '1'); } catch {}
  }

  function getState(user) {
    const state = readJSON(stateKey(user), {});
    return {
      shown: Math.max(0, Number(state.shown || 0)),
      never: !!state.never
    };
  }

  function saveStateFor(user, state) {
    writeJSON(stateKey(user), {
      shown: Math.max(0, Number(state.shown || 0)),
      never: !!state.never
    });
  }

  function isNewUser(user) {
    try { return localStorage.getItem(newUserKey(user)) === '1'; }
    catch { return false; }
  }

  function taskAutoShown(user) {
    try { return localStorage.getItem(taskAutoKey(user)) === '1'; }
    catch { return false; }
  }

  function markTaskAutoShown(user) {
    try { localStorage.setItem(taskAutoKey(user), '1'); } catch {}
  }

  function ensureOverlay() {
    let overlay = document.getElementById('cityrail-tutorial-overlay');
    if (overlay) return overlay;
    overlay = document.createElement('div');
    overlay.id = 'cityrail-tutorial-overlay';
    overlay.className = 'cityrail-tutorial-overlay';
    overlay.innerHTML = [
      '<div class="cityrail-tutorial-panel" role="dialog" aria-modal="true" aria-labelledby="cityrail-tutorial-title">',
        '<div class="cityrail-tutorial-top">',
          '<div>',
            '<div class="cityrail-tutorial-kicker" id="cityrail-tutorial-step">CITYRAIL GUIDE</div>',
            '<div class="cityrail-tutorial-title" id="cityrail-tutorial-title"></div>',
          '</div>',
          '<button type="button" class="cityrail-tutorial-close" id="cityrail-tutorial-close" aria-label="关闭">×</button>',
        '</div>',
        '<div class="cityrail-tutorial-body">',
          '<p class="cityrail-tutorial-lede" id="cityrail-tutorial-lede"></p>',
          '<div class="cityrail-tutorial-list" id="cityrail-tutorial-list"></div>',
        '</div>',
        '<div class="cityrail-tutorial-progress" id="cityrail-tutorial-progress"></div>',
        '<div class="cityrail-tutorial-bottom">',
          '<label class="cityrail-tutorial-optout">',
            '<input type="checkbox" id="cityrail-tutorial-never">',
            '<span>以后不再自动弹出</span>',
          '</label>',
          '<div class="cityrail-tutorial-actions">',
            '<button type="button" id="cityrail-tutorial-prev">上一步</button>',
            '<button type="button" class="primary" id="cityrail-tutorial-next">下一步</button>',
          '</div>',
        '</div>',
      '</div>'
    ].join('');
    document.body.appendChild(overlay);

    overlay.querySelector('#cityrail-tutorial-close').addEventListener('click', close);
    overlay.querySelector('#cityrail-tutorial-prev').addEventListener('click', () => showStep(activeStep - 1));
    overlay.querySelector('#cityrail-tutorial-next').addEventListener('click', () => {
      if (activeStep >= slides.length - 1) close();
      else showStep(activeStep + 1);
    });
    overlay.addEventListener('click', event => {
      if (event.target === overlay) close();
    });
    document.addEventListener('keydown', event => {
      if (!overlay.classList.contains('visible')) return;
      if (event.key === 'Escape') close();
      if (event.key === 'ArrowLeft') showStep(activeStep - 1);
      if (event.key === 'ArrowRight') {
        if (activeStep >= slides.length - 1) close();
        else showStep(activeStep + 1);
      }
    });
    return overlay;
  }

	  let activeStep = 0;
	  let activeUser = 'guest';
	  let activeForced = false;
	  let pendingForcedFaq = false;

  function escapeHtml(value) {
    return String(value == null ? '' : value).replace(/[&<>"]/g, ch => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[ch]));
  }

  function showStep(index) {
    const overlay = ensureOverlay();
    activeStep = Math.max(0, Math.min(slides.length - 1, Number(index) || 0));
    const slide = slides[activeStep];
    overlay.querySelector('#cityrail-tutorial-step').textContent = `CITYRAIL GUIDE ${activeStep + 1} / ${slides.length}`;
    overlay.querySelector('#cityrail-tutorial-title').textContent = slide.title;
    overlay.querySelector('#cityrail-tutorial-lede').textContent = slide.lede;
    overlay.querySelector('#cityrail-tutorial-list').innerHTML = slide.points.map((point, idx) => [
      '<div class="cityrail-tutorial-point">',
        '<div class="cityrail-tutorial-num">', idx + 1, '</div>',
        '<div><b>', escapeHtml(point[0]), '</b><span>', escapeHtml(point[1]), '</span></div>',
      '</div>'
    ].join('')).join('');
    overlay.querySelector('#cityrail-tutorial-progress').innerHTML = slides.map((_, idx) => {
      return '<div class="cityrail-tutorial-dot' + (idx <= activeStep ? ' active' : '') + '"></div>';
    }).join('');
    overlay.querySelector('#cityrail-tutorial-prev').disabled = activeStep === 0;
    overlay.querySelector('#cityrail-tutorial-next').textContent = activeStep >= slides.length - 1 ? '完成' : '下一步';
  }

	  function open(options) {
	    const opts = options || {};
	    activeUser = safeUser(opts.user || getCurrentUser());
	    const overlay = ensureOverlay();
	    const state = getState(activeUser);
	    activeForced = !!opts.force;
	    pendingForcedFaq = !!opts.forceFaq;
	    const checkbox = overlay.querySelector('#cityrail-tutorial-never');
	    const optout = overlay.querySelector('.cityrail-tutorial-optout');
	    if (checkbox) checkbox.checked = activeForced ? false : !!state.never;
	    if (optout) optout.style.display = activeForced ? 'none' : '';
	    showStep(0);
	    overlay.classList.add('visible');
	    if (opts.auto) {
      state.shown += 1;
      saveStateFor(activeUser, state);
    }
  }

	  function close() {
	    const overlay = ensureOverlay();
	    const checkbox = overlay.querySelector('#cityrail-tutorial-never');
	    const shouldOpenFaq = pendingForcedFaq;
	    pendingForcedFaq = false;
	    if (checkbox && checkbox.checked && !activeForced) {
	      const state = getState(activeUser);
	      state.never = true;
	      saveStateFor(activeUser, state);
	    }
	    activeForced = false;
	    overlay.classList.remove('visible');
	    if (shouldOpenFaq) {
	      setTimeout(() => {
	        try { if (typeof window.cityrailShowFaq === 'function') window.cityrailShowFaq(); }
	        catch (e) { console.warn('forced FAQ failed', e); }
	      }, 180);
	    }
	  }

	  function maybeAutoStart() {
	    const user = getCurrentUser();
	    if (!isNewUser(user)) return false;
	    const state = getState(user);
	    const force = state.shown < AUTO_LIMIT;
	    if (!force && state.never) return false;
	    if (state.shown >= AUTO_LIMIT) return false;
	    open({ user, auto: true, force, forceFaq: force });
	    return train;
	  }

  function installSettingsButton() {
    const panel = document.getElementById('settings-panel');
    if (!panel || document.getElementById('cityrail-tutorial-settings-row')) return;
    const row = document.createElement('div');
    row.id = 'cityrail-tutorial-settings-row';
    row.className = 'settings-row cityrail-tutorial-settings-row';
    row.innerHTML = '<span class="sr-label">新手教程</span><button type="button" class="cityrail-tutorial-settings-btn" id="cityrail-tutorial-open">开启新手教程</button>';
    row.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      if (typeof event.stopImmediatePropagation === 'function') event.stopImmediatePropagation();
      open({ user: getCurrentUser(), auto: false });
    });
    const divider = panel.querySelector('.settings-divider');
    if (divider && divider.parentNode) divider.parentNode.insertBefore(row, divider);
    else panel.appendChild(row);
  }

