  if (!mk) return false;
  const oldId = state._waitingMergeIndexV9[mk];
  const old = oldId != null && state._batchMap ? state._batchMap[oldId] : null;
  if (old && old.state === 'waiting' && old.trainId == null) {
    old.count = (old.count || 0) + (batch.count || 0);
    if (state._batchMap && batch.id != null) delete state._batchMap[batch.id];
    return true;
  }
