// 重置乘客系统状态（模拟重启/午夜日结时调用）
function resetPassengerSystem(reason = 'daily-reset') {
  state.batches = [];
  state.passengerBatches = [];
  state._batchAccum = {};
  state._batchMap = {};
  state.__passengerLegCache = null;
  state.__waitingIndexReadyV41 = true;
  state._totalDelivered = 0;
  state._totalGenerated = 0;
  state.totalGenerated = 0;
  state.totalDelivered = 0;
  state.totalEntry = 0;
  state.totalExit = 0;
  state._exitFlow = 0;
  state.__cityrailCanonicalPassengerVolumeMax = 0;
  state._exitFlowByStation = {};
  state.__realtimeStationOD = Object.create(null);
  state.__realtimeStationODByStation = null;
  state.__realtimeStationODGroupCache = null;
  state.__realtimeODDirty = false;
  state.__realtimeODBatchDepth = 0;
  state._lineRidership = {};
  state._segmentActualFlow = {};
  state.lineFlowStats = {};
  state.linePassengerStats = {};
  state.__cityrailCanonicalPassengerVolumeMax = 0;
  state.lineStatsData = [];
  state.segmentFlowsCache = [];
  state.stationFlowMap = {};
  state._maxStationFlow = 1;
  state.hourlyFlow = Array(24).fill(0);
  state._hourlyFlow = Array(24).fill(0);
  state.__v101Hourly = Array(24).fill(0);
  state.__v102Hourly = Array(24).fill(0);
  state.__v111Hourly = Array(24).fill(0);
  state.__v112Hourly = Array(24).fill(0);
  state._fareRevenueYuan = 0;
  state._fareRevenue = 0;
  state._fareIncome = 0;
  state.fareIncome = 0;
  state._fareCountedBatchIds = {};
  _routeGraphStale = true;
  _passengerLineByIdCache = null;
  _passengerLineByIdSource = null;
  _passengerLineByIdCount = 0;
  _lastCleanupTime = 0;
  try { lastFareScanAt = 0; lastFareScanSig = ''; } catch(e) {}

  if (state.passenger && typeof state.passenger === 'object') {
    state.passenger.totalEntry = 0;
    state.passenger.totalExit = 0;
    state.passenger.generated = 0;
    state.passenger.delivered = 0;
    state.passenger.waiting = 0;
  }

  if (Array.isArray(state.trains)) {
    state.trains.forEach(train => {
      if (!train) return;
      train._passengerIds = [];
      train.load = 0;
      train.passengerCount = 0;
      train.passengers = 0;
      train.onboard = 0;
      train.overloaded = false;
    });
  }

  // 清零各站候车池与站点日统计
  if (!state.stationWaitingPool) state.stationWaitingPool = {};
  const liveStationIds = new Set();
  for (const station of state.stations || []) {
    const sid = station.id;
    liveStationIds.add(String(sid));
    const pool = state.stationWaitingPool[sid] || {};
    pool.waiting = 0;
    pool.totalArrived = 0;
    pool.totalBoarded = 0;
    pool.totalDelivered = 0;
    pool.totalTransfer = 0;
    state.stationWaitingPool[sid] = pool;
    [
      'waiting', 'passengers', 'inbound', 'outbound', 'flow', 'dailyFlow',
      'recentFlow', 'currentFlow', 'platformWaiting', 'totalGenerated',
      'totalDelivered', '_totalGenerated', '_totalDelivered'
    ].forEach(key => { if (key in station) station[key] = 0; });
  }
  for (const sid in state.stationWaitingPool) {
    if (liveStationIds.has(String(sid))) continue;
    const pool = state.stationWaitingPool[sid];
    if (!pool) continue;
    pool.waiting = 0;
    pool.totalArrived = 0;
    pool.totalBoarded = 0;
    pool.totalDelivered = 0;
    pool.totalTransfer = 0;
  }

  state.__cityrailLastPassengerResetAt = Date.now();
  state.__cityrailLastPassengerResetReason = reason;
  try { if (typeof invalidateFlowCache === 'function') invalidateFlowCache(); } catch(e) {}
  try { if (window && typeof window.dispatchEvent === 'function') window.dispatchEvent(new CustomEvent('cityrail:dailyPassengerReset', { detail: { reason } })); } catch(e) {}
}

