// ═══ PassengerBatch 批次结构 ═══
// 一个批次代表一批具有相同起终点、相同路径的乘客
// 相比为每个乘客创建独立对象，大幅降低内存与 CPU 占用
let nextBatchId = 1;
const ZONE_ORDER = ['residential','railway_station','airport','shopping','office','school','hospital','leisure'];

function cityrailStationRecordForExternalFlow(stationOrId) {
  if (stationOrId == null) return null;
  if (typeof stationOrId === 'object') return stationOrId;
  const key = String(stationOrId);
  return ((state && Array.isArray(state.stations)) ? state.stations : []).find(st => String(st && st.id) === key) || null;
}

function cityrailStationBlocksExternalPassengers(stationOrId) {
  const station = cityrailStationRecordForExternalFlow(stationOrId);
  return !!(station && station.blockExternalPassengerFlow === true);
}
window.cityrailStationBlocksExternalPassengers = cityrailStationBlocksExternalPassengers;

function cityrailSetStationExternalPassengerBlocked(stationOrId, blocked) {
  const station = cityrailStationRecordForExternalFlow(stationOrId);
  if (!station) return false;
  const next = !!blocked;
  if (station.blockExternalPassengerFlow === next) return false;
  station.blockExternalPassengerFlow = next;
  return true;
}
window.cityrailSetStationExternalPassengerBlocked = cityrailSetStationExternalPassengerBlocked;

function cityrailBatchCountValue(batch) {
  const value = Number(batch && (batch.count ?? batch.passengers ?? batch.size ?? batch.remaining));
  return Number.isFinite(value) && value > 0 ? value : 0;
}

function cityrailBatchWaitingStationId(batch) {
  try {
    if (typeof cityrailBatchWaitingPlatform === 'function') {
      const platform = cityrailBatchWaitingPlatform(batch);
      if (platform && platform.stationId != null) return platform.stationId;
    }
  } catch(e) {}
  return batch && (batch.currentStationId ?? batch.stationId ?? batch.boardStationId ?? batch.originId);
}

function cityrailPurgeStationExternalPassengerBatches(stationOrId) {
  const station = cityrailStationRecordForExternalFlow(stationOrId);
  if (!station || !Array.isArray(state && state.batches)) return 0;
  const stationKey = String(station.id);
  let removed = 0;
  const keep = [];
  for (const batch of state.batches) {
    const externalTouch = batch && (String(batch.originId) === stationKey || String(batch.destinationId) === stationKey);
    const removable = externalTouch && batch.state === 'waiting' && batch.trainId == null;
    if (!removable) {
      keep.push(batch);
      continue;
    }
    const count = cityrailBatchCountValue(batch);
    const waitingStationId = cityrailBatchWaitingStationId(batch);
    const pool = waitingStationId != null && state.stationWaitingPool ? state.stationWaitingPool[waitingStationId] : null;
    if (pool) pool.waiting = Math.max(0, (Number(pool.waiting) || 0) - count);
    try { if (typeof removeWaitingIndexV9 === 'function') removeWaitingIndexV9(batch); } catch(e) {}
    if (state._batchMap && batch.id != null) delete state._batchMap[batch.id];
    removed += count;
  }
  if (removed > 0) {
    state.batches = keep;
    if (state._batchAccum) {
      Object.keys(state._batchAccum).forEach(key => {
        const text = String(key);
        if (text === stationKey || text.startsWith(stationKey + '_') || text.endsWith('_' + stationKey)) delete state._batchAccum[key];
      });
    }
    if (state.__realtimeStationOD) {
      Object.keys(state.__realtimeStationOD).forEach(key => {
        const row = state.__realtimeStationOD[key];
        if (row && (String(row.originId) === stationKey || String(row.destinationId) === stationKey)) delete state.__realtimeStationOD[key];
      });
      try { if (typeof markRealtimeODDirtyV350 === 'function') markRealtimeODDirtyV350(); } catch(e) {}
    }
    try { if (typeof compactWaitingBatchesV9 === 'function') compactWaitingBatchesV9(); } catch(e) {}
  }
  return removed;
}
window.cityrailPurgeStationExternalPassengerBatches = cityrailPurgeStationExternalPassengerBatches;

function cityrailRefreshStationExternalPassengerButton(stationOrId) {
  const btn = document.getElementById('sd-btn-block-external-flow');
  if (!btn) return;
  const blocked = cityrailStationBlocksExternalPassengers(stationOrId);
  btn.classList.toggle('active-action', blocked);
  btn.textContent = blocked ? '恢复进站客流' : '屏蔽进站客流';
  btn.title = blocked
    ? '当前已屏蔽本站外部进站/到达客流，仅保留线路换乘客流'
    : '屏蔽本站作为外部出发或到达需求点，保留线路内部换乘客流';
}
window.cityrailRefreshStationExternalPassengerButton = cityrailRefreshStationExternalPassengerButton;

function createPassengerBatch(originId, destId, count) {
  if (cityrailStationBlocksExternalPassengers(originId) || cityrailStationBlocksExternalPassengers(destId)) {
    return {
      id: nextBatchId++,
      originId,
      destinationId: destId,
      legs: [],
      currentLeg: 0,
      state: 'arrived',
      trainId: null,
      count: 0,
      _externalFlowBlocked: true
    };
  }
  const batch = {
    id: nextBatchId++,
    originId,
    destinationId: destId,
    legs: [],        // [{lineId, boardIdx, alightIdx}]
    currentLeg: 0,
    state: 'waiting', // 'waiting' | 'on_train' | 'arrived'
    trainId: null,
    count,            // 该批次代表的人数
  };
  // 预计算路径
  computePassengerRoute(batch);
  try { if (typeof setBatchFareSnapshot === 'function') setBatchFareSnapshot(batch); } catch(e) {}
  // 立即加入 _batchMap，确保后续任何查找都能命中
  if (!state._batchMap) state._batchMap = {};
  state._batchMap[batch.id] = batch;
  return batch;
}

function markRealtimeODDirtyV350() {
  if ((state.__realtimeODBatchDepth || 0) > 0) {
    state.__realtimeODDirty = true;
    return;
  }
  state.__realtimeStationODVersion = (state.__realtimeStationODVersion || 0) + 1;
  state.__realtimeStationODByStation = null;
  state.__realtimeStationODGroupCache = null;
}

function beginRealtimeODBatchV350() {
  state.__realtimeODBatchDepth = (state.__realtimeODBatchDepth || 0) + 1;
}

function flushRealtimeODBatchV350() {
  state.__realtimeODBatchDepth = Math.max(0, (state.__realtimeODBatchDepth || 0) - 1);
  if (state.__realtimeODBatchDepth > 0 || !state.__realtimeODDirty) return;
  state.__realtimeODDirty = false;
  state.__realtimeStationODVersion = (state.__realtimeStationODVersion || 0) + 1;
  state.__realtimeStationODByStation = null;
  state.__realtimeStationODGroupCache = null;
}

function recordRealtimeOD(originId, destId, count) {
  const n = Number(count);
  if (!originId || !destId || String(originId) === String(destId) || !Number.isFinite(n) || n <= 0) return;
  if (!state.__realtimeStationOD) state.__realtimeStationOD = Object.create(null);
  const key = String(originId) + '>' + String(destId);
  const row = state.__realtimeStationOD[key] || (state.__realtimeStationOD[key] = {
    originId: String(originId),
    destinationId: String(destId),
    count: 0,
    lastAt: 0,
    firstHour: state.simulationHour || 0
  });
  row.count += n;
  row.lastAt = Date.now();
  row.lastHour = state.simulationHour || 0;
  markRealtimeODDirtyV350();
}
window.cityrailRecordRealtimeOD = recordRealtimeOD;

// 获取当前时段的OD流向权重表
function getZoneODTable(hour) {
  if (hour >= 5 && hour < 12) return ZONE_OD_WEIGHTS.morning;
  if (hour >= 16 && hour < 22) return ZONE_OD_WEIGHTS.evening;
  return ZONE_OD_WEIGHTS.midday;
}
// 获取当前时段名称（用于OD矩阵缓存有效期判断）
function getZonePeriodName(hour) {
  if (hour >= 5 && hour < 12) return 'morning';
  if (hour >= 16 && hour < 22) return 'evening';
  return 'midday';
}
function cloneZoneODTable(table) {
  const out = {};
  Object.keys(table || {}).forEach(from => {
    out[from] = Object.assign({}, table[from] || {});
  });
  return out;
}
function applyZoneODMultipliers(table, multipliers) {
  Object.keys(multipliers || {}).forEach(from => {
    if (!table[from]) table[from] = {};
    Object.keys(multipliers[from] || {}).forEach(to => {
      const base = Number.isFinite(Number(table[from][to])) ? Number(table[from][to]) : 0.08;
      table[from][to] = base * cityrailClamp(multipliers[from][to], 0.45, 2.25);
    });
  });
  return table;
}
function getActiveCityWeights() {
  const profile = window.getActiveCityProfile ? window.getActiveCityProfile() : null;
  return cityrailEnsureCityWeights(profile) || cityrailDerivedCityWeights(profile || {});
}
function getWeightedZoneODTable(hour) {
  const period = getZonePeriodName(hour);
  const profile = window.getActiveCityProfile ? window.getActiveCityProfile() : null;
  const weights = getActiveCityWeights();
  const table = cloneZoneODTable(ZONE_OD_WEIGHTS[period] || ZONE_OD_WEIGHTS.midday);
  applyZoneODMultipliers(table, weights && weights.odMultipliers && weights.odMultipliers[period]);
  applyZoneODMultipliers(table, profile && profile.odMultipliers && profile.odMultipliers[period]);
  return table;
}
function cityrailStationWeight(station, role, weights) {
  const zones = getStationZoneTypes(station);
  const zoneAttraction = (weights && weights.zoneAttraction) || {};
  let z = 0;
  zones.forEach(type => { z += cityrailNumber(zoneAttraction[type], 1); });
  z = zones.length ? z / zones.length : 1;
  const bias = cityrailClamp(cityrailNumber(station && station.flowBias, 1), 0.55, 2.20);
  const roleBoost = role === 'origin' ? 0.48 : 0.72;
  return cityrailClamp(1 + (z - 1) * roleBoost, 0.70, 1.65) * Math.pow(bias, role === 'origin' ? 0.35 : 0.55);
}
function cityrailStationStableFactor(station) {
  const lat = cityrailNumber(station && station.lat, 0);
  const lng = cityrailNumber(station && station.lng, 0);
  const key = [
    station && station.id,
    station && station.name,
    Math.round(lat * 10000),
    Math.round(lng * 10000)
  ].join('|');
  let hash = 2166136261;
  for (let i = 0; i < key.length; i++) {
    hash ^= key.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return 0.82 + ((hash >>> 0) / 4294967295) * 0.36;
}
function cityrailStationFunctionFactor(station, weights) {
  const zones = getStationZoneTypes(station);
  const zoneAttraction = (weights && weights.zoneAttraction) || {};
  if (!zones.length) return 1;
  let sum = 0;
  let maxBoost = 1;
  zones.forEach(type => {
    const base = cityrailNumber(zoneAttraction[type], 1);
    let local = base;
    if (/office|business|cbd/i.test(type)) local *= 1.16;
    else if (/shopping|commercial|mall/i.test(type)) local *= 1.12;
    else if (/railway|airport|hub/i.test(type)) local *= 1.24;
    else if (/school/i.test(type)) local *= 1.08;
    else if (/leisure|park|tour/i.test(type)) local *= 1.05;
    sum += local;
    maxBoost = Math.max(maxBoost, local);
  });
  const avg = sum / zones.length;
  return cityrailClamp(avg * 0.72 + maxBoost * 0.28, 0.70, 1.85);
}
function cityrailStationTransferFactor(station) {
  if (Number.isFinite(Number(station && station.__cityrailTransferCount))) {
    return 1 + Math.min(3, Math.max(0, Number(station.__cityrailTransferCount) - 1)) * 0.18;
  }
  if (Array.isArray(station && station.lineIds) && station.lineIds.length) {
    return 1 + Math.min(3, Math.max(0, station.lineIds.length - 1)) * 0.18;
  }
  const id = String(station && station.id);
  let count = 0;
  (state.lines || []).forEach(line => {
    if (Array.isArray(line && line.stationIds) && line.stationIds.some(stId => String(stId) === id)) count++;
  });
  return 1 + Math.min(3, Math.max(0, count - 1)) * 0.18;
}
function cityrailStationCentralityFactor(station) {
  const profile = window.getActiveCityProfile ? window.getActiveCityProfile() : null;
  const center = profile && (profile.center || profile.mapCenter || profile.coordinates);
  const lat = cityrailNumber(station && station.lat, NaN);
  const lng = cityrailNumber(station && station.lng, NaN);
  const cLat = Array.isArray(center) ? cityrailNumber(center[0], NaN) : cityrailNumber(center && center.lat, NaN);
  const cLng = Array.isArray(center) ? cityrailNumber(center[1], NaN) : cityrailNumber(center && center.lng, NaN);
  if (!Number.isFinite(lat) || !Number.isFinite(lng) || !Number.isFinite(cLat) || !Number.isFinite(cLng)) return 1;
  const km = haversine(lat, lng, cLat, cLng);
  const zones = getStationZoneTypes(station).join('|');
  const floor = /airport|railway|hub/i.test(zones) ? 0.88 : 0.72;
  return cityrailClamp(1.28 - km / 34, floor, 1.28);
}

function cityrailFastDistanceKm(a, b) {
  const lat1 = cityrailNumber(a && a.lat, 0);
  const lng1 = cityrailNumber(a && a.lng, 0);
  const lat2 = cityrailNumber(b && b.lat, 0);
  const lng2 = cityrailNumber(b && b.lng, 0);
  const meanLat = (lat1 + lat2) * Math.PI / 360;
  const x = (lng2 - lng1) * 111.320 * Math.cos(meanLat);
  const y = (lat2 - lat1) * 110.574;
  return Math.max(0.001, Math.sqrt(x * x + y * y));
}

function cityrailStationGeometrySignature(stations) {
  return (stations || []).map(st => [
    st && st.id,
    Math.round(cityrailNumber(st && st.lat, 0) * 100000),
    Math.round(cityrailNumber(st && st.lng, 0) * 100000)
  ].join(':')).join('|');
}

function cityrailTargetTripDistanceWeightKm(distanceKm, targetKm) {
  const d = Math.max(0.1, cityrailNumber(distanceKm, 0.1));
  const target = cityrailClamp(targetKm || 12, 8, 32);
  const ratio = d / target;
  const logRatio = Math.log(Math.max(0.08, ratio));
  const sigma = ratio < 1 ? 0.48 : 0.80;
  const peak = Math.exp(-(logRatio * logRatio) / (2 * sigma * sigma));
  const accessFactor = d < 3 ? 0.35 : (d < 5 ? 0.62 : 1);
  const targetBand = d >= target * 1.25 ? 1.80 : (d >= target * 0.95 ? 1.45 : (d < target * 0.65 ? 0.55 : 1));
  return accessFactor * targetBand * (0.18 + 4.6 * peak);
}

// 预计算站间距离矩阵（km），用于重力模型
let _stationDistMatrix = null;
let _stationDistMatrixSig = '';
let _stationDistMatrixSize = 0;
let _stationDistOrder = null;
function cityrailDistAt(i, j) {
  return _stationDistMatrix ? (_stationDistMatrix[i * _stationDistMatrixSize + j] || 0) : 0;
}
function buildStationDistMatrix() {
  const n = state.stations.length;
  const sig = cityrailStationGeometrySignature(state.stations);
  if (_stationDistMatrix && _stationDistMatrixSig === sig && _stationDistMatrixSize === n && _stationDistMatrix.length === n * n) return _stationDistMatrix;
  _stationDistMatrix = new Float64Array(n * n);
  _stationDistMatrixSize = n;
  _stationDistOrder = Array.from({ length:n }, () => []);
  for (let i = 0; i < n; i++) {
    for (let j = i+1; j < n; j++) {
      var a = state.stations[i], b = state.stations[j];
      var d = cityrailFastDistanceKm(a, b);
      var safeD = Math.max(0.5, d);
      _stationDistMatrix[i * n + j] = _stationDistMatrix[j * n + i] = safeD;
      _stationDistOrder[i].push({ idx:j, d:safeD });
      _stationDistOrder[j].push({ idx:i, d:safeD });
    }
  }
  _stationDistOrder.forEach(row => row.sort((a, b) => a.d - b.d));
  _stationDistMatrixSig = sig;
  return _stationDistMatrix;
}

// 基于站点功能区的 OD 矩阵构建（不含时间因子，由 generatePassengers 统一缩放）
// 使用重力模型 + 站点覆盖面积 + 距离衰减 + 路线可到达校验
function buildZoneODMatrix() {
  const stations = state.stations;
  const n = stations.length;
  if (n < 2) return { matrix: Array.from({length:n},()=>Array(n).fill(0)), stations };
  stations.forEach((station, idx) => {
    if (station && !station.__manualZoneTypes) cityrailAutoRefreshStationZoneTypes(station, 'buildZoneODMatrix');
    cityrailNormalizeStationPopulation(station, cityrailInitialStationPopulation(station && station.lat, station && station.lng, idx));
  });

  // 预计算距离矩阵
  buildStationDistMatrix();

  const matrix = Array.from({ length: n }, () => Array(n).fill(0));
  const effectivePop = cityrailEffectiveDemandPopulations(stations);
  const stationExternalBlocked = stations.map(st => cityrailStationBlocksExternalPassengers(st));
  const totalPop = effectivePop.reduce((s, v, idx) => stationExternalBlocked[idx] ? s : s + Math.max(0, v), 0);
  if (totalPop <= 0) return { matrix, stations };

  const hour = state.simulationHour;
  const zoneTable = getWeightedZoneODTable(hour);
  const cityWeights = getActiveCityWeights();
  const demandShape = (cityWeights && cityWeights.demandShape) || {};
  const GRAVITY_EXP = cityrailClamp(demandShape.distanceExp || 1.3, 0.85, 1.50); // 距离衰减指数
  const distanceDecayKm = cityrailClamp(demandShape.distanceDecayKm || 24, 10, 42);
  const transferCounts = Object.create(null);
  (state.lines || []).forEach(line => {
    (Array.isArray(line && line.stationIds) ? line.stationIds : []).forEach(id => {
      const key = String(id);
      transferCounts[key] = (transferCounts[key] || 0) + 1;
    });
  });
  stations.forEach(st => { if(st) st.__cityrailTransferCount = transferCounts[String(st.id)] || (Array.isArray(st.lineIds) ? st.lineIds.length : 0); });

  // 对每个站点计算覆盖面积比例 —— 用 Voronoi 近似：
  // 站点覆盖半径 = 到最近邻站距离的 60%，但不超过 5km
  const coverageRadii = [];
  for (let i = 0; i < n; i++) {
    var minDist = (_stationDistOrder && _stationDistOrder[i] && _stationDistOrder[i][0]) ? _stationDistOrder[i][0].d : Infinity;
    coverageRadii.push(Math.min(Math.max(minDist * 0.6, 0.5), 5.0));
  }
  // 估计各站实际服务人口：本站人口 × 覆盖半径 × 功能强度 × 换乘吸引 × 区位 × 稳定站点差异。
  // 归一化前保留每个非换乘站自己的地理与人口特征，避免同功能区车站生成相同客流。
  const rawServedPop = stations.map(function(station, i) {
    if (stationExternalBlocked[i]) {
      station.__cityrailDemandFactor = 0;
      return 0;
    }
    const pop = Math.max(1, cityrailNumber(effectivePop[i], totalPop / n));
    const radius = cityrailNumber(coverageRadii[i], 1);
    const coverageFactor = cityrailClamp(Math.pow(radius / 1.6, 0.42), 0.58, 1.68);
    const functionFactor = cityrailStationFunctionFactor(station, cityWeights);
    const transferFactor = cityrailStationTransferFactor(station);
    const centralityFactor = cityrailStationCentralityFactor(station);
    const stableFactor = cityrailStationStableFactor(station);
    const demandFactor = coverageFactor * functionFactor * transferFactor * centralityFactor * stableFactor;
    station.__cityrailDemandFactor = Math.round(demandFactor * 1000) / 1000;
    return Math.max(1, pop * demandFactor);
  });
  // 归一化，使 ∑ 服务人口仍等于城市总站点人口，避免整体客流规模漂移。
  var sumW = rawServedPop.reduce(function(a,b){ return a+b; }, 0);
  var scaleW = sumW > 0 ? totalPop / sumW : 1;
  var servedPop = stations.map(function(s,i){
    const value = rawServedPop[i] * scaleW;
    s.__cityrailServedPop = Math.round(value);
    return value;
  });
  const stationIndexById = Object.create(null);
  stations.forEach((st, idx) => { if(st) stationIndexById[String(st.id)] = idx; });
  const stationByIdForTrip = Object.create(null);
  stations.forEach(st => { if(st) stationByIdForTrip[String(st.id)] = st; });
  let segmentKmTotal = 0, segmentCount = 0;
  (state.lines || []).forEach(line => {
    const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
    for(let i = 0; i < ids.length - 1; i++){
      const aIdx = stationIndexById[String(ids[i])];
      const bIdx = stationIndexById[String(ids[i + 1])];
      if(aIdx != null && bIdx != null){
        segmentKmTotal += cityrailDistAt(aIdx, bIdx) || 0;
        segmentCount++;
      }
    }
  });
  const avgStationSpacingKm = segmentCount ? segmentKmTotal / segmentCount : 1;
  let minLat = Infinity, minLng = Infinity, maxLat = -Infinity, maxLng = -Infinity;
  stations.forEach(st => {
    const lat = cityrailNumber(st && st.lat, NaN), lng = cityrailNumber(st && st.lng, NaN);
    if(!Number.isFinite(lat) || !Number.isFinite(lng)) return;
    minLat = Math.min(minLat, lat); maxLat = Math.max(maxLat, lat);
    minLng = Math.min(minLng, lng); maxLng = Math.max(maxLng, lng);
  });
  const extentKm = Number.isFinite(minLat) ? cityrailFastDistanceKm({lat:minLat,lng:minLng}, {lat:maxLat,lng:maxLng}) : 0;
  const lineCount = (state.lines || []).length;
  const cityScaleTargetKm = (n >= 320 || extentKm >= 35 || lineCount >= 8) ? 18 : ((n >= 120 || extentKm >= 18 || lineCount >= 4) ? 11.5 : 10.5);
  const spacingBoostKm = avgStationSpacingKm > 1.35 ? Math.min(8, (avgStationSpacingKm - 1.35) * 3.2) : 0;
  const targetTripKm = cityrailClamp(cityScaleTargetKm + spacingBoostKm, 8, 30);
  const sparseOD = n > 180;
  const nearCandidateCount = n >= 420 ? 10 : 14;
  const midCandidateCount = n >= 420 ? 46 : 60;
  const farCandidateCount = n >= 420 ? 18 : 24;
  const topDemandCandidateCount = n >= 420 ? 28 : 36;
  const candidateLimit = n >= 420 ? 92 : 120;
  function tripDistancePreferenceKm(d) {
    if (d < 1.2) return 0.05;
    if (d < 3) return 0.10 + (d - 1.2) * 0.08;
    return cityrailTargetTripDistanceWeightKm(d, targetTripKm);
  }
  const destAttraction = stations.map(function(st, idx){
    if (stationExternalBlocked[idx]) return 0;
    return servedPop[idx] * cityrailStationWeight(st, 'dest', cityWeights);
  });
  const topDemandDestinations = sparseOD
    ? destAttraction.map((score, idx) => ({ score, idx })).sort((a, b) => b.score - a.score).slice(0, topDemandCandidateCount).map(row => row.idx)
    : [];
  function pushTopCandidate(top, limit, row, score) {
    if (!Number.isFinite(score) || limit <= 0) return;
    const item = { idx: row.idx, d: row.d, score };
    let pos = top.length;
    while (pos > 0 && score > top[pos - 1].score) pos--;
    if (pos >= limit) return;
    top.splice(pos, 0, item);
    if (top.length > limit) top.length = limit;
  }
  function topScoredDistanceCandidates(rows, minKm, maxKm, limit) {
    const top = [];
    for (let ri = 0; ri < rows.length; ri++) {
      const row = rows[ri];
      if (!row) continue;
      if (row.d < minKm) continue;
      if (row.d >= maxKm) break;
      pushTopCandidate(top, limit, row, destAttraction[row.idx] * tripDistancePreferenceKm(row.d));
    }
    return top;
  }
  function topScoredFarCandidates(rows, minKm, limit) {
    const top = [];
    for (let ri = 0; ri < rows.length; ri++) {
      const row = rows[ri];
      if (!row || row.d < minKm) continue;
      pushTopCandidate(top, limit, row, destAttraction[row.idx] * tripDistancePreferenceKm(row.d));
    }
    return top;
  }
  const lineMembershipByStation = Object.create(null);
  if (sparseOD) {
    (state.lines || []).forEach(line => {
      const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
      ids.forEach((id, idx) => {
        const key = String(id);
        if (!lineMembershipByStation[key]) lineMembershipByStation[key] = [];
        lineMembershipByStation[key].push({ line, idx });
      });
    });
  }
  function sparseDestinationsForOrigin(origin, i) {
    if (!sparseOD) return null;
    const set = new Set();
    const nearest = (_stationDistOrder && _stationDistOrder[i]) || [];
    for (let ni = 0, added = 0; ni < nearest.length && added < nearCandidateCount; ni++) {
      const row = nearest[ni];
      if (!row || row.d >= 3) break;
      set.add(row.idx);
      added++;
    }
    topScoredDistanceCandidates(nearest, 3, 18, midCandidateCount).forEach(row => set.add(row.idx));
    topScoredFarCandidates(nearest, 18, farCandidateCount).forEach(row => set.add(row.idx));
    topDemandDestinations.forEach(idx => { if (idx !== i) set.add(idx); });
    const memberships = lineMembershipByStation[String(origin && origin.id)] || [];
    memberships.forEach(entry => {
      const ids = Array.isArray(entry.line && entry.line.stationIds) ? entry.line.stationIds : [];
      if (!ids.length) return;
      const step = Math.max(1, Math.floor(ids.length / 8));
      [0, ids.length - 1, entry.idx - 1, entry.idx + 1, entry.idx - step, entry.idx + step].forEach(pos => {
        if (pos >= 0 && pos < ids.length) {
          const stationIdx = stationIndexById[String(ids[pos])];
          if (stationIdx != null && stationIdx !== i) set.add(stationIdx);
        }
      });
    });
    let arr = Array.from(set);
    if (arr.length > candidateLimit) {
      arr.sort((a, b) => {
        const dA = cityrailDistAt(i, a), dB = cityrailDistAt(i, b);
        const scoreA = destAttraction[a] * tripDistancePreferenceKm(dA) / Math.pow(Math.max(1.0, dA), 0.18);
        const scoreB = destAttraction[b] * tripDistancePreferenceKm(dB) / Math.pow(Math.max(1.0, dB), 0.18);
        return scoreB - scoreA;
      });
      arr = arr.slice(0, candidateLimit);
    }
    return arr;
  }

	  for (let i = 0; i < n; i++) {
	    const origin = stations[i];
	    if (stationExternalBlocked[i]) continue;
	    const fromZone = getStationZoneType(origin);
    // 该站服务人口的出行产生率（日均出行次数 ≈ 2.0 次/人）
    // 出行产生率提升客流密度，使候车人数快速达到可见水平
    const genRate = 200;
    const originWeight = cityrailStationWeight(origin, 'origin', cityWeights);
    const outFlowBase = servedPop[i] * genRate / 100 * originWeight; // 转换为OD矩阵基数

    // 用重力模型分配目的地
    var totalGravity = 0;
    var destScores = [];
    const candidateDestinations = sparseDestinationsForOrigin(origin, i);
    const destinationIndexes = candidateDestinations || stations.map((_, idx) => idx);
    for (let di = 0; di < destinationIndexes.length; di++) {
      const j = destinationIndexes[di];
	      if (i === j) { destScores.push(0); continue; }
	      if (stationExternalBlocked[j]) { destScores[j] = 0; continue; }
	      const dest = stations[j];
      const toZone = getStationZoneType(dest);
      const zoneW = blendedZoneWeight(zoneTable, origin, dest);
      // 重力：人口吸引力 / 距离^指数
      const dist = cityrailDistAt(i, j);
      const shortTripPenalty = dist < 1.2 ? 0.04 + dist * 0.08 : (dist < 3 ? 0.10 + (dist - 1.2) * 0.10 : (dist < 5 ? 0.32 + (dist - 3) * 0.18 : 1));
      const longTripSoftener = Math.sqrt(distanceDecayKm / Math.max(distanceDecayKm, dist));
      const destinationWeight = cityrailStationWeight(dest, 'dest', cityWeights);
      const targetDistanceWeight = cityrailTargetTripDistanceWeightKm(dist, targetTripKm);
      const gravity = Math.pow(servedPop[j], 0.6) * destinationWeight * shortTripPenalty * targetDistanceWeight * longTripSoftener / Math.pow(dist, GRAVITY_EXP);
      // 多功能区结合计算：共同功能越多，同质出行折扣越大，但不再简单按单一类型判断。
      const sameZoneDiscount = 1.0 - 0.65 * sameZoneBlendSimilarity(origin, dest);
      const score = zoneW * gravity * sameZoneDiscount;
      destScores[j] = score;
      totalGravity += score;
    }

    if (totalGravity <= 0) continue;

    // 按重力得分分配客流
    for (let di = 0; di < destinationIndexes.length; di++) {
      const j = destinationIndexes[di];
      if (i === j || destScores[j] <= 0) continue;
      const rawFlow = Math.round(outFlowBase * destScores[j] / totalGravity);

      // 可达性由 computePassengerRoute 在创建 batch 时校验，此处不做 A* 避免 O(n²) 卡死
      matrix[i][j] = Math.max(1, rawFlow);
    }
  }
  return { matrix, stations, _targetTripKm:targetTripKm, _avgStationSpacingKm:avgStationSpacingKm, _extentKm:extentKm };
}
let odMatrixCache = null; // cached OD matrix for current network

// 基于站点功能区构建 OD 矩阵 + 标记当前时段
function buildODMatrix() {
  const result = buildZoneODMatrix();
  result._zonePeriod = getZonePeriodName(state.simulationHour);
  odMatrixCache = result;
  return odMatrixCache;
}

function getRunSimulationIndexes() {
  const stationSig = state.stations.map(s => String(s && s.id)).join('|');
  const odStations = odMatrixCache && Array.isArray(odMatrixCache.stations) ? odMatrixCache.stations : [];
  const odSig = odStations.map(s => String(s && s.id)).join('|');
  const cache = state.__runSimulationIndexCache;
  if (cache && cache.stationSig === stationSig && cache.odSig === odSig) return cache;
  const stationById = Object.create(null);
  for (let si = 0; si < state.stations.length; si++) {
    const st = state.stations[si];
    if (st) stationById[st.id] = st;
  }
  const odIdxByStationId = Object.create(null);
  for (let oi = 0; oi < odStations.length; oi++) {
    const st = odStations[oi];
    if (st) odIdxByStationId[st.id] = oi;
  }
  state.__runSimulationIndexCache = { stationSig, odSig, stationById, odIdxByStationId };
  return state.__runSimulationIndexCache;
}

function runSimulation() {
  const hour = state.simulationHour;
  const timeFactor = getTimeFactor(hour);
  state.currentTimeFactor = timeFactor;

  if (!state.isSimulating) return;
  if (state.stations.length === 0) return;
  const runNow = performance.now();
  const runMinInterval = cityrailIsMapInteractionBusy() ? 20000 : ((state.stations.length > 420 || state.trains.length > 900) ? 15000 : 1200);
  if (state.__cityrailLastRunSimulationAt && runNow - state.__cityrailLastRunSimulationAt < runMinInterval) return;
  state.__cityrailLastRunSimulationAt = runNow;

  // Build or rebuild OD matrix when zone period changes
  if (!odMatrixCache || odMatrixCache._zonePeriod !== getZonePeriodName(hour)) {
    buildODMatrix();
  }

  const simIndexes = getRunSimulationIndexes();
  const _stMap = simIndexes.stationById;
  const _odIdxMap = simIndexes.odIdxByStationId;

  // flowMap 改用实际送达客流：只有乘坐列车抵达目的地的乘客才算
  const flowMap = {};
  state.stations.forEach(s => {
    const pool = state.stationWaitingPool[s.id];
    flowMap[s.id] = pool ? (pool.totalDelivered || 0) : 0;
  });

  const shouldBuildSegmentGeometry = false;
  const segmentFlows = [];

  // Compute segment flows from actual train passenger counts
  state.lines.forEach(line => {
    const lineBidirCap = getLineBidirCapacity(line);

    for (let i = 0; i < line.stationIds.length - 1; i++) {
      const sidA = line.stationIds[i];
      const sidB = line.stationIds[i + 1];
      const staA = _stMap[sidA];
      const staB = _stMap[sidB];
      if (!staA || !staB) continue;

      // Get station indices in OD matrix
      const idxA = _odIdxMap[sidA];
      const idxB = _odIdxMap[sidB];
      if (idxA < 0 || idxB < 0) continue;

      const dist = Math.max(0.5, getLineSegmentDistance(line, i));

      // Use ACTUAL segment flow from train passenger tracking
      const segKey = line.id + '_' + i;
      const actualFlow = state._segmentActualFlow[segKey] || 0;

      // Also use OD demand as a fallback for "demand" (unmet demand)
      const directFlow = odMatrixCache.matrix[idxA][idxB] + odMatrixCache.matrix[idxB][idxA];
      const popProduct = staA.population * staB.population;
      const gravityComponent = popProduct / Math.pow(dist, 1.3);
      const demandFlow = timeFactor * (directFlow * 0.4 + gravityComponent * 2e-7);

      // actualFlow = 当日累计实际通过该区间的乘客人数（来自列车进站跟踪）
      // demandFlow = OD模型估计的潜在需求
      const overload = Math.max(0, demandFlow - actualFlow);
      const overloadRatio = lineBidirCap > 0 ? demandFlow / lineBidirCap : 0;

      segmentFlows.push({
        key: segKey,
        lineId: line.id,
        color: line.color,
        latlngs: shouldBuildSegmentGeometry ? getSegmentCurveWithWaypoints(line, i) : null,
        flow: actualFlow,
        demandFlow,
        overload,
        overloadRatio,
        lineBidirCap,
        dist,
        popProduct,
      });
    }
  });

  // Restore any legacy station-flow highlight geometry left from older sessions.
  state.stations.forEach(station => {
    const allPolys = stationTransferPolygons[station.id] || [];
    if (allPolys.length === 0) return;
    if (allPolys[0]._flowScaled) {
      allPolys.forEach(poly => {
        const line = state.lines.find(l => l.id === poly._lineId);
        if (!line) return;
        const pos = getStationPosition(station, line.id);
        const baseLen = getLinePlatformLength(station.id, line);
        const angle = getLineStationAngle(station.id, line);
        const corners = computeStationCorners(pos.lat, pos.lng, baseLen, STATION_WIDTH, angle);
        poly.setLatLngs(corners);
        const bs = poly._baseStyle;
        if (bs) poly.setStyle(bs);
        else poly.setStyle({ fillColor: line.color, color: 'transparent', weight: 0, fillOpacity: 0.45, opacity: 1 });
        poly._flowScaled = false;
      });
    }
  });

  // --- Aggregate per-line stats ---
  const lineLengthCache = typeof cityrailEnsureLineLengthCache === 'function'
    ? cityrailEnsureLineLengthCache('runSimulation')
    : (computeLineLengths(), { byLine: state.lineLengthCache || {} });
  const lineDistMap = lineLengthCache.byLine || state.lineLengthCache || {};

  // 线路客运量 = 实际乘坐人数（来自 batch 上车跟踪）
  // 线路需求 = 各断面 demand 的最大值（高峰断面）
  const lineDemandMap = {};
  state.lines.forEach(l => { lineDemandMap[l.id] = 0; });
  segmentFlows.forEach(seg => {
    if (lineDemandMap[seg.lineId] !== undefined) {
      lineDemandMap[seg.lineId] = Math.max(lineDemandMap[seg.lineId], seg.demandFlow);
    }
  });

  state.lineStatsData = state.lines.filter(l => !(typeof cityrailIsConnectorLine === 'function' && cityrailIsConnectorLine(l))).map(l => {
    const ridership = state._lineRidership[l.id] || 0;
    const len = lineDistMap[l.id] || 0;
    return {
      id: l.id, name: l.name, color: l.color,
      trainType: l.trainType, cars: l.cars, speed: l.speed,
      length: len,
      flow: ridership,
      demandFlow: lineDemandMap[l.id] || 0,
      bidirCap: getLineBidirCapacity(l),
      intensity: len > 0 ? ridership / len : 0,
    };
  });
  state.lineStatsData.sort((a, b) => {
    if (typeof window.cityrailCompareLinesByNumber === 'function') return window.cityrailCompareLinesByNumber(a, b);
    const numA = parseInt(a.name.match(/^(\d+)/)?.[1]) ?? Infinity;
    const numB = parseInt(b.name.match(/^(\d+)/)?.[1]) ?? Infinity;
    if (numA !== numB) return numA - numB;
    return a.name.localeCompare(b.name, 'zh-CN');
  });
  // Store delivered-flow totals for control-center and line/station diagnostics.
  state.stationFlowMap = flowMap;
  // Cache max flow to avoid expensive spread every train arrival
  state._maxStationFlow = Math.max(1, ...Object.values(flowMap));
  state.segmentFlowsCache = segmentFlows;

  if (state.showLineStats) renderLineStats();


}

function getFlowColor(ratio) {
  // Realistic flow heatmap: blue(green→yellow→orange→red
  const h = (1 - ratio) * 220; // hue: 220(blue) → 0(red)
  const s = 0.9;
  const l = 0.3 + ratio * 0.35; // lightness: dim→bright
  const c = (1 - Math.abs(2 * l - 1)) * s;
  const x = c * (1 - Math.abs((h / 60) % 2 - 1));
  const m = l - c / 2;
  let r, g, b;
  if (h < 60) { r = c; g = x; b = 0; }
  else if (h < 120) { r = x; g = c; b = 0; }
  else if (h < 180) { r = 0; g = c; b = x; }
  else if (h < 240) { r = 0; g = x; b = c; }
  else { r = x; g = 0; b = c; }
  return `rgb(${Math.round((r+m)*255)},${Math.round((g+m)*255)},${Math.round((b+m)*255)})`;
}

function invalidateFlowCache() {
  odMatrixCache = null; // force OD matrix rebuild
  state.lineLengthCache = {}; // invalidate line lengths too
  state.__runSimulationIndexCache = null;
  state.__passengerLegCache = null;
  // Distance cache is guarded by station geometry signature; keep it for zone/source/timetable changes.
  _routePairCache = new Map();
}

// ==================== TRAIN SYSTEM ====================
function getTrainCapacity(line) {
  const tt = TRAIN_TYPES[normalizeLineTrainType(line)] || TRAIN_TYPES['A'];
  return tt.capPerCar * (line.cars || 6);
}

function getTrainAccel(line) {
  const tt = TRAIN_TYPES[normalizeLineTrainType(line)] || TRAIN_TYPES['A'];
  return tt.accel || 1.0; // m/s²
}

function getTrainDecel(line) {
  const tt = TRAIN_TYPES[normalizeLineTrainType(line)] || TRAIN_TYPES['A'];
  return tt.decel || 1.1; // m/s²
}

function getTrainMaxSpeed(line) {
  // 列车时速以线路配置面板设定为准（车型差异体现在加速度/减速度/载客量）
  return line.speed || 80; // km/h
}

function getDwellBase(line) {
  const tt = TRAIN_TYPES[normalizeLineTrainType(line)] || TRAIN_TYPES['A'];
  return tt.dwellBase || 25; // seconds
}

function cityrailFixedDwellSeconds(line) {
  return Math.max(1, Number(getDwellBase(line)) || 25);
}

// Get current headway in seconds based on time of day
function getCurrentHeadway(line) {
  const hour = state.simulationHour;
  const isPeak = (hour >= 7 && hour < 9) || (hour >= 17 && hour < 19);
  const isNormal = (hour >= 6 && hour < 7) || (hour >= 9 && hour < 10) || (hour >= 16 && hour < 17) || (hour >= 19 && hour < 20);
  let min = line.normalHeadwayMin || LINE_SERVICE_DEFAULTS.normalHeadwayMin;
  if (isPeak) min = line.peakHeadwayMin || LINE_SERVICE_DEFAULTS.peakHeadwayMin;
  else if (!isNormal) min = line.offPeakHeadwayMin || LINE_SERVICE_DEFAULTS.offPeakHeadwayMin;
  return Math.max(1, min) * 60;
}

// 获取当前时段名称：'peak' / 'normal' / 'offpeak'
function getHeadwayPeriod(hour) {
  if ((hour >= 7 && hour < 9) || (hour >= 17 && hour < 19)) return 'peak';
  if ((hour >= 6 && hour < 7) || (hour >= 9 && hour < 10) || (hour >= 16 && hour < 17) || (hour >= 19 && hour < 20)) return 'normal';
  return 'offpeak';
}

// 计算线路单程总距离（km）
function getLineDistance(line) {
  const nodes = getLineTrainNodes(line);
  let total = 0;
  for (const n of nodes) total += n.segDist || 0;
  return total;
}

function cityrailSegmentCurveLimitKmh(nodes, segIndex, lineMaxKmh) {
  if (!Array.isArray(nodes) || !nodes.length) return Math.max(1, Number(lineMaxKmh) || 80);
  const idx = Math.max(0, Math.min(nodes.length - 1, Math.round(Number(segIndex) || 0)));
  const raw = Number(nodes[idx] && nodes[idx].curveLimitKmh);
  const limit = Number.isFinite(raw) && raw > 0 ? raw : (Number(lineMaxKmh) || 80);
  return Math.max(1, Math.min(Number(lineMaxKmh) || 80, limit));
}

function cityrailCurveProfileTargetSpeedKmh(train, nodes, lineMaxKmh, decelMs2) {
	  const maxSpeed = Math.max(1, Number(lineMaxKmh) || 80);
	  if (!train || !Array.isArray(nodes) || nodes.length < 2) return maxSpeed;
	  const segIndex = Math.max(0, Math.min(nodes.length - 2, Math.round(Number(train.segIndex) || 0)));
	  const direction = Number(train.direction) === 1 ? 1 : 0;
	  const speedKmh = Math.max(0, Number(train.speed) || 0);
	  const decel = Math.max(0.2, Number(decelMs2) || 0.8);
	  const speedMs = speedKmh / 3.6;
	  const slowestMs = CITYRAIL_CURVE_MIN_LIMIT_KMH / 3.6;
	  const worstBrakeKm = Math.max(0, (speedMs * speedMs - slowestMs * slowestMs) / (2 * decel)) / 1000;
	  const lookaheadKm = Math.min(4, Math.max(0.22, worstBrakeKm + 0.12));
  const profile = nodes._curveSpeedProfile;
  if (profile && Number(profile.restrictedSegments) <= 0) return maxSpeed;
  const cumulative = nodes._cumulativeSegDist;
  if (cumulative && cumulative.length >= nodes.length && nodes._curveLimitRangeIndex) {
    const segKm = Math.max(0.0001, Number(nodes[segIndex] && nodes[segIndex].segDist) || 0.0001);
    const progress = Math.max(0, Math.min(1, Number(train.segProgress) || 0));
    const currentKm = (Number(cumulative[segIndex]) || 0) + segKm * progress;
    let from = segIndex;
    let to = segIndex;
    if (direction === 0) {
      const endKm = currentKm + lookaheadKm;
      to = cityrailUpperBound(cumulative, endKm, segIndex, nodes.length - 1) - 1;
      to = Math.max(segIndex, Math.min(nodes.length - 2, to));
    } else {
      const startKm = currentKm - lookaheadKm;
      const j = cityrailLowerBound(cumulative, startKm, 1, Math.min(cumulative.length, segIndex + 2));
      from = Math.max(0, Math.min(segIndex, j - 1));
    }
    const target = cityrailCurveLimitRangeMinKmh(nodes, from, to, maxSpeed);
    return Math.max(CITYRAIL_CURVE_MIN_LIMIT_KMH, Math.min(maxSpeed, target));
  }
	  let target = cityrailSegmentCurveLimitKmh(nodes, segIndex, maxSpeed);
	  let distanceKm = 0;
  let idx = segIndex;
  let first = true;
  while (idx >= 0 && idx < nodes.length - 1 && distanceKm <= lookaheadKm) {
    const segKm = Math.max(0.0001, Number(nodes[idx] && nodes[idx].segDist) || 0.0001);
    const remainingKm = first
      ? (direction === 0 ? segKm * (1 - Math.max(0, Math.min(1, Number(train.segProgress) || 0))) : segKm * Math.max(0, Math.min(1, Number(train.segProgress) || 0)))
      : segKm;
    const limit = cityrailSegmentCurveLimitKmh(nodes, idx, maxSpeed);
    if (limit < target) {
      target = limit;
    }
    if (limit < speedKmh - 0.1) {
      const limitMs = limit / 3.6;
      const brakeKm = Math.max(0, (speedMs * speedMs - limitMs * limitMs) / (2 * decel)) / 1000 + 0.035;
      if (distanceKm <= brakeKm) target = Math.min(target, limit);
    }
    distanceKm += remainingKm;
    idx += direction === 0 ? 1 : -1;
    first = false;
  }
  return Math.max(CITYRAIL_CURVE_MIN_LIMIT_KMH, Math.min(maxSpeed, target));
}

function cityrailStationNodeIndexForStop(line, nodes, stationIndex) {
  if (!line || !Array.isArray(line.stationIds) || !Array.isArray(nodes)) return -1;
  const sid = line.stationIds[stationIndex];
  const indexed = nodes._stationNodeIndexes && nodes._stationNodeIndexes[String(sid)];
  if (indexed && indexed.length) return indexed[0];
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i] && nodes[i].type === 'station' && String(nodes[i].id) === String(sid)) return i;
  }
  return -1;
}

function cityrailEstimateProfileSectionSeconds(nodes, startIdx, endIdx, maxSpeedKmh, accelMs2, decelMs2) {
  const a = Math.max(0.2, Number(accelMs2) || 0.8);
  const d = Math.max(0.2, Number(decelMs2) || 0.8);
  const from = Math.max(0, Math.min(nodes.length - 2, Math.round(Number(startIdx) || 0)));
  const to = Math.max(from + 1, Math.min(nodes.length - 1, Math.round(Number(endIdx) || 0)));
  const count = to - from + 1;
  const speeds = new Array(count).fill(Math.max(1, Number(maxSpeedKmh) || 80) / 3.6);
  speeds[0] = 0;
  speeds[count - 1] = 0;
  const distancesM = [];
  for (let i = from; i < to; i++) {
    const local = i - from;
    const limitKmh = cityrailSegmentCurveLimitKmh(nodes, i, maxSpeedKmh);
    speeds[local] = Math.min(speeds[local], limitKmh / 3.6);
    speeds[local + 1] = Math.min(speeds[local + 1], limitKmh / 3.6);
    distancesM.push(Math.max(0.1, (Number(nodes[i] && nodes[i].segDist) || 0.0001) * 1000));
  }
  for (let i = 1; i < count; i++) {
    speeds[i] = Math.min(speeds[i], Math.sqrt(speeds[i - 1] * speeds[i - 1] + 2 * a * distancesM[i - 1]));
  }
  speeds[count - 1] = 0;
  for (let i = count - 2; i >= 0; i--) {
    speeds[i] = Math.min(speeds[i], Math.sqrt(speeds[i + 1] * speeds[i + 1] + 2 * d * distancesM[i]));
  }
  let seconds = 0;
  for (let i = 0; i < distancesM.length; i++) {
    const v0 = speeds[i];
    const v1 = speeds[i + 1];
    seconds += (2 * distancesM[i]) / Math.max(0.5, v0 + v1);
  }
  return seconds;
}

function cityrailEstimateLineProfileRunSec(line, options = {}) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return 0;
  let nodes = [];
  try { nodes = getLineTrainNodes(line); } catch(e) { nodes = []; }
  if (!Array.isArray(nodes) || nodes.length < 2) return 0;
  const maxSpeed = Math.max(1, Number(getTrainMaxSpeed(line)) || 80);
  const accel = Math.max(0.2, Number(getTrainAccel(line)) || 0.8);
  const decel = Math.max(0.2, Number(getTrainDecel(line)) || 0.8);
  const stopSet = new Set(Array.isArray(options.stopIndexes) ? options.stopIndexes.map(v => Math.max(0, Math.round(Number(v) || 0))) : line.stationIds.map((_, i) => i));
  stopSet.add(0);
  stopSet.add(line.stationIds.length - 1);
  const stopNodeIndexes = Array.from(stopSet)
    .map(index => cityrailStationNodeIndexForStop(line, nodes, index))
    .filter(index => index >= 0)
    .sort((a, b) => a - b);
  if (stopNodeIndexes.length < 2) return 0;
  let seconds = 0;
  for (let i = 0; i < stopNodeIndexes.length - 1; i++) {
    const aIdx = stopNodeIndexes[i];
    const bIdx = stopNodeIndexes[i + 1];
    if (bIdx > aIdx) seconds += cityrailEstimateProfileSectionSeconds(nodes, aIdx, bIdx, maxSpeed, accel, decel);
  }
  return seconds;
}

// 计算往返时间（秒）：2 × (行驶时间 + 站点停靠时间)
function getRoundTripSeconds(line) {
  try {
    const api = window.CityRailDispatchAuthorityV300;
    if (api && typeof api.roundTripSec === 'function') return Math.max(600, Math.round(Number(api.roundTripSec(line)) || 0));
  } catch(e) {}
  const dist = getLineDistance(line); // km
  const speed = getTrainMaxSpeed(line); // km/h
  if (speed <= 0) return 3600; // fallback
  const travelOneWay = (dist / speed) * 3600; // 行驶秒数
  const stations = line.stationIds.length;
  const dwell = getDwellBase(line); // 每站停靠秒数
  const dwellOneWay = stations * dwell;
  const estimated = isLoopLine(line) ? (travelOneWay + dwellOneWay) : ((travelOneWay + dwellOneWay) * 2);
  const factor = Math.max(0.5, Math.min(3, Number(window.CITYRAIL_RUNTIME_CALIBRATION_FACTOR) || 1.1));
  return Math.round(estimated * factor);
}

function normalizeLoopStationIds(line, reason) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
  const ids = line.stationIds.map(String);
  const firstId = ids[0];
  let changed = false;

  while (line.stationIds.length > 1 && String(line.stationIds[line.stationIds.length - 1]) === firstId) {
    line.stationIds.pop();
    changed = true;
  }

  if (changed) {
    markLoopCandidate(line, 0, reason || 'repeated-closure');
    line.waypoints = (line.waypoints || []).filter(wp => {
      const seg = Math.round(Number(wp && wp.segIdx));
      return Number.isFinite(seg) && seg >= 0 && seg < Math.max(1, line.stationIds.length);
    });
    if (window.__CITYRAIL_DEBUG_TOPOLOGY__) {
      console.log('[CityRail loop] normalized repeated closure station', { reason, line: line.name || line.id, firstId });
    }
  }
  return changed;
}

function markLoopCandidate(line, distM, reason) {
  if (!line || line.__loopChoice === 'loop' || line.__loopChoice === 'normal') return false;
  line.__loopCandidate = true;
  line.__loopCandidateReason = reason || 'distance';
  line.loopClosedByDistanceM = Math.round(Number(distM) || 0);
  line.isLoop = false;
  line.loopMode = '';
  line.loopClosedExplicit = false;
  delete line.loopStartStationId;
  delete line.loopEndStationId;
  delete line.loopDirection;
  return true;
}

const LOOP_TERMINAL_MERGE_MAX_M = 120;

function shouldMergeLoopTerminals(line) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 3) return false;
  const firstId = line.stationIds[0];
  const lastId = line.stationIds[line.stationIds.length - 1];
  if (String(firstId) === String(lastId)) return true;
  const first = state.stations.find(s => s.id === firstId);
  const last = state.stations.find(s => s.id === lastId);
  if (!first || !last) return false;
  const distanceM = haversine(first.lat, first.lng, last.lat, last.lng) * 1000;
  line.loopTerminalDistanceM = Math.round(distanceM);
  return distanceM <= LOOP_TERMINAL_MERGE_MAX_M;
}

function mergeLoopTerminals(line, reason) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
  let changed = false;
  while (line.stationIds.length > 1 && String(line.stationIds[line.stationIds.length - 1]) === String(line.stationIds[0])) {
    line.stationIds.pop();
    changed = true;
  }
  if (line.stationIds.length < 3) return changed;
  const firstId = line.stationIds[0];
  const lastId = line.stationIds[line.stationIds.length - 1];
  if (String(firstId) === String(lastId)) return changed;
  if (!shouldMergeLoopTerminals(line)) return changed;
  const last = state.stations.find(s => s.id === lastId);

  const oldLastStationIdx = line.stationIds.length - 1;
  const oldLastSeg = line.stationIds.length - 2;
  const oldClosureSeg = line.stationIds.length - 1;
  const newClosureSeg = Math.max(0, line.stationIds.length - 2);
  const terminalWaypoint = {
    id: 'loop_merge_' + String(lastId) + '_' + Date.now().toString(36),
    segIdx: newClosureSeg,
    order: 999000,
    lat: last.lat,
    lng: last.lng,
    __loopMergedTerminal: true,
    mergedStationId: lastId,
    mergedIntoStationId: firstId
  };

  line.stationIds.pop();
  line.waypoints = (line.waypoints || []).map(wp => {
    if (!wp) return wp;
    const next = Object.assign({}, wp);
    const seg = Math.round(Number(next.segIdx));
    if (!Number.isFinite(seg)) return next;
    if (seg < oldLastSeg) return next;
    if (seg === oldLastSeg) {
      next.segIdx = newClosureSeg;
      next.order = Math.min(Number(next.order) || 0, 998000);
    } else if (seg === oldClosureSeg) {
      next.segIdx = newClosureSeg;
      next.order = 999100 + (Number(next.order) || 0);
    } else if (seg > oldClosureSeg) {
      next.segIdx = Math.max(0, seg - 1);
    }
    return next;
  });
  if (!line.waypoints.some(wp => wp && wp.__loopMergedTerminal && String(wp.mergedStationId) === String(lastId))) {
    line.waypoints.push(terminalWaypoint);
  }

  if (state.stationWaitingPool && state.stationWaitingPool[lastId]) {
    const from = state.stationWaitingPool[lastId];
    const to = state.stationWaitingPool[firstId] || { waiting: 0, totalArrived: 0, totalBoarded: 0, totalDelivered: 0 };
    ['waiting','totalArrived','totalBoarded','totalDelivered'].forEach(k => { to[k] = (Number(to[k]) || 0) + (Number(from[k]) || 0); });
    state.stationWaitingPool[firstId] = to;
    delete state.stationWaitingPool[lastId];
  }
  (state.batches || []).forEach(b => {
    ['originId','destinationId','currentStationId','stationId','boardStationId'].forEach(k => {
      if (String(b && b[k]) === String(lastId)) b[k] = firstId;
    });
    (b && b.legs || []).forEach(leg => {
      if (!leg || String(leg.lineId) !== String(line.id)) return;
      if (Number(leg.boardIdx) === oldLastStationIdx) leg.boardIdx = 0;
      if (Number(leg.alightIdx) === oldLastStationIdx) leg.alightIdx = 0;
      annotatePassengerLegForLine(line, leg);
    });
    if (b && String(b.originId) === String(b.destinationId) && b.state !== 'on_train') {
      b.state = 'arrived';
      b.trainId = null;
      b.legs = [];
    }
  });
  (state.trains || []).forEach(t => {
    if (!t || String(t.lineId) !== String(line.id)) return;
    t.direction = 0;
    if (Number(t.nextStationIdx) === oldLastStationIdx) t.nextStationIdx = 0;
    if (Number(t.nextStationIdx) > oldLastStationIdx) t.nextStationIdx = Math.max(0, line.stationIds.length - 1);
  });
  (state.virtualTransfers || []).forEach(vt => {
    ['stationA','stationB','fromStationId','toStationId','from','to'].forEach(k => {
      if (String(vt && vt[k]) === String(lastId)) vt[k] = firstId;
    });
  });

  const stillReferenced = (state.lines || []).some(l => l && Array.isArray(l.stationIds) && l.stationIds.some(id => String(id) === String(lastId)));
  if (!stillReferenced) {
    try { removeStationPolygons(lastId); } catch(e) {}
    state.stations = (state.stations || []).filter(s => String(s.id) !== String(lastId));
  }
  line.__loopMergedTerminals = { from: lastId, into: firstId, reason: reason || '', at: Date.now() };
  invalidateLineNodesCache(line.id);
  _routeGraphStale = true;
  try { rebuildWaitingIndexesV41(); } catch(e) {}
  invalidateFlowCache();
  return true;
}

function applyLoopChoice(line, enabled, reason) {
  if (!line || !Array.isArray(line.stationIds)) return false;
  normalizeLoopStationIds(line, reason || 'applyLoopChoice');
  if (enabled) {
    line.__loopChoice = 'loop';
    line.__loopCandidate = false;
    line.isLoop = true;
    line.loopMode = 'closed-ring';
    line.loopClosedExplicit = true;
    line.loopStartStationId = line.stationIds[0];
    line.loopEndStationId = line.stationIds[0];
    line.loopDirection = 0;
    if (mergeLoopTerminals(line, reason || 'applyLoopChoice')) {
      normalizeLineWaypoints(line, reason || 'loop-terminal-merge');
      line.loopStartStationId = line.stationIds[0];
      line.loopEndStationId = line.stationIds[0];
    }
  } else {
    line.__loopChoice = 'normal';
    line.__loopCandidate = false;
    line.isLoop = false;
    line.loopMode = '';
    line.loopClosedExplicit = false;
    delete line.loopStartStationId;
    delete line.loopEndStationId;
    delete line.loopDirection;
  }
  line._topologyVersion = (Number(line._topologyVersion) || 0) + 1;
  return true;
}

function refreshLoopLineFlag(line) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) {
    if (line) { line.isLoop = false; line.loopMode = ''; line.loopClosedByDistanceM = 0; }
    return false;
  }
  const normalizedRepeatedClosure = normalizeLoopStationIds(line, 'refreshLoopLineFlag');
  const first = state.stations.find(s => s.id === line.stationIds[0]);
  const last = state.stations.find(s => s.id === line.stationIds[line.stationIds.length - 1]);
  if (line.__loopChoice === 'normal') {
    line.isLoop = false;
    line.loopMode = '';
    line.loopClosedExplicit = false;
    delete line.loopStartStationId;
    delete line.loopEndStationId;
    delete line.loopDirection;
    if (first && last) line.loopClosedByDistanceM = Math.round(haversine(first.lat, first.lng, last.lat, last.lng) * 1000);
    return false;
  }
  const chosenLoop = line.__loopChoice === 'loop' || !!line.loopClosedExplicit || !!line.closedLoop || !!line.isCircular || line.loopMode === 'closed-ring';
  if (!first || !last) return chosenLoop || !!line.isLoop;
  const distM = haversine(first.lat, first.lng, last.lat, last.lng) * 1000;
  if (chosenLoop) {
    line.__loopChoice = 'loop';
    line.__loopCandidate = false;
    line.isLoop = true;
    line.loopMode = 'closed-ring';
    line.loopClosedExplicit = true;
    line.loopClosedByDistanceM = Math.round(distM);
    line.loopStartStationId = first.id;
    line.loopEndStationId = first.id;
    line.loopDirection = 0;
    if (mergeLoopTerminals(line, 'refreshLoopLineFlag')) {
      normalizeLineWaypoints(line, 'refreshLoopLineFlag');
      line.loopStartStationId = line.stationIds[0];
      line.loopEndStationId = line.stationIds[0];
    }
    return true;
  }
  if (line.__loopChoice !== 'normal' && (normalizedRepeatedClosure || distM <= 100)) {
    markLoopCandidate(line, distM, normalizedRepeatedClosure ? 'repeated-closure' : 'distance');
  }
  line.isLoop = false;
  line.loopMode = '';
  line.loopClosedExplicit = false;
  if (line.__loopChoice === 'normal') line.loopClosedByDistanceM = Math.round(distM);
  delete line.loopStartStationId;
  delete line.loopEndStationId;
  delete line.loopDirection;
  return false;
}

function isLoopLine(line) {
  return !!(line && refreshLoopLineFlag(line));
}

function hasLoopOperationalFlag(line) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
  const first = String(line.stationIds[0]);
  const last = String(line.stationIds[line.stationIds.length - 1]);
  return !!(line.isLoop || line.loopClosedExplicit || line.closedLoop || line.isCircular || line.loopMode === 'closed-ring' || (line.__loopChoice === 'loop' && first !== last));
}

function isSingleDirectionLoopLine(line) {
  if (!hasLoopOperationalFlag(line)) return false;
  return !!(line.loopSingleDirection || line.loopOneWay || line.loopOperationMode === 'single-direction' || line.loopMode === 'single-direction');
}

function loopForwardStationDistance(line, boardIdx, alightIdx) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return 0;
  const total = line.stationIds.length;
  const from = Math.max(0, Math.min(total - 1, Math.round(Number(boardIdx))));
  const to = Math.max(0, Math.min(total - 1, Math.round(Number(alightIdx))));
  if (from === to) return 0;
  return (to - from + total) % total;
}

function passengerLegDirectionForLine(line, leg) {
  if (!leg) return 0;
  if (hasLoopOperationalFlag(line)) {
    if (isSingleDirectionLoopLine(line)) return 0;
    const total = Array.isArray(line.stationIds) ? line.stationIds.length : 0;
    if (total < 2) return 0;
    const forward = loopForwardStationDistance(line, leg.boardIdx, leg.alightIdx);
    const backward = (total - forward) % total;
    return backward > 0 && backward < forward ? 1 : 0;
  }
  if (Number.isFinite(Number(leg.direction))) return Number(leg.direction) === 1 ? 1 : 0;
  return Number(leg.alightIdx) > Number(leg.boardIdx) ? 0 : 1;
}

function annotatePassengerLegForLine(line, leg) {
  if (!leg) return leg;
  if (hasLoopOperationalFlag(line)) {
    leg.direction = passengerLegDirectionForLine(line, leg);
    leg.loopForwardStops = loopForwardStationDistance(line, leg.boardIdx, leg.alightIdx);
    const total = Array.isArray(line.stationIds) ? line.stationIds.length : 0;
    leg.loopBackwardStops = total > 0 ? (total - leg.loopForwardStops) % total : 0;
    leg.wrapAround = Number(leg.alightIdx) < Number(leg.boardIdx);
  } else {
    leg.direction = Number(leg.alightIdx) > Number(leg.boardIdx) ? 0 : 1;
    delete leg.loopForwardStops;
    delete leg.loopBackwardStops;
    delete leg.wrapAround;
  }
  return leg;
}

function canPassengerLegBoardOnLine(line, leg, trainDir, stationIdx) {
  if (!line || !leg || String(leg.lineId) !== String(line.id)) return false;
  if (Number(leg.boardIdx) !== Number(stationIdx)) return false;
  const dir = Number(trainDir) === 1 ? 1 : 0;
  if (hasLoopOperationalFlag(line)) {
    if (Number(leg.alightIdx) === Number(leg.boardIdx)) return false;
    if (isSingleDirectionLoopLine(line)) return dir === 0;
    return dir === passengerLegDirectionForLine(line, leg);
  }
  return (dir === 0 && Number(leg.alightIdx) > Number(leg.boardIdx)) ||
    (dir === 1 && Number(leg.alightIdx) < Number(leg.boardIdx));
}

try {
  window.cityrailHasLoopOperationalFlag = hasLoopOperationalFlag;
  window.cityrailIsSingleDirectionLoopLine = isSingleDirectionLoopLine;
  window.cityrailPassengerLegDirectionForLine = passengerLegDirectionForLine;
  window.cityrailAnnotatePassengerLegForLine = annotatePassengerLegForLine;
  window.cityrailCanPassengerLegBoardOnLine = canPassengerLegBoardOnLine;
} catch(e) {}

function cityrailIsWaitingBatch(batch) {
  if (!batch || batch.trainId != null) return false;
  const stateName = String(batch.state || '');
  return ['waiting','queued','transfer_waiting','platform_waiting','waiting_platform','station_waiting','entry_waiting'].includes(stateName);
}

function cityrailBatchPassengerCount(batch) {
  const value = Number(batch && (batch.count ?? batch.passengers ?? batch.size ?? batch.remaining));
  return Number.isFinite(value) && value > 0 ? value : 0;
}

function cityrailFindLineById(lineId) {
  const lines = (state && Array.isArray(state.lines)) ? state.lines : [];
  return lines.find(line => String(line && line.id) === String(lineId)) || null;
}

function cityrailBatchCurrentLeg(batch) {
  if (!batch || !Array.isArray(batch.legs)) return null;
  const idx = Math.max(0, Math.round(Number(batch.currentLeg) || 0));
  return batch.legs[idx] || null;
}

function cityrailBatchWaitingPlatform(batch) {
  if (!cityrailIsWaitingBatch(batch)) return null;
  const leg = cityrailBatchCurrentLeg(batch);
  if (leg && leg.lineId != null && Number.isFinite(Number(leg.boardIdx))) {
    const line = cityrailFindLineById(leg.lineId);
    if (line && Array.isArray(line.stationIds) && line.stationIds.length) {
      const boardIdx = Math.max(0, Math.min(line.stationIds.length - 1, Math.round(Number(leg.boardIdx))));
      const stationId = line.stationIds[boardIdx];
      if (stationId != null) {
        return {
          stationId,
          lineId: line.id,
          stationIdx: boardIdx,
          direction: passengerLegDirectionForLine(line, leg),
          leg,
          line
        };
      }
    }
  }

  const stationId = batch.currentStationId ?? batch.stationId ?? batch.boardStationId ?? batch.originId;
  if (stationId == null) return null;
  let line = null;
  const lineId = batch.lineId ?? (leg && leg.lineId);
  if (lineId != null) line = cityrailFindLineById(lineId);
  if (!line) {
    const stationKey = String(stationId);
    line = ((state && Array.isArray(state.lines)) ? state.lines : []).find(l => Array.isArray(l && l.stationIds) && l.stationIds.some(id => String(id) === stationKey)) || null;
  }
  const stationIdx = line && Array.isArray(line.stationIds) ? line.stationIds.findIndex(id => String(id) === String(stationId)) : -1;
  let direction = Number(batch.direction ?? (leg && leg.direction));
  if (!Number.isFinite(direction) && line && stationIdx >= 0) {
    const destId = batch.destinationId ?? batch.destStationId ?? batch.toStationId ?? (leg && (leg.alightStationId ?? leg.destinationId ?? leg.toStationId));
    const destIdx = line.stationIds.findIndex(id => String(id) === String(destId));
    if (destIdx >= 0 && destIdx !== stationIdx) direction = destIdx > stationIdx ? 0 : 1;
  }
  return {
    stationId,
    lineId: line ? line.id : lineId,
    stationIdx,
    direction: Number(direction) === 1 ? 1 : 0,
    leg,
    line
  };
}

function cityrailBatchMatchesLineStationDirection(batch, line, stationIdx, direction) {
  const platform = cityrailBatchWaitingPlatform(batch);
  if (!platform || !line) return false;
  if (String(platform.lineId) !== String(line.id)) return false;
  if (Number(platform.stationIdx) !== Number(stationIdx)) return false;
  return Number(platform.direction) === Number(direction);
}

function cityrailWaitingCountForLineStationDirection(line, stationIdx, direction) {
  const batches = Array.isArray(state.batches) ? state.batches : (Array.isArray(state.passengerBatches) ? state.passengerBatches : []);
  let total = 0;
  for (const batch of batches) {
    if (!cityrailBatchMatchesLineStationDirection(batch, line, stationIdx, direction)) continue;
    total += cityrailBatchPassengerCount(batch);
  }
  return Math.round(total);
}

function cityrailWaitingCountAtStation(stationId) {
  const key = String(stationId);
  const batches = Array.isArray(state.batches) ? state.batches : (Array.isArray(state.passengerBatches) ? state.passengerBatches : []);
  let total = 0;
  for (const batch of batches) {
    const platform = cityrailBatchWaitingPlatform(batch);
    if (platform && String(platform.stationId) === key) total += cityrailBatchPassengerCount(batch);
  }
  return Math.round(total);
}

