function promptLoopChoiceIfNeeded(line) {
  if (!line || !line.__loopCandidate || line.__loopChoice) return false;
  const overlay = ensureLoopChoicePrompt();
  const desc = document.getElementById('loop-choice-desc');
  const dist = Number(line.loopClosedByDistanceM || 0);
  if (desc) desc.textContent = `「${line.name || '当前线路'}」首尾${dist ? `距离约 ${dist} 米` : '已经闭合'}，可以作为环线连续运营。选择“按普通线路”则列车仍按两端折返运营。`;
  const normal = document.getElementById('loop-choice-normal');
  const loop = document.getElementById('loop-choice-loop');
  function finish(enabled) {
    overlay.classList.add('hidden');
    applyLoopChoice(line, enabled, enabled ? 'player-confirm-loop' : 'player-confirm-normal');
    try { rebuildLineTopology(line, enabled ? 'loopChoiceYes' : 'loopChoiceNo'); } catch(e) { try { refreshLinePolyline(line); } catch(err) {} }
    try { reRenderStationsOnLine(line); } catch(e) { try { refreshAllStations(); } catch(err) {} }
    try { invalidateFlowCache(); cityrailRefreshTrainsAfterTopologyEdit('loopChoice', [line]); updateUI(); saveState(); } catch(e) {}
    setTimeout(() => { try { runSimulation(); } catch(e) {} }, 0);
  }
  normal.onclick = () => finish(false);
  loop.onclick = () => finish(true);
  overlay.classList.remove('hidden');
  return true;
}
window.CityRailLoopChoice = { prompt: promptLoopChoiceIfNeeded, apply: applyLoopChoice };

// ── 将列车按已行驶时间定位到线路上 ──
// travelTime: 该列车已经行驶的秒数
// 遍历路径节点，包含停站时间，将列车放在正确的位置
function positionTrainByTime(train, line, nodes, travelTime) {
  if (travelTime <= 0 || nodes.length < 2) return false;

  const speed = getTrainMaxSpeed(line); // km/h
  if (speed <= 0) return false;
  const speedKmPerSec = speed / 3600;
  const dwell = getDwellBase(line); // 每站停靠秒数
  const totalStations = line.stationIds.length;

  // 根据方向确定出发节点
  let nodeIdx = train.direction === 0 ? 0 : nodes.length - 1;
  let stationIdx = train.direction === 0 ? 0 : totalStations - 1;
  let remaining = travelTime;

  // 防止无限循环的安全上限
  const maxSteps = nodes.length * 4;
  let steps = 0;

  while (remaining > 0 && steps < maxSteps) {
    steps++;
    const nextNodeIdx = train.direction === 0 ? nodeIdx + 1 : nodeIdx - 1;

    // 到达端点：循环回起点（持续运营）
    if (nextNodeIdx < 0 || nextNodeIdx >= nodes.length) {
      if (train.direction === 0) {
        nodeIdx = 0;
        stationIdx = 0;
      } else {
        nodeIdx = nodes.length - 1;
        stationIdx = totalStations - 1;
      }
      continue;
    }

    const segIdx = Math.min(nodeIdx, nextNodeIdx);
    const segLen = nodes[segIdx].segDist || 0.001;
    const segTime = segLen / speedKmPerSec;

    if (remaining < segTime) {
      // 列车在当前路段上
      train.segIndex = segIdx;
      train.segProgress = train.direction === 0
        ? remaining / segTime
        : 1 - remaining / segTime;
      train.speed = speed;
      train.state = 'cruising';
      train.depTime = 0; // 标记为已激活，跳过等待逻辑
      // 确定下一个站点
      train.nextStationIdx = findNextStationFromPosition(train, line, nodes);
      return true;
    }

    remaining -= segTime;
    nodeIdx = nextNodeIdx;

    // 到达一个站点节点，扣除停站时间
    if (nodes[nodeIdx].type === 'station') {
      if (train.direction === 0) stationIdx++;
      else stationIdx--;

      if (remaining <= dwell) {
        // 正在停站
        train.segIndex = train.direction === 0 ? nodeIdx - 1 : nodeIdx;
        train.segIndex = Math.max(0, Math.min(nodes.length - 2, train.segIndex));
        train.segProgress = train.direction === 0 ? 1 : 0;
        train.speed = 0;
        train.dwellRemaining = dwell - remaining;
        train.state = 'dwelling';
        train.depTime = 0;
        train.nextStationIdx = findNextStationFromPosition(train, line, nodes);
        return true;
      }
      remaining -= dwell;
    }
  }

  // 兜底：放到运营方向终点
  if (train.direction === 0) {
    train.segIndex = nodes.length - 2;
    train.segProgress = 1;
    train.nextStationIdx = totalStations - 1;
  } else {
    train.segIndex = 0;
    train.segProgress = 0;
    train.nextStationIdx = 0;
  }
  train.speed = 0;
  train.state = 'dwelling';
  train.dwellRemaining = dwell;
  train.depTime = 0;
  return true;
}

// 从列车当前位置，找到线路上下一个站点在 line.stationIds 中的索引
function findNextStationFromPosition(train, line, nodes) {
  const totalStations = line.stationIds.length;
  if (train.direction === 0) {
    for (let i = train.segIndex + 1; i < nodes.length; i++) {
      if (nodes[i].type === 'station' && nodes[i].id) {
        const idx = line.stationIds.indexOf(nodes[i].id);
        if (idx >= 0) return idx;
      }
    }
    return totalStations - 1;
  } else {
    for (let i = train.segIndex; i >= 0; i--) {
      if (nodes[i].type === 'station' && nodes[i].id) {
        const idx = line.stationIds.indexOf(nodes[i].id);
        if (idx >= 0) return idx;
      }
    }
    return 0;
  }
}

// Initialize trains for a given line
function initTrainsForLine(line) {
  // Remove existing trains for this line（乘客返回候车）
  state.trains.forEach(t => {
    if (t.lineId === line.id) {
      // 该列车上的乘客回到候车状态
      if (t._passengerIds) {
        for (let k = 0; k < t._passengerIds.length; k++) {
          const p = state._batchMap ? state._batchMap[t._passengerIds[k]] : null;
          if (p && p.state === 'on_train') {
            p.state = 'waiting';
            p.trainId = null;
            const curStationId = line.stationIds[Math.max(0, Math.min(line.stationIds.length - 1, t.nextStationIdx || 0))];
            const pool = state.stationWaitingPool[curStationId];
            if (pool) pool.waiting += (p.count || PASSENGER_BATCH_SCALE);
          }
        }
      }
      if (trainMarkers[t.id]) {
        map.removeLayer(trainMarkers[t.id]);
        delete trainMarkers[t.id];
      }
    }
  });
  state.trains = state.trains.filter(t => t.lineId !== line.id);

  if (line.stationIds.length < 2) return;

  if (window.CityRailHeadwayTopologyDemandV240 && typeof window.CityRailHeadwayTopologyDemandV240.initHeadwayLine === 'function') {
    window.CityRailHeadwayTopologyDemandV240.initHeadwayLine(line);
    return;
  }

  const nowSec = (Number(state.simulationHour) || 0) * 3600;
  const firstSec = (Number(line.firstTrain ?? 6) || 6) * 3600;
  const headwaySec = Math.max(30, getCurrentHeadway(line));
  const roundTripSec = Math.max(600, getRoundTripSeconds(line));
  const targetTotal = cityrailTargetFleetFromHeadway(roundTripSec, headwaySec);
  line._serviceActivatedV17 = nowSec >= firstSec;
  line._dispatchReady = nowSec >= firstSec;
  line._strictTargetFleet = targetTotal;
  line._strictRoundTripSec = roundTripSec;
  line._strictHeadwaySec = headwaySec;
  line._strictSchedule = {
    fwdNext: nowSec >= firstSec ? firstSec + Math.ceil(Math.max(0, nowSec - firstSec) / headwaySec) * headwaySec : firstSec,
    bwdNext: nowSec >= firstSec ? firstSec + headwaySec / 2 + Math.ceil(Math.max(0, nowSec - firstSec - headwaySec / 2) / headwaySec) * headwaySec : firstSec + headwaySec / 2,
    lastHeadway: headwaySec,
    targetFleet: targetTotal
  };
  line._strictFleetShortage = targetTotal;
  line._strictFleetShortageReason = nowSec >= firstSec ? 'waiting_for_headway_runtime' : 'before_first_train';

}

function createTrainObj(line, direction, depTime, nodes) {
  const capacity = getTrainCapacity(line);
  const firstH = line.firstTrain ?? 6;
  const train = {
    id: genId(),
    lineId: line.id,
    direction,           // 0 = forward (start→end), 1 = backward (end→start)
    depTime,             // scheduled departure time in seconds from midnight
    segIndex: 0,         // current segment index
    segProgress: 0,      // 0-1 progress within current segment
    speed: 0,            // current speed in km/h
    state: 'waiting',    // 'waiting' | 'accelerating' | 'cruising' | 'decelerating' | 'dwelling' | 'holding_short' | 'done'
    _holdingShort: false, // 是否因前车占用车站而机外等待
    _holdTimer: 0,         // 累计机外等待时长(game sec)，超时强制进站
    _stuckTimer: 0,      // 累计静止时长(game sec)，用于卡死检测
    dwellRemaining: 0,   // seconds remaining in station
    load: 0,             // current passenger count (scaled)
    maxLoad: capacity,
    _passengerIds: [],   // 乘客ID列表（on_train状态的乘客）
    nextStationIdx: direction === 0 ? 1 : -999, // index in line.stationIds (resolved below)
  };

  // Resolve starting position and nextStationIdx
  const totalStations = line.stationIds.length;
  if (direction === 0) {
    // Forward: start at first station (node index 0)
    train.nextStationIdx = 1;
    train.segIndex = 0;
    train.segProgress = 0;
  } else {
    // Backward: start at the last station, heading toward second-to-last
    train.nextStationIdx = totalStations - 2;
    const lastStationId = line.stationIds[totalStations - 1];
    let stationNodeIdx = -1;
    for (let i = nodes.length - 1; i >= 0; i--) {
      if (nodes[i].type === 'station' && nodes[i].id === lastStationId) {
        stationNodeIdx = i;
        break;
      }
    }
    train.segIndex = Math.max(0, stationNodeIdx - 1); // segment [i-1, i] ends at the last station
    train.segProgress = 1; // positioned at the last station node
  }

  return train;
}

function chooseBalancedSpawnStation(line, direction) {
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return -1;
  const totalStations = line.stationIds.length;
  const loadByStation = Array(totalStations).fill(0);
  state.trains.forEach(t => {
    if (!t || t.lineId !== line.id || t.state === 'done' || t.state === 'waiting') return;
    const idx = Math.max(0, Math.min(totalStations - 1, Math.round(Number(t.nextStationIdx) || 0)));
    loadByStation[idx]++;
  });
  const minIdx = direction === 0 ? 0 : 1;
  const maxIdx = direction === 0 ? totalStations - 2 : totalStations - 1;
  let best = -1, bestScore = Infinity;
  for (let i = minIdx; i <= maxIdx; i++) {
    const terminalPenalty = (i === 0 || i === totalStations - 1) ? 1.6 : 0;
    const edgeBalance = Math.abs((i / Math.max(1, totalStations - 1)) - 0.5) * 0.15;
    const score = loadByStation[i] * 10 + terminalPenalty + edgeBalance;
    if (score < bestScore) {
      bestScore = score;
      best = i;
    }
  }
  return best;
}

function placeTrainAtStationBalanced(train, line, nodes, stationIdx, direction) {
  if (!train || !line || !Array.isArray(nodes)) return false;
  const totalStations = line.stationIds.length;
  if (totalStations >= 2) {
    if (Number(direction) === 1 && stationIdx <= 0) stationIdx = 1;
    if (Number(direction) !== 1 && stationIdx >= totalStations - 1) stationIdx = totalStations - 2;
  }
  if (stationIdx < 0 || stationIdx >= totalStations) return false;
  const stationId = line.stationIds[stationIdx];
  const nodeIdx = nodes.findIndex(n => n.type === 'station' && n.id === stationId);
  if (nodeIdx < 0) return false;
  train.direction = direction;
  train.nextStationIdx = stationIdx;
  train.speed = 0;
  train.state = 'dwelling';
  train.dwellRemaining = cityrailFixedDwellSeconds(line);
  train.depTime = 0;
  train._holdingShort = false;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  if (direction === 0) {
    train.segIndex = Math.max(0, Math.min(nodes.length - 2, nodeIdx));
    train.segProgress = stationIdx >= totalStations - 1 ? 1 : 0;
  } else {
    train.segIndex = Math.max(0, Math.min(nodes.length - 2, nodeIdx - 1));
    train.segProgress = stationIdx <= 0 ? 0 : 1;
  }
  return true;
}
try {
  window.chooseBalancedSpawnStation = chooseBalancedSpawnStation;
  window.placeTrainAtStationBalanced = placeTrainAtStationBalanced;
} catch(e) {}

function cityrailFullTrainResetAuthorityDepth() {
  return Number(window.__CITYRAIL_FULL_TRAIN_RESET_AUTH_DEPTH || 0);
}

function cityrailCanFullNetworkTrainReset(reason) {
  return cityrailFullTrainResetAuthorityDepth() > 0;
}

function cityrailRecordBlockedFullTrainReset(reason, detail) {
  try {
    state.__cityrailBlockedFullTrainReset = {
      reason: String(reason || 'unknown'),
      detail: detail || null,
      hour: Number(state && state.simulationHour) || 0,
      at: Date.now()
    };
    document.documentElement.dataset.cityrailBlockedFullTrainReset = state.__cityrailBlockedFullTrainReset.reason;
  } catch(e) {}
}

function cityrailWithFullNetworkTrainResetAuthority(reason, fn) {
  window.__CITYRAIL_FULL_TRAIN_RESET_AUTH_DEPTH = cityrailFullTrainResetAuthorityDepth() + 1;
  try {
    try {
      state.__cityrailLastFullTrainResetAuthority = {
        reason: String(reason || 'midnight'),
        hour: Number(state && state.simulationHour) || 0,
        at: Date.now()
      };
    } catch(e) {}
    return fn();
  } finally {
    window.__CITYRAIL_FULL_TRAIN_RESET_AUTH_DEPTH = Math.max(0, cityrailFullTrainResetAuthorityDepth() - 1);
  }
}

function cityrailSyncTrainsWithoutFullReset(reason) {
  if (typeof cityrailIsTrainTopologyEditReason === 'function' && cityrailIsTrainTopologyEditReason(reason)) {
    return cityrailRefreshTrainsAfterTopologyEdit(reason || 'topology-sync');
  }
  try { _routeGraphStale = true; } catch(e) {}
  try {
    const existingPools = state.stationWaitingPool || {};
    state.stationWaitingPool = state.stationWaitingPool || {};
    (state.stations || []).forEach(station => {
      if (!station || station.id == null) return;
      if (!state.stationWaitingPool[station.id]) {
        state.stationWaitingPool[station.id] = existingPools[station.id] || {
          waiting: 0,
          totalArrived: 0,
          totalBoarded: 0,
          totalDelivered: 0
        };
      }
    });
  } catch(e) {}
  try {
    if (window.CityRailDispatchAuthorityV300 && typeof window.CityRailDispatchAuthorityV300.dispatchLoop === 'function') {
      window.CityRailDispatchAuthorityV300.dispatchLoop();
    } else if (typeof dispatchLoop === 'function' && dispatchLoop !== initAllTrains) {
      dispatchLoop();
    }
  } catch(e) {}
  try { renderAllTrainMarkers(); } catch(e) {}
  cityrailRecordBlockedFullTrainReset(reason || 'initAllTrains', {
    trains: Array.isArray(state && state.trains) ? state.trains.length : 0,
    lines: Array.isArray(state && state.lines) ? state.lines.length : 0
  });
  return state.trains || [];
}

function cityrailInstallTrainResetAuthority(reason) {
  if (!state || state.__cityrailTrainResetAuthorityInstalled) return false;
  let currentTrains = Array.isArray(state.trains) ? state.trains : [];
  try {
    Object.defineProperty(state, 'trains', {
      configurable: true,
      enumerable: true,
      get() { return currentTrains; },
      set(next) {
        const incoming = Array.isArray(next) ? next : [];
        const networkExists = Array.isArray(state.lines) && state.lines.length > 0;
        const clearingWholeFleet = Array.isArray(currentTrains) && currentTrains.length > 0 && incoming.length === 0;
        const validLineIds = new Set((state.lines || []).map(line => String(line && line.id)));
        const clearingOnlyInvalidLines = clearingWholeFleet && currentTrains.every(train => !validLineIds.has(String(train && train.lineId)));
        if (networkExists && clearingWholeFleet && !clearingOnlyInvalidLines && !cityrailCanFullNetworkTrainReset('state.trains')) {
          cityrailRecordBlockedFullTrainReset('state.trains-set', {
            previous: currentTrains.length,
            incoming: incoming.length,
            validLines: validLineIds.size
          });
          return;
        }
        currentTrains = incoming;
      }
    });
    state.__cityrailTrainResetAuthorityInstalled = true;
    state.__cityrailTrainResetAuthorityReason = reason || 'install';
    window.cityrailCanFullNetworkTrainReset = cityrailCanFullNetworkTrainReset;
    window.cityrailWithFullNetworkTrainResetAuthority = cityrailWithFullNetworkTrainResetAuthority;
    window.cityrailSyncTrainsWithoutFullReset = cityrailSyncTrainsWithoutFullReset;
    window.cityrailInstallTrainResetAuthority = cityrailInstallTrainResetAuthority;
    return true;
  } catch(e) {
    return false;
  }
}

// Initialize all trains
function initAllTrains(reason) {
  cityrailInstallTrainResetAuthority('initAllTrains');
  if (!cityrailCanFullNetworkTrainReset(reason || 'initAllTrains')) {
    return cityrailSyncTrainsWithoutFullReset(reason || 'initAllTrains');
  }
  // Clean up
  Object.values(trainMarkers).forEach(m => map.removeLayer(m));
  trainMarkers = {};
  state.trains = [];
  trainLastUpdateHour = -1;

  // 标记路由图缓存失效（线路/站点可能已变更）
  _routeGraphStale = true;

  // ── 初始化各站候车池（保留已有数据以维持连续性）──
  const existingPools = state.stationWaitingPool || {};
  state.stationWaitingPool = {};
  for (const station of state.stations) {
    if (existingPools[station.id]) {
      state.stationWaitingPool[station.id] = existingPools[station.id];
    } else {
      // 候车人数必须只由 PassengerBatch 累加，不填假数据
      state.stationWaitingPool[station.id] = {
        waiting: 0,
        totalArrived: 0,
        totalBoarded: 0,
        totalDelivered: 0,
      };
    }
  }

  state.lines.forEach(line => {
    initTrainsForLine(line);
  });
  // Render even when paused so trains are visible on page load
  renderAllTrainMarkers();
}
cityrailInstallTrainResetAuthority('runtime-boot');

function cityrailIsTrainTopologyEditReason(reason) {
  return /topology|geometry|station|waypoint|node|line-edit|rebuildLineTopology|moveStation|finishStationDrag|refreshStationMoveVisuals|insert|delete|extend|loopChoice|addToLine/i.test(String(reason || ''));
}

function cityrailTrainCurrentLatLng(train, line, nodes) {
  if (!train || !Array.isArray(nodes) || nodes.length < 2) return null;
  const directLat = Number(train.lat);
  const directLng = Number(train.lng);
  if (Number.isFinite(directLat) && Number.isFinite(directLng)) return { lat:directLat, lng:directLng };
  const renderLat = Number(train._lastRenderLatV48);
  const renderLng = Number(train._lastRenderLngV48);
  if (Number.isFinite(renderLat) && Number.isFinite(renderLng)) return { lat:renderLat, lng:renderLng };
  try {
    if ((train.state === 'dwelling' || train.state === 'turning_back' || train.state === 'dispatch_turning_back') && line && Array.isArray(line.stationIds)) {
      const stationId = line.stationIds[Math.max(0, Math.min(line.stationIds.length - 1, Math.round(Number(train.nextStationIdx) || 0)))];
      const station = (state.stations || []).find(st => String(st && st.id) === String(stationId));
      if (station) {
        const pos = typeof getStationPosition === 'function' ? getStationPosition(station, line.id) : station;
        if (Number.isFinite(Number(pos.lat)) && Number.isFinite(Number(pos.lng))) return { lat:Number(pos.lat), lng:Number(pos.lng) };
      }
    }
  } catch(e) {}
  const seg = Math.max(0, Math.min(nodes.length - 2, Math.round(Number(train.segIndex) || 0)));
  const progress = Math.max(0, Math.min(1, Number(train.segProgress) || 0));
  const a = nodes[seg], b = nodes[seg + 1] || a;
  if (!a || !b) return null;
  return {
    lat:Number(a.lat) + (Number(b.lat) - Number(a.lat)) * progress,
    lng:Number(a.lng) + (Number(b.lng) - Number(a.lng)) * progress
  };
}

function cityrailProjectLatLngToTrainNodes(point, nodes) {
  if (!point || !Array.isArray(nodes) || nodes.length < 2) return null;
  let best = null;
  const scale = Math.max(0.1, Math.cos((Number(point.lat) || 0) * Math.PI / 180));
  for (let i = 0; i < nodes.length - 1; i++) {
    const a = nodes[i], b = nodes[i + 1];
    if (!a || !b) continue;
    const ax = Number(a.lng) * scale, ay = Number(a.lat);
    const bx = Number(b.lng) * scale, by = Number(b.lat);
    const px = Number(point.lng) * scale, py = Number(point.lat);
    const dx = bx - ax, dy = by - ay;
    const len2 = dx * dx + dy * dy;
    const t = len2 > 0 ? Math.max(0, Math.min(1, ((px - ax) * dx + (py - ay) * dy) / len2)) : 0;
    const x = ax + dx * t, y = ay + dy * t;
    const dist2 = (px - x) * (px - x) + (py - y) * (py - y);
    if (!best || dist2 < best.dist2) {
      best = {
        segIndex:i,
        segProgress:t,
        lat:Number(a.lat) + (Number(b.lat) - Number(a.lat)) * t,
        lng:Number(a.lng) + (Number(b.lng) - Number(a.lng)) * t,
        dist2
      };
    }
  }
  return best;
}

function cityrailReprojectTrainToLineGeometry(train, line, reason) {
  if (!train || !line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
  let nodes = [];
  try { nodes = getLineTrainNodes(line); } catch(e) { nodes = []; }
  if (!Array.isArray(nodes) || nodes.length < 2) return false;
  const before = cityrailTrainCurrentLatLng(train, line, nodes);
  if (!before) return false;
  const projected = cityrailProjectLatLngToTrainNodes(before, nodes);
  if (!projected) return false;
  train.segIndex = Math.max(0, Math.min(nodes.length - 2, projected.segIndex));
  train.segProgress = Math.max(0, Math.min(1, projected.segProgress));
  train.lat = projected.lat;
  train.lng = projected.lng;
  train._topologyReprojectReason = reason || 'topology-edit';
  train._topologyReprojectAt = Date.now();
  return true;
}

function cityrailRefreshTrainsAfterTopologyEdit(reason, affectedLines) {
  const lineList = Array.isArray(affectedLines) && affectedLines.length
    ? affectedLines
    : (state && Array.isArray(state.lines) ? state.lines : []);
  const lineMap = new Map();
  lineList.forEach(line => { if (line && line.id != null) lineMap.set(String(line.id), line); });
  let repaired = 0;
  (state.trains || []).forEach(train => {
    if (!train || train.state === 'done') return;
    const line = lineMap.get(String(train.lineId));
    if (!line) return;
    if (cityrailReprojectTrainToLineGeometry(train, line, reason)) repaired++;
  });
  try { renderAllTrainMarkers(); } catch(e) {}
  try {
    state.__cityrailLastTopologyTrainRefresh = {
      reason:String(reason || 'topology-edit'),
      affectedLines:lineMap.size,
      trains:repaired,
      at:Date.now()
    };
  } catch(e) {}
  return state.trains || [];
}

function cityrailSafeInitAllTrains(reason) {
  cityrailInstallTrainResetAuthority('safe-init');
  const st = state || {};
  const hasExistingTrains = Array.isArray(st.trains) && st.trains.length > 0;
  const resetAllowed = cityrailCanFullNetworkTrainReset(reason || 'safe-init');
  if (!resetAllowed && (hasExistingTrains || cityrailIsTrainTopologyEditReason(reason))) {
    return cityrailRefreshTrainsAfterTopologyEdit(reason || 'safe-init-existing-trains');
  }
  const authority = window.CityRailDispatchAuthorityV300;
  if (authority && typeof authority.initTrains === 'function') return authority.initTrains();
  if (!resetAllowed) return cityrailSyncTrainsWithoutFullReset(reason || 'safe-init');
  return state.trains || [];
}

try {
  window.cityrailIsTrainTopologyEditReason = cityrailIsTrainTopologyEditReason;
  window.cityrailRefreshTrainsAfterTopologyEdit = cityrailRefreshTrainsAfterTopologyEdit;
  window.cityrailSafeInitAllTrains = cityrailSafeInitAllTrains;
  window.initAllTrains = initAllTrains = cityrailSafeInitAllTrains;
} catch(e) {}

// ==================== SMOOTH TRAIN ANIMATION LOOP ====================
// Runs at ~30fps via setInterval, driving smooth train movement.
// Uses performance.now() exclusively to avoid timestamp source conflicts.
let _trainAnimTimer = null;


// ═══ 实时发车调度：每帧检查，基于 headway 自动从起点站发车 ═══
// 玩家通过频率间接控制 headway，系统自动推导列车数
function getActiveDispatchTrainsForLine(line) {
  const lineId = String(line && line.id);
  if (!lineId || !Array.isArray(state.trains)) return [];
  const snap = state.__cityrailDispatchSnapshot;
  if (snap && snap.byLine && snap.byLine.has(lineId)) return snap.byLine.get(lineId);
  return state.trains.filter(train =>
    train &&
    String(train.lineId) === lineId &&
    train.state !== 'done' &&
    !train._retireOnTerminal &&
    !train._returnToDepotRequested &&
    !train._outOfServiceToDepot &&
    train._depotState !== 'pulling_in' &&
    !(typeof window.cityrailIsConnectorServiceTrain === 'function' && window.cityrailIsConnectorServiceTrain(train))
  );
}

function getLineDispatchTarget(line) {
  let target = Math.max(0, Number(line && line._strictPlannedFleet) || 0);
  try {
    if (window.cityrailGetStrictPlannedFleet) {
      target = Math.max(0, Number(window.cityrailGetStrictPlannedFleet(line)) || target);
    }
  } catch(e) {}
  if(!target) {
    target = Math.max(
      Number(line && line._strictTargetFleet) || 0,
      Number(line && line.playerConfig && line.playerConfig.fleet && line.playerConfig.fleet.currentTarget) || 0
    );
  }
  return Math.max(0, Math.round(target));
}

function canDispatchHeadwayTrain(line, direction) {
  const target = getLineDispatchTarget(line);
  if (!target) return true;
  const lineId = String(line && line.id);
  const snap = state.__cityrailDispatchSnapshot;
  const activeCount = snap && snap.countByLine ? (snap.countByLine.get(lineId) || 0) : getActiveDispatchTrainsForLine(line).length;
  if (activeCount >= target) {
    line._strictFleetShortage = 0;
    line._strictFleetShortageReason = '';
    return false;
  }
  if (isLoopLine(line)) return activeCount < target;
  const dir = Number(direction) === 1 ? 1 : 0;
  const dirTarget = dir === 0 ? Math.ceil(target / 2) : Math.floor(target / 2);
  const activeDir = snap && snap.countByLineDir ? (snap.countByLineDir.get(lineId + '|' + dir) || 0) : getActiveDispatchTrainsForLine(line).filter(train => Number(train.direction) === dir).length;
  return activeDir < Math.max(1, dirTarget);
}

let _lastDispatchLoopPerf = 0;
function buildDispatchSnapshot() {
  const byLine = new Map();
  const countByLine = new Map();
  const countByLineDir = new Map();
  if (Array.isArray(state.trains)) {
    for (const train of state.trains) {
      if (!train || train.state === 'done' || train._retireOnTerminal || train._returnToDepotRequested || train._outOfServiceToDepot || train._depotState === 'pulling_in') continue;
      if (typeof window.cityrailIsConnectorServiceTrain === 'function' && window.cityrailIsConnectorServiceTrain(train)) continue;
      const lineId = String(train.lineId);
      let arr = byLine.get(lineId);
      if (!arr) byLine.set(lineId, arr = []);
      arr.push(train);
      countByLine.set(lineId, (countByLine.get(lineId) || 0) + 1);
      const dirKey = lineId + '|' + (Number(train.direction) === 1 ? 1 : 0);
      countByLineDir.set(dirKey, (countByLineDir.get(dirKey) || 0) + 1);
    }
  }
  return { byLine, countByLine, countByLineDir };
}

function dispatchLoop() {
  if (!state.isSimulating) return;
  const perf = performance.now ? performance.now() : Date.now();
  const trainCount = Array.isArray(state.trains) ? state.trains.length : 0;
  const minInterval = trainCount > 180 ? 420 : 180;
  if (_lastDispatchLoopPerf && perf - _lastDispatchLoopPerf < minInterval) return;
  _lastDispatchLoopPerf = perf;
  const authority = window.CityRailDispatchAuthorityV300;
  if (authority && typeof authority.dispatchLoop === 'function') {
    authority.dispatchLoop();
    return;
  }
  if (state && Array.isArray(state.lines)) {
    state.lines.forEach(line => {
      if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return;
      line._strictFleetShortageReason = 'dispatch_authority_unavailable';
      line._strictFleetShortageUpdatedAt = Date.now();
    });
  }
}

function cityrailIsMapInteractionBusy() {
  try {
    if (window.CityRailPerformanceAuthorityV255 && typeof CityRailPerformanceAuthorityV255.mapActive === 'function' && CityRailPerformanceAuthorityV255.mapActive()) return true;
  } catch(e) {}
  try {
    const root = document.documentElement;
    return root.classList.contains('cityrail-map-interacting') ||
      root.classList.contains('cityrail-v255-map-active') ||
      root.dataset.cityrailMapInteraction === 'active';
  } catch(e) {}
  return false;
}

function cityrailTrainFrameIntervalMs() {
  if (document.hidden) return 500;
  const trains = Array.isArray(state.trains) ? state.trains.length : 0;
  const stations = Array.isArray(state.stations) ? state.stations.length : 0;
  const load = trains + stations * 0.35;
  if (cityrailIsMapInteractionBusy()) return load > 900 ? 4000 : 1200;
  if (load > 1200) return 2200;
  if (load > 850) return 1400;
  if (load > 520) return 100;
  return 50;
}

function startTrainAnimation() {
  if (_trainAnimTimer) return; // already running
  // 只重置时间基准，不重置任何列车位置。
  lastTrainFrameTime = performance.now();
  const tick = () => {
    _trainAnimTimer = null;
    trainAnimationFrame(performance.now());
    if (state.isSimulating) {
      _trainAnimTimer = setTimeout(tick, cityrailTrainFrameIntervalMs());
    }
  };
  _trainAnimTimer = setTimeout(tick, cityrailTrainFrameIntervalMs());
}

function stopTrainAnimation() {
  if (_trainAnimTimer) { clearTimeout(_trainAnimTimer); clearInterval(_trainAnimTimer); _trainAnimTimer = null; }
  lastTrainFrameTime = null;
}

function trainAnimationFrame(nowTime) {
  const mapBusy = cityrailIsMapInteractionBusy();
  // ── 面板刷新（始终执行，不受模拟状态影响）──
  if (stationDetailId && !_lastSdRefreshTime) _lastSdRefreshTime = nowTime;
  const _sdMoveBtn = document.getElementById('sd-btn-move');
  const _stationMoveActive = (_sdMoveBtn && _sdMoveBtn.classList.contains('active-action')) || !!dragStationId;
  if (!mapBusy && stationDetailId && !_stationMoveActive && nowTime - (_lastSdRefreshTime || 0) > 700) {
    refreshStationDetail(stationDetailId);
    _lastSdRefreshTime = nowTime;
  }

  // 控制中心与线网图面板（暂停状态下也要刷新，反映拖拽时间轴后数据变化）
  if (!window._lastPanelRefresh) window._lastPanelRefresh = 0;
  if (!mapBusy && nowTime - window._lastPanelRefresh >= 1400) {
    window._lastPanelRefresh = nowTime;
    renderCtrlCenter();
    if (window._metroMapRendered) renderMetroMap();
  }

  // 暂停时重置时间基准（列车可能被清空再重建但不停帧）
  if (!state.isSimulating) {
    lastTrainFrameTime = null;
    return;
  }

  // 首帧初始化基准时间
  if (lastTrainFrameTime === null) {
    lastTrainFrameTime = nowTime;
    return;
  }

  // 真实时间差（秒）。大线网采用低频累计步进，不丢客流时间，
  // 但仍限制单步跨度，避免切回页面后列车跨站跳跃。
  let elapsed = nowTime - lastTrainFrameTime;
  lastTrainFrameTime = nowTime;
  if (elapsed <= 0) return; // 时间未前进则跳过（罕见情况）

  const largeFrameNet = ((state.stations && state.stations.length > 420) || (state.trains && state.trains.length > 900));
  if (mapBusy && largeFrameNet) {
    window.__cityrailDeferredTrainElapsedMs = Math.min(5000, (Number(window.__cityrailDeferredTrainElapsedMs) || 0) + elapsed);
    return;
  }
  if (!mapBusy && window.__cityrailDeferredTrainElapsedMs) {
    elapsed += Number(window.__cityrailDeferredTrainElapsedMs) || 0;
    window.__cityrailDeferredTrainElapsedMs = 0;
  }
  const maxRealStep = document.hidden ? 0.5 : (largeFrameNet ? 4.5 : 0.35);
  const dtRealSec = Math.min(elapsed / 1000, maxRealStep);
  const dtGameSec = dtRealSec * state.simSpeed;
  if (dtGameSec <= 0) return;

  window.__cityrailOpsAccumGameSec = Math.min(180, (Number(window.__cityrailOpsAccumGameSec) || 0) + dtGameSec);
  const opsAccum = Number(window.__cityrailOpsAccumGameSec) || 0;
  const largeOpsNet = (state.stations && state.stations.length > 420) || (state.trains && state.trains.length > 900);
  const opsInterval = mapBusy ? (largeOpsNet ? 6000 : 2200) : (largeOpsNet ? 3000 : 900);
  const opsDue = !window.__cityrailLastOpsTickAt || nowTime - window.__cityrailLastOpsTickAt >= opsInterval || opsAccum >= 15;

  if (opsDue) {
    window.__cityrailLastOpsTickAt = nowTime;
    window.__cityrailOpsAccumGameSec = 0;

    // ── 实时发车调度：基于 headway 自动发车 ──
    dispatchLoop();

    // 发车调度必须先于空车返回执行。否则首班前没有车时，首班时刻永远进不了调度器。
    // 乘客需求由 runSimLoop 按游戏时间推进，不能依赖列车动画帧。
    if (state.trains.length === 0) return;

  } else if (state.trains.length === 0) {
    return;
  }

  // v9 性能优化：不再每 33ms 全量重建 _batchMap。
  // 新建/上车/下车逻辑会增量维护 _batchMap；这里只做低频压缩和索引修复。
  if (!window._lastBatchCompactV9 || nowTime - window._lastBatchCompactV9 > 2500) {
    window._lastBatchCompactV9 = nowTime;
    try { compactWaitingBatchesV9(); } catch(e) {}
  }

  // 定期清理已送达乘客（每 60 秒游戏时间清理一次）
  const nowGameTime = state.simulationHour * 3600;
  if (!_lastCleanupTime) _lastCleanupTime = nowGameTime;
  if (nowGameTime - _lastCleanupTime > 60) {
    cleanupArrivedBatches();
    _lastCleanupTime = nowGameTime;
  }

  // v159: do not cap stationWaitingPool. Waiting counts are passenger data; late-game
  // performance is handled by no-loss batch compaction instead.

// Update trains with smooth sub-second delta
updateTrains(dtGameSec);

}

// Update train positions and states
function updateTrains(dtGameSeconds) {
  const toRemove = [];
  const stuckTrains = []; // 卡死列车：记录线路/方向信息用于补充运力
  const tickContext = createTrainTickContext();
  state.trains.forEach(train => {
    updateSingleTrain(train, dtGameSeconds, toRemove, tickContext);
  });

  // Separate stuck trains from normal removals
  const removedTrainIds = new Set();
  const removedTrainObjects = new Set();
  toRemove.forEach(train => {
    if (!train) return;
    removedTrainObjects.add(train);
    if (train.id != null) removedTrainIds.add(String(train.id));
    if (train._stuck) stuckTrains.push(train);
    // 列车上的乘客返回候车状态（回到当前车站的候车池）
    // 跳过已由 retireTrain 自行处理过的列车，避免双重返还
    if (train._passengersAlreadyReturned) {
      if (trainMarkers[train.id]) {
        map.removeLayer(trainMarkers[train.id]);
        delete trainMarkers[train.id];
      }
      return;
    }
		    if (train._passengerIds) {
      const tLine = tickContext && tickContext.getLine ? tickContext.getLine(train.lineId) : cityrailLineByIdFast(train.lineId);
      const curStationId = tLine && Array.isArray(tLine.stationIds)
        ? tLine.stationIds[Math.max(0, Math.min(tLine.stationIds.length - 1, Math.round(Number(train.nextStationIdx) || 0)))]
        : null;
      for (let k = 0; k < train._passengerIds.length; k++) {
        const p = state._batchMap ? state._batchMap[train._passengerIds[k]] : null;
        if (p && p.state === 'on_train') {
          p.state = 'waiting';
          p.trainId = null;
          p.currentStationId = curStationId || p.currentStationId || p.originId || null;
          if (p.currentStationId) {
            if (!state.stationWaitingPool) state.stationWaitingPool = {};
            const pool = state.stationWaitingPool[p.currentStationId] || (state.stationWaitingPool[p.currentStationId] = { waiting:0, totalArrived:0, totalBoarded:0, totalDelivered:0 });
            pool.waiting += (p.count || PASSENGER_BATCH_SCALE);
          }
          try { if (typeof addWaitingIndexV9 === 'function') addWaitingIndexV9(p); } catch(e) {}
        }
	      }
      train._passengerIds = [];
      train.load = train.passengerCount = train.passengers = train.onboard = 0;
      train._passengersAlreadyReturned = true;
	    }
	    try { DepotService.returnTrain(train, train._stuck ? 'stuck_recycle' : 'removed'); } catch(e) {}
	    if (trainMarkers[train.id]) {
      map.removeLayer(trainMarkers[train.id]);
      delete trainMarkers[train.id];
    }
  });
  if (removedTrainIds.size || removedTrainObjects.size) {
    state.trains = state.trains.filter(t => !removedTrainObjects.has(t) && !removedTrainIds.has(String(t && t.id)));
  }

  // 卡死列车只回收；后续出车由 v300 时刻表权威按用户车隔从车辆段发出。

  if (!window.__cityrailSkipDepotSyncDuringTrainSubstep) {
    try {
      const syncNow = performance.now();
      const shouldSyncDepotStock = toRemove.length > 0 || !window.__cityrailLastDepotStockSyncAt || syncNow - window.__cityrailLastDepotStockSyncAt > 1000;
      if (shouldSyncDepotStock && window.CityRailDepotService && typeof CityRailDepotService.syncStock === 'function') {
        window.__cityrailLastDepotStockSyncAt = syncNow;
        CityRailDepotService.syncStock();
      }
    } catch(e) {}
  }

  // Redraw all train markers
  if (!window.__cityrailSkipTrainRenderDuringSubstep && !cityrailIsMapInteractionBusy()) {
    renderAllTrainMarkers();
  }

  try {
    if (window.CityRailAtsLiveV137 && typeof window.CityRailAtsLiveV137.markDirty === 'function') {
      window.CityRailAtsLiveV137.markDirty('train-tick');
    }
  } catch(e) {}

  // Refresh line ops panel every ~0.5s (throttled) — 确保列车状态实时显示
  const opsOverlay = document.getElementById('line-config-overlay');
  if (opsCurrentLineId && opsOverlay && !opsOverlay.classList.contains('hidden') && !cityrailIsMapInteractionBusy()) {
    const now = performance.now();
    if (!opsLastRefresh || now - opsLastRefresh > 500) {
      opsLastRefresh = now;
      renderLineOpsPanel(opsCurrentLineId, opsCurrentDir);
    }
  }
}

const INTENTIONAL_TRAIN_STOP_STATES = new Set(['waiting', 'done', 'dwelling', 'turning_back', 'dispatch_turning_back', 'holding_short', 'depot_pulling_out']);

function cityrailTrainStationOccId(train, line, stationIdx) {
  const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
  const idx = Math.max(0, Math.min(Math.max(0, ids.length - 1), Math.round(Number(stationIdx) || 0)));
  return ids[idx] != null ? String(ids[idx]) : String(stationIdx);
}

function cityrailTrainOccKeyFromStationIds(lineId, direction, stationIds, stationIdx) {
  const ids = Array.isArray(stationIds) ? stationIds : [];
  const idx = Math.max(0, Math.min(Math.max(0, ids.length - 1), Math.round(Number(stationIdx) || 0)));
  const stationKey = ids[idx] != null ? String(ids[idx]) : String(stationIdx);
  return String(lineId) + '|' + (Number(direction) === 1 ? 1 : 0) + '|' + stationKey;
}

function cityrailTrainOccKey(lineOrId, direction, stationIdx, train) {
  let stationKey = String(stationIdx);
  if (lineOrId && typeof lineOrId === 'object') stationKey = cityrailTrainStationOccId(train, lineOrId, stationIdx);
  return String(lineOrId && typeof lineOrId === 'object' ? lineOrId.id : lineOrId) + '|' + (Number(direction) === 1 ? 1 : 0) + '|' + stationKey;
}

function createTrainTickContext() {
  const runtimeIndexes = cityrailGetRuntimeIndexes();
  const lineById = runtimeIndexes.lineById;
  const stationById = runtimeIndexes.stationById;
  const lineNodesById = new Map();
  const lineProfileByKey = new Map();
  const occupiedStations = new Map();
  function addOccupied(train) {
    if (!train || train.id == null || train.lineId == null) return;
    const line = lineById.get(String(train.lineId));
    const route = train.routePlan && Array.isArray(train.routePlan.stationIds) && train.routePlan.stationIds.length >= 2 ? train.routePlan : null;
    const key = route
      ? cityrailTrainOccKeyFromStationIds(train.lineId, train.direction, route.stationIds, train.nextStationIdx)
      : cityrailTrainOccKey(line || train.lineId, train.direction, train.nextStationIdx, train);
    let set = occupiedStations.get(key);
    if (!set) occupiedStations.set(key, set = new Set());
    set.add(String(train.id));
  }
  for (const train of state.trains || []) {
    if (!train) continue;
    const trainState = String(train.state || '');
    if (trainState === 'dwelling' || trainState === 'turning_back' || trainState === 'dispatch_turning_back' || trainState === 'decelerating') {
      addOccupied(train);
      continue;
    }
    if (trainState === 'accelerating' || trainState === 'cruising') {
      const line = lineById.get(String(train.lineId));
      const route = train.routePlan && Array.isArray(train.routePlan.stationIds) && train.routePlan.stationIds.length >= 2 ? train.routePlan : null;
      const ids = route ? route.stationIds : (line && Array.isArray(line.stationIds) ? line.stationIds : []);
      const stationId = ids[train.nextStationIdx] || null;
      const station = stationId != null ? stationById.get(String(stationId)) : null;
      if (station && Number.isFinite(Number(train.lat)) && Number.isFinite(Number(train.lng))) {
        try {
          const latDelta = Math.abs(Number(train.lat) - Number(station.lat));
          const lngDelta = Math.abs(Number(train.lng) - Number(station.lng));
          if (latDelta < 0.003 && lngDelta < 0.003 && haversine(train.lat, train.lng, station.lat, station.lng) < 0.2) addOccupied(train);
        } catch(e) {}
      }
    }
  }
  return {
    holdingReleaseKeys: new Set(),
    lineById,
    stationById,
    occupiedStations,
    lineNodesById,
	    getLine(lineId) { return lineById.get(String(lineId)); },
	    getStation(stationId) { return stationById.get(String(stationId)); },
    getLineProfile(line) {
      if (!line || line.id == null) {
        return { maxSpeed:80, accelMs2:1, decelMs2:1.1, accel:3.6, decel:3.96, loop:false };
      }
      const key = [
        String(line.id),
        line._runtimeRouteId || '',
        line._topologyVersion || 0,
        line._geometryVersion || 0,
        line.stationIds && line.stationIds.length || 0,
        line.loopMode || '',
        line.isLoop ? 1 : 0,
        line.loopClosedExplicit ? 1 : 0,
        line.trainType || '',
        line.cars || '',
        line.speed || ''
      ].join('|');
      let profile = lineProfileByKey.get(key);
      if (!profile) {
        const maxSpeed = getTrainMaxSpeed(line);
        const accelMs2 = getTrainAccel(line);
        const decelMs2 = getTrainDecel(line);
        profile = {
          maxSpeed,
          accelMs2,
          decelMs2,
          accel: accelMs2 * 3.6,
          decel: decelMs2 * 3.6,
          loop: isLoopLine(line)
        };
        lineProfileByKey.set(key, profile);
      }
      return profile;
    },
	    getLineNodes(line) {
      if (!line || line.id == null) return [];
      const key = [
        String(line.id),
        line._runtimeRouteId || '',
        Array.isArray(line.stationIds) ? line.stationIds.join(',') : '',
        Array.isArray(line.waypoints) ? line.waypoints.length : 0,
        line.pathMode || ''
      ].join('|');
      let nodes = lineNodesById.get(key);
      if (!nodes) {
        nodes = getLineTrainNodes(line);
        lineNodesById.set(key, nodes);
      }
      return nodes;
    }
  };
}

// 防撞：检查前方车站是否被其他列车占用
const SAFE_HOLDING_DISTANCE = 0.15; // km，机外等待安全距离（约150m）
function isStationOccupied(lineOrId, direction, stationIdx, excludeTrainId, tickContext) {
  if (tickContext && tickContext.occupiedStations) {
    const set = tickContext.occupiedStations.get(cityrailTrainOccKey(lineOrId, direction, stationIdx, null));
    if (!set || set.size === 0) return false;
    const excluded = String(excludeTrainId);
    for (const id of set) if (id !== excluded) return true;
    return false;
  }
  const line = lineOrId && typeof lineOrId === 'object' ? lineOrId : cityrailLineByIdFast(lineOrId);
  const lineId = line && line.id != null ? line.id : lineOrId;
  const targetStationId = line && Array.isArray(line.stationIds) ? line.stationIds[stationIdx] : null;
  if (!targetStationId) return false;
  return state.trains.some(t => {
    if (t.id === excludeTrainId) return false;
    if (t.lineId !== lineId || t.direction !== direction) return false;
    // 前方有列车正在停站
    if (t.nextStationIdx === stationIdx && (t.state === 'dwelling' || t.state === 'turning_back' || t.state === 'dispatch_turning_back')) return true;
    // 前方有列车正在减速进站（已接近车站平台）
    if (t.state === 'decelerating' && t.nextStationIdx === stationIdx) return true;
    // 前方有列车正在驶离该站（刚离开站台，距离车站极近）
    // 用实际地理距离检测，替代不可靠的 segProgress 边界判断
    if (t.nextStationIdx === stationIdx && (t.state === 'accelerating' || t.state === 'cruising')) {
      const station = cityrailStationByIdFast(targetStationId);
      if (station) {
        const latDelta = Math.abs(Number(t.lat) - Number(station.lat));
        const lngDelta = Math.abs(Number(t.lng) - Number(station.lng));
        if (latDelta >= 0.003 || lngDelta >= 0.003) return false;
        const distKm = haversine(t.lat, t.lng, station.lat, station.lng);
        if (distKm < 0.2) return true; // 200米内视为刚离开
      }
    }
    return false;
  });
}



// v57：底层终点折返状态机。
// 终点到站后不再复用普通 dwelling。普通停站可能被客流模块不断延长 dwellRemaining，
// 导致终点车“等客不折返”。这里将终点停站独立为 turning_back：
// 允许上下客，但折返计时只由列车状态机控制，计时到必须切换方向并离开终点站台。
function isExpressServiceActive(line) {
  const cfg = line && line.expressService;
  return !!(cfg && cfg.enabled && Array.isArray(cfg.expressStops) && cfg.expressStops.length >= 2);
}

function isExpressServiceTrain(train, line) {
  return !!(train && train.serviceType === 'express' && isExpressServiceActive(line));
}

function serviceStopSetForTrain(line, train) {
  const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
  const cfg = line && line.expressService || {};
  const stops = Array.isArray(train && train.expressStops) && train.expressStops.length
    ? train.expressStops
    : (Array.isArray(cfg.expressStops) ? cfg.expressStops : []);
  const set = new Set(stops.map(v => String(v)));
  if (ids[0]) set.add(String(ids[0]));
  if (ids.length > 1) set.add(String(ids[ids.length - 1]));
  return set;
}

function isServiceStopIndex(line, idx, train) {
  const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
  const i = Math.max(0, Math.min(ids.length - 1, Math.round(Number(idx) || 0)));
  if (!ids.length) return false;
  if (!isExpressServiceTrain(train, line)) return true;
  return serviceStopSetForTrain(line, train).has(String(ids[i]));
}

function nextServiceStopIndex(line, fromIdx, direction, train) {
  const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
  if (!ids.length) return Math.round(Number(fromIdx) || 0);
  const start = Math.max(0, Math.min(ids.length - 1, Math.round(Number(fromIdx) || 0)));
  if (!isExpressServiceTrain(train, line)) return start;
  const dir = Number(direction) === 1 ? 1 : 0;
  if (dir === 0) {
    for (let i = start; i < ids.length; i++) if (isServiceStopIndex(line, i, train)) return i;
    return ids.length - 1;
  }
  for (let i = start; i >= 0; i--) if (isServiceStopIndex(line, i, train)) return i;
  return 0;
}

function normalizeTrainTargetForService(train, line, reason) {
  if (!train || !line || !isExpressServiceTrain(train, line)) {
    if (train) train._expressSkipping = false;
    return false;
  }
  const current = Math.round(Number(train.nextStationIdx) || 0);
  const target = nextServiceStopIndex(line, current, train.direction, train);
  train._expressSkippedFromV29 = current;
  train._expressSkipping = target !== current;
  train._serviceTargetNormalizedReason = reason || '';
  train.nextStationIdx = target;
  return target !== current;
}

try {
  window.cityrailNormalizeTrainTargetForService = normalizeTrainTargetForService;
  window.cityrailNextServiceStopIndex = nextServiceStopIndex;
} catch(e) {}

function isTerminalStationIndex(line, idx) {
  if (isLoopLine(line)) return false;
  return !!(line && Array.isArray(line.stationIds) && (idx === 0 || idx === line.stationIds.length - 1));
}

function getStationNodeIndexForLine(line, stationIdx, nodes) {
  if (!line || !Array.isArray(line.stationIds) || !Array.isArray(nodes)) return -1;
  const stationId = line.stationIds[stationIdx];
  const indexed = nodes._stationNodeIndexes && nodes._stationNodeIndexes[String(stationId)];
  if (indexed && indexed.length) return indexed[0];
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i] && nodes[i].type === 'station' && nodes[i].id === stationId) return i;
  }
  return -1;
}

function getTerminalOutboundPlan(line, stationIdx, nodes) {
  const total = line && line.stationIds ? line.stationIds.length : 0;
  const nodeIdx = getStationNodeIndexForLine(line, stationIdx, nodes);
  if (nodeIdx < 0 || total < 2) return null;
  if (stationIdx >= total - 1) {
    return { direction: 1, nextStationIdx: total - 2, segIndex: Math.max(0, nodeIdx - 1), segProgress: 1 };
  }
  if (stationIdx <= 0) {
    return { direction: 0, nextStationIdx: 1, segIndex: nodeIdx, segProgress: 0 };
  }
  return null;
}

function beginTerminalTurnback(train, line, nodes, reason) {
  if (!train || !line || !isTerminalStationIndex(line, train.nextStationIdx)) return false;
  const sec = (typeof getTerminalTurnbackDwellSec === 'function' ? getTerminalTurnbackDwellSec(line) : getDwellBase(line));
  train.state = 'turning_back';
  train.speed = 0;
  train.dwellRemaining = Math.max(3, Math.min(45, Number(sec) || 12));
  train._turnbackDuration = train.dwellRemaining;
  train._turnbackElapsed = 0;
  train._turnbackReason = reason || 'terminal-arrival';
  train._holdingShort = false;
  train._terminalHold = false;
  train._terminalHoldForSecondStation = false;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  if (window.CITYRAIL_DEBUG_TRAIN === true) {
    try { console.warn('[CityRail v57]', '进入终点折返状态', { trainId: train.id, line: line.name || line.id, terminalIdx: train.nextStationIdx, direction: train.direction, seconds: train.dwellRemaining, reason: train._turnbackReason }); } catch(e) {}
  }
  return true;
}

function cityrailV300TerminalReleaseClockSec() {
  try { return (Number(state && state.simulationHour) || 0) * 3600; } catch(e) { return Date.now() / 1000; }
}

function cityrailV300TurnbackHeadwaySec(line) {
  if (window.cityrailDispatchAuthorityOwnsFleet && Number(line && line._v300EffectiveServiceIntervalSec) > 0) {
    return Math.max(30, Number(line._v300EffectiveServiceIntervalSec) || 0);
  }
  try { if (typeof getCurrentHeadway === 'function') return Math.max(30, Number(getCurrentHeadway(line)) || 0); } catch(e) {}
  return Math.max(30, Number(line && line._strictHeadwaySec) || 300);
}

function cityrailV300CanReleaseTerminalTurnback(train, line, plan, reason) {
  if (!window.cityrailDispatchAuthorityOwnsFleet) return true;
  if (!train || !line || !plan) return true;
  if (train._dispatchHold || train._manualHoldUntil === Infinity) return false;
  const reasonText = String(reason || train._dispatchCommand || '');
  if (/ats|manual|user|release|force-release/i.test(reasonText)) return true;
  if (typeof isLoopLine === 'function' && isLoopLine(line) && typeof cityrailIsSingleDirectionLoopLine === 'function' && cityrailIsSingleDirectionLoopLine(line)) return true;
  const dir = Number(plan.direction) === 1 ? 1 : 0;
  const nowSec = cityrailV300TerminalReleaseClockSec();
  const hw = cityrailV300TurnbackHeadwaySec(line);
  line._v300TerminalReleaseSec = line._v300TerminalReleaseSec || Object.create(null);
  const key = String(dir);
  const last = Number(line._v300TerminalReleaseSec[key]);
  if (!Number.isFinite(last) || nowSec - last >= hw - 2) {
    line._v300TerminalReleaseSec[key] = nowSec;
    train._v300TerminalHeadwayHold = false;
    return true;
  }
  const wait = Math.max(1, hw - (nowSec - last));
  train.state = 'turning_back';
  train.speed = 0;
  train.dwellRemaining = Math.max(Number(train.dwellRemaining) || 0, wait);
  train._v300TerminalHeadwayHold = true;
  train._v300TerminalHeadwayWaitSec = wait;
  train._v300TerminalHeadwayDirection = dir;
  return false;
}

function completeTerminalTurnback(train, line, nodes, reason) {
  if (!train || !line || !isTerminalStationIndex(line, train.nextStationIdx)) return false;
  const terminalIdx = train.nextStationIdx;
  const plan = getTerminalOutboundPlan(line, terminalIdx, nodes);
  if (!plan) return false;
  if (!cityrailV300CanReleaseTerminalTurnback(train, line, plan, reason)) return false;
  train.direction = plan.direction;
  train.nextStationIdx = plan.nextStationIdx;
  normalizeTrainTargetForService(train, line, 'terminal-turnback');
  train.segIndex = plan.segIndex;
  train.segProgress = plan.segProgress;
  train.state = 'accelerating';
  train.speed = 0;
  train.dwellRemaining = 0;
  train._turnbackElapsed = 0;
  train._turnbackDuration = 0;
  train._holdingShort = false;
  train._terminalHold = false;
  train._terminalHoldForSecondStation = false;
  train._v300TerminalHeadwayHold = false;
  train._v300TerminalHeadwayWaitSec = 0;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  if (window.CITYRAIL_DEBUG_TRAIN === true) {
    try { console.warn('[CityRail v57]', '折返完成，反向发车', { trainId: train.id, line: line.name || line.id, fromTerminalIdx: terminalIdx, newDirection: train.direction, nextStationIdx: train.nextStationIdx, segIndex: train.segIndex, segProgress: train.segProgress, reason: reason || 'timer' }); } catch(e) {}
  }
  return true;
}

function getDispatchTurnbackPlan(train, line, nodes) {
  if (!train || !line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return null;
  const total = line.stationIds.length;
  const stationIdx = Math.max(0, Math.min(total - 1, Math.round(Number(train.nextStationIdx) || 0)));
  if (stationIdx <= 0 || stationIdx >= total - 1) return getTerminalOutboundPlan(line, stationIdx, nodes);
  const nodeIdx = getStationNodeIndexForLine(line, stationIdx, nodes);
  if (nodeIdx < 0) return null;
  if (train.direction === 0) {
    return { direction: 1, nextStationIdx: stationIdx - 1, segIndex: Math.max(0, nodeIdx - 1), segProgress: 1 };
  }
  return { direction: 0, nextStationIdx: stationIdx + 1, segIndex: nodeIdx, segProgress: 0 };
}

function beginDispatchTurnback(train, line, nodes, reason) {
  if (!train || !line) return false;
  const plan = getDispatchTurnbackPlan(train, line, nodes);
  if (!plan) return false;
  train.state = 'dispatch_turning_back';
  train.speed = 0;
  train.dwellRemaining = Math.max(6, Math.min(30, getDwellBase(line) * 0.55));
  train._turnbackDuration = train.dwellRemaining;
  train._turnbackElapsed = 0;
  train._dispatchTurnbackPlan = plan;
  train._dispatchCommand = 'turnback';
  train._dispatchTurnbackReason = reason || 'dispatch-command';
  train._dispatchHold = false;
  delete train._manualHoldUntil;
  train._holdingShort = false;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  return true;
}

function completeDispatchTurnback(train, line, nodes, reason) {
  const plan = train && train._dispatchTurnbackPlan;
  if (!train || !plan) return false;
  train.direction = plan.direction;
  train.nextStationIdx = plan.nextStationIdx;
  normalizeTrainTargetForService(train, line, 'dispatch-turnback');
  train.segIndex = plan.segIndex;
  train.segProgress = plan.segProgress;
  train.state = 'accelerating';
  train.speed = 0;
  train.dwellRemaining = 0;
  train._turnbackElapsed = 0;
  train._turnbackDuration = 0;
  train._holdingShort = false;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  delete train._dispatchTurnbackNext;
  delete train._dispatchTurnbackPlan;
  delete train._dispatchCommand;
  return true;
}

// v55：终点折返发车不再被“第二站/首区间占用”卡死。
// 根因：旧 v21 保护把终点站当作“等待第二站清空”的蓄车点；
//      当第二站或首段长期有车时，终到列车会反复重置 dwellRemaining，
//      长时间占住终点站，导致后续列车机外等待，最终触发强制刷新/退役。
// 新逻辑：折返计时结束后必须先完成折返并离开终点站台；
//      后续防撞仍由 isStationOccupied / holding_short 在第二站前处理，
//      这样终点站台会被释放，不再堵死整条线。
function canDepartTerminalAfterTurnback(line, train, totalStations, nodes) {
  return true;
}

function normalizeLoopClosureArrival(train, line, nodes) {
  if (!train || !line || !Array.isArray(nodes) || !isLoopLine(line)) return false;
  const dir = Number(train.direction) === 1 ? 1 : 0;
  const nextIdx = Math.round(Number(train.nextStationIdx) || 0);
  if (dir === 0) {
    if (nextIdx !== 0 || (Number(train.segIndex) || 0) < nodes.length - 2) return false;
    train.segIndex = 0;
    train.segProgress = 0;
    train.lat = nodes[0] && nodes[0].lat;
    train.lng = nodes[0] && nodes[0].lng;
  } else {
    const lastStationIdx = Array.isArray(line.stationIds) ? line.stationIds.length - 1 : 0;
    if (nextIdx !== lastStationIdx || (Number(train.segIndex) || 0) > 0) return false;
    train.segIndex = Math.max(0, nodes.length - 2);
    train.segProgress = 1;
    const last = nodes[nodes.length - 1] || nodes[nodes.length - 2];
    train.lat = last && last.lat;
    train.lng = last && last.lng;
  }
  train._loopClosureArrived = true;
  return true;
}

function recoverStationStopIfNeeded(train, line, nodes, dtSec, tickContext) {
  if (!train || !line) return false;
  const stateName = String(train.state || '');
  const stopState = stateName === 'dwelling' || stateName === 'turning_back' || stateName === 'dispatch_turning_back' || stateName === 'holding_short';
  const manualHold = !!train._dispatchHold || train._manualHoldUntil === Infinity || train._dispatchCommand === 'hold';
  if (!stopState || manualHold) {
    train._stationStopElapsed = 0;
    train._stationStopRecoveryReason = '';
    return false;
  }
  const dt = Math.max(0, Number(dtSec) || 0);
  train._stationStopElapsed = Math.max(0, Number(train._stationStopElapsed) || 0) + dt;
  const base = Math.max(8, Number(getDwellBase(line)) || 25);

  if (stateName === 'dwelling') {
    const maxDwell = Math.max(90, base * 6);
    const dwell = Number(train.dwellRemaining);
    if (!Number.isFinite(dwell) || dwell > maxDwell) {
      train.dwellRemaining = Math.max(0, Math.min(Number.isFinite(dwell) ? dwell : 0, maxDwell));
    }
    if (train._stationStopElapsed > maxDwell) {
      train._stationStopRecoveryReason = 'dwelling-timeout';
      if (train._dispatchTurnbackNext) {
        return beginDispatchTurnback(train, line, nodes, 'station-stop-timeout');
      }
      if (isTerminalStationIndex(line, train.nextStationIdx)) {
        return beginTerminalTurnback(train, line, nodes, 'station-stop-timeout');
      }
      train.dwellRemaining = 0;
      return true;
    }
  }

  if (stateName === 'turning_back') {
    const planned = Math.max(3, Math.min(45, Number(train._turnbackDuration) || base));
    if (train._stationStopElapsed > Math.max(90, planned * 3)) {
      train._stationStopRecoveryReason = 'terminal-turnback-timeout';
      return completeTerminalTurnback(train, line, nodes, 'station-stop-timeout');
    }
  }

  if (stateName === 'dispatch_turning_back') {
    const planned = Math.max(6, Math.min(30, Number(train._turnbackDuration) || base * 0.55));
    if (train._stationStopElapsed > Math.max(90, planned * 3)) {
      train._stationStopRecoveryReason = 'dispatch-turnback-timeout';
      return completeDispatchTurnback(train, line, nodes, 'station-stop-timeout');
    }
  }

  if (stateName === 'holding_short') {
    const occupied = isStationOccupied(line, train.direction, train.nextStationIdx, train.id, tickContext);
    if (!occupied && train._stationStopElapsed > 60) {
      train._stationStopRecoveryReason = 'holding-short-clear-timeout';
      train._holdingShort = false;
      train._holdTimer = 0;
      train.state = 'accelerating';
      train.speed = 0;
      return true;
    }
  }
  return false;
}

function updateSingleTrain(train, dtSec, toRemove, tickContext) {
  let line = tickContext && tickContext.getLine ? tickContext.getLine(train.lineId) : state.lines.find(l => l.id === train.lineId);
  if (!line || line.stationIds.length < 2) {
    toRemove.push(train);
    return;
  }

  const route = train && train.routePlan && Array.isArray(train.routePlan.stationIds) && train.routePlan.stationIds.length >= 2
    ? train.routePlan
    : null;
  if (route) {
    line = Object.assign({}, line, {
      stationIds: route.stationIds.slice(),
      waypoints: Array.isArray(route.waypoints) ? route.waypoints.map(w => Object.assign({}, w)) : [],
      expressService: route.expressService || line.expressService,
      pathMode: 'ordered',
      _runtimeParentLineId: line.id,
      _runtimeRouteId: route.routeId || ''
    });
  }
  const nodes = tickContext && tickContext.getLineNodes ? tickContext.getLineNodes(line) : getLineTrainNodes(line);
  if (nodes.length < 2) { toRemove.push(train); return; }
  const depotPulloutBeforeNormalize = train._depotConnectorVisualPhase === 'pulling_out';
  cityrailNormalizeOutboundDepotConnectorVisual(train);
  const totalStations = line.stationIds.length;
  if (train.state === 'depot_pulling_out' || train._depotEntryDwellPending) {
    train.speed = 0;
    train._stuckTimer = 0;
    if (depotPulloutBeforeNormalize && train._depotConnectorVisualPhase === 'pulling_out') return;
    if (cityrailBeginDepotEntryDwell(train, line, nodes, 'connector-complete')) return;
  }
  if (resolveDepotReturnLifecycle(train, line, toRemove, 'train-tick')) return;

  // Check operating hours
  const firstH = line.firstTrain ?? 6;
  const lastH = line.lastTrain ?? 22;
  const nowSec = state.simulationHour * 3600;

  // If train hasn't departed yet (waiting state)
  if (train.state === 'waiting') {
    if (nowSec >= train.depTime && nowSec >= firstH * 3600 && nowSec < lastH * 3600) {
      train.state = 'accelerating';
      train.speed = 0;
    } else if (nowSec >= lastH * 3600) {
      // 已过末班时间，该列车无法再发车，清除
      train.state = 'done';
      toRemove.push(train);
    }
    return;
  }

  // ── 兜底卡死检测：只检测已发车但长时间静止的列车 ──
  const STUCK_TIMEOUT = 300; // 5 分钟游戏时间
  if (train.speed === 0 && !INTENTIONAL_TRAIN_STOP_STATES.has(train.state)) {
    train._stuckTimer = (train._stuckTimer || 0) + dtSec;
    if (train._stuckTimer >= STUCK_TIMEOUT) {
      train._stuck = true;
      toRemove.push(train);
      return;
    }
  } else {
    train._stuckTimer = 0;
  }

  // Allow current run to finish even past operating hours
  // (handled implicitly — trains already running keep going)

  const lineProfile = tickContext && tickContext.getLineProfile ? tickContext.getLineProfile(line) : null;
	  const maxSpeed = lineProfile ? lineProfile.maxSpeed : getTrainMaxSpeed(line); // km/h
	  const accelMs2 = lineProfile ? lineProfile.accelMs2 : getTrainAccel(line);
	  const decelMs2 = lineProfile ? lineProfile.decelMs2 : getTrainDecel(line);
	  const accel = lineProfile ? lineProfile.accel : accelMs2 * 3.6; // convert m/s² to km/h per second
	  const decel = lineProfile ? lineProfile.decel : decelMs2 * 3.6;
  const lineIsLoop = lineProfile ? lineProfile.loop : isLoopLine(line);

  // Get current segment nodes
  const segIdx = train.segIndex;
  if (segIdx < 0 || segIdx >= nodes.length - 1) {
	    if (lineIsLoop) {
      if (train.direction === 0 && segIdx >= nodes.length - 1) {
        train.segIndex = 0;
        train.segProgress = 0;
        train.nextStationIdx = Math.max(1, Math.min(totalStations - 1, Number(train.nextStationIdx) || 1));
        train.state = 'accelerating';
        train.speed = 0;
        train._holdingShort = false;
        train._holdTimer = 0;
        return;
      }
      if (train.direction === 1 && segIdx < 0) {
        train.segIndex = Math.max(0, nodes.length - 2);
        train.segProgress = 1;
        train.nextStationIdx = Math.max(0, Math.min(totalStations - 2, Number(train.nextStationIdx) || totalStations - 2));
        train.state = 'accelerating';
        train.speed = 0;
        train._holdingShort = false;
        train._holdTimer = 0;
        return;
      }
    }
    // ── 兜底修正：segIndex 越界不应直接移除列车 ──
    // 尝试修正到最近的有效位置（终点站附近），让列车继续折返运行
    if (train.direction === 0 && segIdx >= nodes.length - 1) {
      // 正向越界 → 修正到末站，强制进站停靠后折返
      train.segIndex = Math.max(0, nodes.length - 2);
      train.segProgress = 1;
      train.speed = 0;
      train.nextStationIdx = totalStations - 1;
      if (handleTrainArrival(train, line)) return;
      train._holdTimer = 0;
      train._holdingShort = false;
      beginTerminalTurnback(train, line, nodes, 'segIndex boundary terminal');
      return;
    }
    if (train.direction === 1 && segIdx < 0) {
      // 反向越界 → 修正到首站，强制进站停靠后折返
      train.segIndex = 0;
      train.segProgress = 0;
      train.speed = 0;
      train.nextStationIdx = 0;
      if (handleTrainArrival(train, line)) return;
      train._holdTimer = 0;
      train._holdingShort = false;
      beginTerminalTurnback(train, line, nodes, 'segIndex boundary terminal');
      return;
    }
    // 其他异常越界情况才标记移除
    toRemove.push(train);
    return;
  }

  // Node A and B for current segment（使用预计算的 segDist，避免每帧 haversine）
  const nodeA = nodes[segIdx];
  const nodeB = nodes[segIdx + 1];
  let segDist = nodeA.segDist || 0.001; // km（预计算值）

  recoverStationStopIfNeeded(train, line, nodes, dtSec, tickContext);

  if (train.state === 'dispatch_turning_back') {
    train.speed = 0;
    train._stuckTimer = 0;
    train._turnbackElapsed = (train._turnbackElapsed || 0) + dtSec;
    const planned = Math.max(6, Math.min(30, Number(train._turnbackDuration) || getDwellBase(line) * 0.55));
    train.dwellRemaining = Math.max(0, planned - train._turnbackElapsed);
    try { boardPassengersDuringDwell(train, line); } catch(e) {}
    if (train._turnbackElapsed >= planned || train.dwellRemaining <= 0) {
      completeDispatchTurnback(train, line, nodes, 'dispatch turnback timer reached');
      if (typeof window.cityrailRecordActualDiagramDeparture === 'function') {
        try { window.cityrailRecordActualDiagramDeparture(line, train.direction, train); } catch(e) {}
      }
    }
    return;
  }

  if (train.state === 'turning_back') {
    train.speed = 0;
    train._stuckTimer = 0;
    if (train._retireOnTerminal) {
      retireTrain(train, toRemove);
      return;
    }
    train._turnbackElapsed = (train._turnbackElapsed || 0) + dtSec;
    const rawPlanned = Number(train._turnbackDuration) || (typeof getTerminalTurnbackDwellSec === 'function' ? getTerminalTurnbackDwellSec(line) : getDwellBase(line));
    const planned = train._v309TurnbackBufferSec > 0 ? Math.max(3, rawPlanned) : Math.max(3, Math.min(45, rawPlanned));
    train.dwellRemaining = Math.max(0, planned - train._turnbackElapsed);
    // 终点折返期间仍允许按折返后的方向持续上客，但不能由客流模块延长折返时间。
    try { boardPassengersDuringDwell(train, line); } catch(e) {}
    if (train._turnbackElapsed >= planned || train.dwellRemaining <= 0) {
      completeTerminalTurnback(train, line, nodes, 'turning_back timer reached');
      if (typeof window.cityrailRecordActualDiagramDeparture === 'function') {
        try { window.cityrailRecordActualDiagramDeparture(line, train.direction, train); } catch(e) {}
      }
    }
    return;
  }

  if (train.state === 'dwelling' || train.state === 'turning_back') {
    train._stuckTimer = 0;
    train.dwellRemaining -= dtSec;
    train.speed = 0;

    // ═══ 停站期间持续接客（独立函数，不影响原有停靠/发车逻辑）═══
    // 用 try-catch 包裹：确保接客逻辑的任何异常都不会破坏原有停站行为
    try { boardPassengersDuringDwell(train, line); } catch(e) { /* 接客失败不影响停靠 */ }

    const isTerminal = isTerminalStationIndex(line, train.nextStationIdx);
    if (train.dwellRemaining <= 0) {
      // ═══ 终点站退役机制：被标记的列车在终点站直接消失 ═══
      if (train._retireOnTerminal && isTerminal) {
        retireTrain(train, toRemove);
        return;
      }
      // 普通站发车；如果旧存档/旧模块把终点车放进 dwelling，则转交给 v57 终点折返状态机。
      if (train._dispatchTurnbackNext) {
        beginDispatchTurnback(train, line, nodes, 'dwelling dispatch turnback');
      } else if (isTerminal) {
        beginTerminalTurnback(train, line, nodes, 'legacy dwelling terminal handoff');
      } else {
        const departedStationIdx = train.nextStationIdx;
        advanceNextStation(train, line, totalStations);
	        if (lineIsLoop && train.direction === 0 && train.nextStationIdx === 0) {
          const nodeIdx = getStationNodeIndexForLine(line, departedStationIdx, nodes);
          train.segIndex = Math.max(0, Math.min(nodes.length - 2, nodeIdx >= 0 ? nodeIdx : nodes.length - 2));
          train.segProgress = 0;
        }
        train.state = 'accelerating';
        train.speed = 0;
      }
    }
    return;
  }

  // 机外等待：前车占用车站，后车在站外等候
  if (train.state === 'holding_short') {
    train.speed = 0;
    train._stuckTimer = 0;
    // 累计机外等待时间（持久化跨循环：不在此处重置，只在成功抵达后清零）
    train._holdTimer = (train._holdTimer || 0) + dtSec;
    const MAX_HOLD_TIME = 45; // 45秒游戏时间后进入保护逻辑
    const occupied = isStationOccupied(line, train.direction, train.nextStationIdx, train.id, tickContext);
    if (train._holdTimer >= MAX_HOLD_TIME) {
      // v21：旧逻辑会“超时强制进站”，容易把后车硬塞到仍被占用的第二站，造成折返后堆积。
      // 新逻辑：如果车站仍被占用，就继续机外等待；只有车站清空才恢复进站。
      if (occupied) {
        train._holdTimer = MAX_HOLD_TIME;
        return;
      }
      train._holdingShort = false;
      train.state = 'accelerating';
      train.speed = 0;
      return;
    }
    if (!occupied) {
      // 车站已清空，允许进站（不重置 _holdTimer，防止反复进出死循环）
      const releaseKey = [train.lineId, train.direction, train.nextStationIdx].join('__');
      const releaseSet = tickContext && tickContext.holdingReleaseKeys;
      if(releaseSet && releaseSet.has(releaseKey)) return;
      if(releaseSet) releaseSet.add(releaseKey);
      train.state = 'accelerating';
      train.speed = 0;
    }
    return;
  }

  // Calculate braking distance needed at current speed
  const brakeDist = train.speed > 0 ? (train.speed * train.speed) / (2 * decel * 3600) : 0; // km

  // Distance remaining in this segment (direction-aware)
  const segRemaining = (train.direction === 0)
    ? segDist * (1 - train.segProgress)   // forward: to node B
    : segDist * train.segProgress;         // backward: to node A

  // Total remaining to next station
  const totalToStation = segRemaining + getRemainingSegmentsToStation(train, line, nodes, segIdx);

  // 防撞检查：前方车站是否被其他列车占用
  const stationOccupied = isStationOccupied(line, train.direction, train.nextStationIdx, train.id, tickContext);
  const profileTargetSpeed = cityrailCurveProfileTargetSpeedKmh(train, nodes, maxSpeed, decelMs2);

  // Check if we need to start braking
  if (train.state !== 'decelerating' && train.speed > 0) {
    if (stationOccupied) {
      // 前车占用车站 — 制动目标改为站前安全距离（机外等待）
      const holdingTarget = totalToStation - SAFE_HOLDING_DISTANCE;
      if (holdingTarget <= brakeDist) {
        train.state = 'decelerating';
        train._holdingShort = true;
      }
    } else {
      if (totalToStation <= brakeDist) {
        train.state = 'decelerating';
        train._holdingShort = false;
      }
    }
  }

  // 若正在减速中车站突然清空，切回正常进站模式
  if (train.state === 'decelerating' && train._holdingShort && !stationOccupied) {
    train._holdingShort = false;
    if (totalToStation > brakeDist + 0.01) {
      train.state = 'accelerating';
    }
  }

  if (train.state === 'decelerating') {
    // Decelerate
    train.speed = Math.max(0, train.speed - decel * dtSec);
    if (train.speed <= 0) {
      train.speed = 0;
      if (train._holdingShort) {
        // 机外等待 — 停在站前安全距离
        train.state = 'holding_short';
      } else {
        // Arrived at station — handle passenger exchange
        if (handleTrainArrival(train, line)) return;
        train._holdTimer = 0; // 成功抵达，清除机外等待累计
        // Set dwell time
        // Station is at node B for forward, node A for backward
        train.segProgress = (train.direction === 0) ? 1 : 0;
        normalizeLoopClosureArrival(train, line, nodes);
        if (train._dispatchTurnbackNext) {
          beginDispatchTurnback(train, line, nodes, 'arrival dispatch turnback');
        } else if (isTerminalStationIndex(line, train.nextStationIdx)) {
          beginTerminalTurnback(train, line, nodes, 'arrival decelerating');
        } else {
          train.state = 'dwelling';
          train.dwellRemaining = cityrailFixedDwellSeconds(line);
        }
      }
      return;
    }
  } else {
    const targetSpeed = Math.max(1, Math.min(maxSpeed, profileTargetSpeed));
    const curveBrake = Math.min(decel, 0.72 * 3.6);
    const serviceAccel = Math.min(accel, 0.9 * 3.6);
    if (train.speed > targetSpeed + 0.2) {
      train.speed = Math.max(targetSpeed, train.speed - curveBrake * dtSec);
      train.state = 'cruising';
    } else if (train.state === 'accelerating' || train.speed < targetSpeed - 0.2) {
      train.speed = Math.min(targetSpeed, train.speed + serviceAccel * dtSec);
      train.state = train.speed >= targetSpeed - 0.2 ? 'cruising' : 'accelerating';
    } else if (train.state === 'cruising') {
      train.speed = targetSpeed;
    }
  }

  // Move train — direction-aware
  const speedKmPerSec = train.speed / 3600;
  const distMoved = speedKmPerSec * dtSec; // km
  const segDistCovered = distMoved / segDist;

  if (train.direction === 0) {
    // Forward: segProgress increases
    train.segProgress += segDistCovered;

    // Check if we crossed a segment boundary forward
    while (train.segProgress >= 1 && train.segIndex < nodes.length - 2) {
      const excess = train.segProgress - 1;
      train.segIndex++;
      train.segProgress = 0;

      // ═══ 穿过节点时检查：是否到达目标车站？═══
      // 每次跨过一个段就到了新的 node（即上一段的 nodeB）
      // 如果该节点是目标车站 → 立即截停停靠
      const arrivedNode = nodes[train.segIndex];
      if (arrivedNode && arrivedNode.type === 'station' &&
          arrivedNode.id === line.stationIds[train.nextStationIdx]) {
        // 到达目标站：强制截停
        train.speed = 0;
        train.segProgress = (train.direction === 0) ? 1 : 0;
        // 回退到目标站所在节点（当前 segIndex 的 node A 就是该站）
        if (handleTrainArrival(train, line)) return;
        normalizeLoopClosureArrival(train, line, nodes);
        train._holdTimer = 0;
        train._holdingShort = false;
        if (train._dispatchTurnbackNext) {
          beginDispatchTurnback(train, line, nodes, 'forward node dispatch turnback');
        } else {
          train.state = 'dwelling';
          train.dwellRemaining = cityrailFixedDwellSeconds(line);
        }
        return; // 本帧结束
      }

      const newSeg = nodes[train.segIndex];
      const newSegDist = newSeg.segDist || 0.001; // 预计算值
      train.segProgress = excess * segDist / newSegDist;
      if (train.segProgress >= 1) train.segProgress = 0.999;
      segDist = newSegDist;
    }

    // Forward end-of-line or reached terminal station: trigger dwell and direction flip
    const isApproachingTerminalFwd = (train.nextStationIdx >= totalStations - 1);
	    if (lineIsLoop && train.direction === 0 && train.nextStationIdx === 0 && train.segIndex >= nodes.length - 2 && train.segProgress >= 1) {
      train.segIndex = 0;
      train.segProgress = 0;
      train.speed = 0;
      if (handleTrainArrival(train, line)) return;
      train._holdTimer = 0;
      train._holdingShort = false;
      train.state = 'dwelling';
      train.dwellRemaining = cityrailFixedDwellSeconds(line);
      return;
    }
	    if (!lineIsLoop && (train.segIndex >= nodes.length - 1 ||
        (isApproachingTerminalFwd && train.segIndex === nodes.length - 2))) {
      train.segIndex = nodes.length - 2;
      train.segProgress = 1;
      train.speed = 0;
      // 一致性保护：确保 nextStationIdx 指向末站
      const lastStnIdx = totalStations - 1;
      if (train.nextStationIdx !== lastStnIdx) {
        train.nextStationIdx = lastStnIdx;
      }
      if (handleTrainArrival(train, line)) return;
      beginTerminalTurnback(train, line, nodes, 'end-of-line terminal');
      return;
    }
    if (train.segProgress >= 1) train.segProgress = 0.999;
  } else {
    // Backward: segProgress decreases toward node A
    train.segProgress -= segDistCovered;

    // Check if we crossed a segment boundary backward
    while (train.segProgress < 0 && train.segIndex > 0) {
      const excess = -train.segProgress;
      train.segIndex--;
      train.segProgress = 1;

      // ═══ 穿过节点时检查：是否到达目标车站？═══
      // 反向移动时，segIndex-- 后当前段的 node A 就是穿过的节点
      const arrivedNode = nodes[train.segIndex];
      if (arrivedNode && arrivedNode.type === 'station' &&
          arrivedNode.id === line.stationIds[train.nextStationIdx]) {
        // 到达目标站：强制截停
        train.speed = 0;
        train.segProgress = (train.direction === 0) ? 1 : 0;
        if (handleTrainArrival(train, line)) return;
        normalizeLoopClosureArrival(train, line, nodes);
        train._holdTimer = 0;
        train._holdingShort = false;
        if (train._dispatchTurnbackNext) {
          beginDispatchTurnback(train, line, nodes, 'backward node dispatch turnback');
        } else {
          train.state = 'dwelling';
          train.dwellRemaining = cityrailFixedDwellSeconds(line);
        }
        return; // 本帧结束
      }

      const newSeg = nodes[train.segIndex];
      const newSegDist = newSeg.segDist || 0.001; // 预计算值
      train.segProgress = 1 - excess * segDist / newSegDist;
      if (train.segProgress <= 0) train.segProgress = 0.001;
      segDist = newSegDist;
    }

    // Backward end-of-line or reached terminal station: trigger dwell and direction flip
    const isApproachingTerminalBwd = (train.nextStationIdx <= 0);
	    if (lineIsLoop && train.direction === 1 && train.nextStationIdx >= totalStations - 1 && train.segIndex <= 0 && train.segProgress <= 0) {
      train.segIndex = Math.max(0, nodes.length - 2);
      train.segProgress = 1;
      train.speed = 0;
      if (handleTrainArrival(train, line)) return;
      train._holdTimer = 0;
      train._holdingShort = false;
      train.state = 'dwelling';
      train.dwellRemaining = cityrailFixedDwellSeconds(line);
      return;
    }
	    if (!lineIsLoop && (train.segIndex < 0 ||
        (isApproachingTerminalBwd && train.segIndex === 0))) {
      train.segIndex = 0;
      train.segProgress = 0;
      train.speed = 0;
      // 一致性保护：确保 nextStationIdx 指向首站
      if (train.nextStationIdx !== 0) {
        train.nextStationIdx = 0;
      }
      if (handleTrainArrival(train, line)) return;
      beginTerminalTurnback(train, line, nodes, 'end-of-line terminal');
      return;
    }
    if (train.segProgress < 0) train.segProgress = 0.001;
  }

  // Get the two nodes defining current segment
  const curA = nodes[train.segIndex];
  const curB = nodes[train.segIndex + 1];
  train.lat = curA.lat + (curB.lat - curA.lat) * train.segProgress;
  train.lng = curA.lng + (curB.lng - curA.lng) * train.segProgress;

  // ═══ 安全网：检测列车是否已越过目标车站节点但未进入 dwelling 状态 ═══
  // 当 dtSec 较大或浮点精度问题时，减速逻辑可能未将 speed 减至 0，
  // 导致列车直接穿过车站。此处用位置做兜底：若 segProgress 已越过车站所在节点，
  // 强制截停并进入 dwelling 状态。
  const nextStnNodeIdx = findNextStationNodeIndex(train, line, nodes, train.segIndex);
  if (nextStnNodeIdx >= 0 && train.state !== 'dwelling' && train.state !== 'holding_short') {
    const passedStation =
      (train.direction === 0 && (train.segIndex > nextStnNodeIdx || (train.segIndex === nextStnNodeIdx && train.segProgress >= 1))) ||
      (train.direction === 1 && (train.segIndex < nextStnNodeIdx || (train.segIndex === nextStnNodeIdx && train.segProgress <= 0)));
    if (passedStation) {
      train.speed = 0;
      train.segIndex = nextStnNodeIdx;
      train.segProgress = (train.direction === 0) ? 1 : 0;
      if (handleTrainArrival(train, line)) return;
      normalizeLoopClosureArrival(train, line, nodes);
      train._holdTimer = 0;
      train._holdingShort = false;
      if (train._dispatchTurnbackNext) {
        beginDispatchTurnback(train, line, nodes, 'passed-station dispatch turnback');
      } else if (isTerminalStationIndex(line, train.nextStationIdx)) {
        beginTerminalTurnback(train, line, nodes, 'passed-station terminal safety');
      } else {
        train.state = 'dwelling';
        train.dwellRemaining = cityrailFixedDwellSeconds(line);
      }
      return;
    }
  }
}

function getRemainingSegmentsToStation(train, line, nodes, segIdx) {
	  // 使用预计算的 segDist，不再每帧调用 haversine
	  const nextStationNodeIdx = findNextStationNodeIndex(train, line, nodes, segIdx);
	  if (nextStationNodeIdx < 0) return 999;
  const cumulative = nodes && nodes._cumulativeSegDist;
  if (cumulative && cumulative.length >= nodes.length) {
    if (train.direction === 0) {
      const from = Math.max(0, Math.min(cumulative.length - 1, segIdx + 1));
      const to = Math.max(0, Math.min(cumulative.length - 1, nextStationNodeIdx));
      return Math.max(0, cumulative[to] - cumulative[from]);
    }
    const from = Math.max(0, Math.min(cumulative.length - 1, nextStationNodeIdx));
    const to = Math.max(0, Math.min(cumulative.length - 1, segIdx));
    return Math.max(0, cumulative[to] - cumulative[from]);
  }

	  let total = 0;
  if (train.direction === 0) {
    for (let i = segIdx + 1; i < nextStationNodeIdx; i++) {
      total += nodes[i].segDist || 0;
    }
  } else {
    for (let i = nextStationNodeIdx; i < segIdx; i++) {
      total += nodes[i].segDist || 0;
    }
  }
  return total;
}

function findNextStationNodeIndex(train, line, nodes, segIdx) {
  const targetId = line.stationIds[train.nextStationIdx];
  const indexed = nodes && nodes._stationNodeIndexes && nodes._stationNodeIndexes[String(targetId)];
  if (indexed && indexed.length) {
    if (train.direction === 0) {
      for (let i = 0; i < indexed.length; i++) {
        if (indexed[i] > segIdx) return indexed[i];
      }
    } else {
      for (let i = indexed.length - 1; i >= 0; i--) {
        if (indexed[i] <= segIdx) return indexed[i];
      }
    }
  }
  if (train.direction === 0) {
    // Forward: search higher indices
    for (let i = segIdx + 1; i < nodes.length; i++) {
      if (nodes[i].type === 'station' && nodes[i].id === targetId) {
        return i;
      }
    }
  } else {
    // Backward: search lower indices
    for (let i = segIdx; i >= 0; i--) {
      if (nodes[i].type === 'station' && nodes[i].id === targetId) {
        return i;
      }
    }
  }
  return -1;
}

function advanceNextStation(train, line, totalStations) {
  if (isLoopLine(line)) {
    if (train.direction === 0) {
      train.nextStationIdx++;
      if (train.nextStationIdx >= totalStations) train.nextStationIdx = 0;
    } else {
      train.nextStationIdx--;
      if (train.nextStationIdx < 0) train.nextStationIdx = totalStations - 1;
    }
    train._holdingShort = false;
    train._holdTimer = 0;
    return;
  }
  if (train.direction === 0) {
    train.nextStationIdx++;
    // 只有越过最后一个站才折返（nextStationIdx 从 totalStations-1 变成 totalStations）
    if (train.nextStationIdx >= totalStations) {
      train.direction = 1;
      train.nextStationIdx = totalStations - 2;
      // 折返时清理机外等待残留状态
      train._holdingShort = false;
      train._holdTimer = 0;
    }
  } else {
    train.nextStationIdx--;
    // 只有越过第一个站才折返（nextStationIdx 从 0 变成 -1）
    if (train.nextStationIdx < 0) {
      train.direction = 0;
      train.nextStationIdx = 1;
      // 折返时清理机外等待残留状态
      train._holdingShort = false;
      train._holdTimer = 0;
    }
  }
}

function cityrailNum(v, d = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

function cityrailSimElapsedSec(startSec) {
  const nowSec = cityrailNum(state && state.simulationHour, 0) * 3600;
  return ((nowSec - cityrailNum(startSec, nowSec)) % 86400 + 86400) % 86400;
}

function cityrailNormalizeDepotConnectorPath(path) {
  return (Array.isArray(path) ? path : []).map(point => {
    const lat = Array.isArray(point) ? cityrailNum(point[0], NaN) : cityrailNum(point && point.lat, NaN);
    const lng = Array.isArray(point) ? cityrailNum(point[1], NaN) : cityrailNum(point && point.lng, NaN);
    return Number.isFinite(lat) && Number.isFinite(lng) ? { lat, lng } : null;
  }).filter(Boolean);
}

function cityrailDepotConnectorPathLengthM(points) {
  const path = cityrailNormalizeDepotConnectorPath(points);
  if (path.length < 2) return 0;
  let total = 0;
  for (let i = 1; i < path.length; i++) {
    try {
      total += haversine(path[i - 1].lat, path[i - 1].lng, path[i].lat, path[i].lng) * 1000;
    } catch(e) {
      const a = path[i - 1], b = path[i];
      const x = (b.lng - a.lng) * 111320 * Math.cos(((a.lat + b.lat) / 2) * Math.PI / 180);
      const y = (b.lat - a.lat) * 110540;
      total += Math.sqrt(x * x + y * y);
    }
  }
  return Math.max(0, total);
}

function cityrailDepotConnectorVisualDurationSec(train) {
  const len = Math.max(0, cityrailNum(train && train._depotConnectorLengthM, cityrailDepotConnectorPathLengthM(train && train._depotConnectorPath)));
  const stored = cityrailNum(train && train._depotConnectorVisualDurationSec, NaN);
  if (Number.isFinite(stored) && stored > 0) return Math.max(6, stored);
  return Math.max(18, Math.min(180, len / (35 * 1000 / 3600)));
}

function cityrailNormalizeOutboundDepotConnectorVisual(train) {
  if (!train || train._depotConnectorVisualPhase !== 'pulling_out') return;
  const path = cityrailNormalizeDepotConnectorPath(train._depotConnectorPath);
  const start = cityrailNum(train._depotConnectorVisualStartSec, train._depotOutSec);
  if (path.length < 2 || cityrailSimElapsedSec(start) >= cityrailDepotConnectorVisualDurationSec(train)) {
    train._depotConnectorVisualPhase = '';
  }
}

function cityrailPointAlongPath(points, progress) {
  const path = cityrailNormalizeDepotConnectorPath(points);
  if (path.length < 2) return null;
  const p = Math.max(0, Math.min(1, cityrailNum(progress, 0)));
  const lengths = [];
  let total = 0;
  for (let i = 1; i < path.length; i++) {
    const d = cityrailDepotConnectorPathLengthM([path[i - 1], path[i]]);
    lengths.push(d);
    total += d;
  }
  if (total <= 0) {
    const a = path[0], b = path[path.length - 1];
    return {
      lat:a.lat + (b.lat - a.lat) * p,
      lng:a.lng + (b.lng - a.lng) * p,
      nodeA:a,
      nodeB:b
    };
  }
  let target = total * p;
  for (let i = 1; i < path.length; i++) {
    const seg = lengths[i - 1] || 0;
    if (target <= seg || i === path.length - 1) {
      const a = path[i - 1], b = path[i];
      const t = seg > 0 ? Math.max(0, Math.min(1, target / seg)) : 0;
      return {
        lat:a.lat + (b.lat - a.lat) * t,
        lng:a.lng + (b.lng - a.lng) * t,
        nodeA:a,
        nodeB:b
      };
    }
    target -= seg;
  }
  const last = path[path.length - 1], prev = path[path.length - 2];
  return { lat:last.lat, lng:last.lng, nodeA:prev, nodeB:last };
}

function cityrailDepotConnectorTrainVisual(train) {
  if (!train || !train._depotConnectorVisualPhase) return null;
  const path = cityrailNormalizeDepotConnectorPath(train._depotConnectorPath);
  if (path.length < 2) return null;
  const phase = train._depotConnectorVisualPhase;
  if (phase !== 'pulling_out' && phase !== 'pulling_in') return null;
  const start = cityrailNum(train._depotConnectorVisualStartSec, phase === 'pulling_in' ? train._depotInSec : train._depotOutSec);
  const duration = cityrailDepotConnectorVisualDurationSec(train);
  const elapsed = cityrailSimElapsedSec(start);
  if (phase === 'pulling_out' && elapsed >= duration) return null;
  const progress = duration > 0 ? Math.max(0, Math.min(1, elapsed / duration)) : 1;
  const visualProgress = phase === 'pulling_in' ? 1 - progress : progress;
  const pos = cityrailPointAlongPath(path, visualProgress);
  if (!pos) return null;
  const heading = pos.nodeA && pos.nodeB
    ? (phase === 'pulling_in'
      ? bearing(pos.nodeB.lat, pos.nodeB.lng, pos.nodeA.lat, pos.nodeA.lng)
      : bearing(pos.nodeA.lat, pos.nodeA.lng, pos.nodeB.lat, pos.nodeB.lng))
    : null;
  return Object.assign(pos, { phase, progress, duration, elapsed, heading });
}

function cityrailBeginDepotEntryDwell(train, line, nodes, reason) {
  if (!train || !line || !Array.isArray(line.stationIds) || !Array.isArray(nodes) || nodes.length < 2) return false;
  let entryIdx = Math.round(cityrailNum(train._depotEntryDwellStationIdx, -1));
  if (entryIdx < 0 || entryIdx >= line.stationIds.length) entryIdx = depotEntryIndexForTrain(line, train);
  if (entryIdx < 0 || entryIdx >= line.stationIds.length) return false;
  const stationId = line.stationIds[entryIdx];
  const nodeIdx = nodes.findIndex(node => node && node.type === 'station' && String(node.id) === String(stationId));
  if (nodeIdx < 0) return false;
  const dir = Number(train._depotEntryDwellDirection != null ? train._depotEntryDwellDirection : train.direction) === 1 ? 1 : 0;
  train.direction = dir;
  train.nextStationIdx = entryIdx;
  train.speed = 0;
  train.state = 'dwelling';
  train.dwellRemaining = typeof cityrailFixedDwellSeconds === 'function'
    ? cityrailFixedDwellSeconds(line)
    : Math.max(1, (typeof getDwellBase === 'function' ? getDwellBase(line) : 25));
  train.depTime = 0;
  train._holdingShort = false;
  train._holdTimer = 0;
  train._stuckTimer = 0;
  if (dir === 0) {
    train.segIndex = Math.max(0, Math.min(nodes.length - 2, nodeIdx));
    train.segProgress = entryIdx >= line.stationIds.length - 1 ? 1 : 0;
  } else {
    train.segIndex = Math.max(0, Math.min(nodes.length - 2, nodeIdx - 1));
    train.segProgress = entryIdx <= 0 ? 0 : 1;
  }
  train._depotState = 'in_service';
  train._depotLifecycle = 'entry_station_dwelling';
  train._depotEntryDwellStartedAtSec = cityrailNum(state && state.simulationHour, 0) * 3600;
  train._depotEntryDwellStartedReason = reason || 'connector-complete';
  train._depotConnectorVisualPhase = '';
  delete train._depotEntryDwellPending;
  try { boardPassengersDuringDwell(train, line); } catch(e) {}
  return true;
}

function depotEntryIndexForTrain(line, train) {
  if (!line || !Array.isArray(line.stationIds)) return -1;
  const svc = window.CityRailDepotService || window.DepotService;
  try {
    if (svc && typeof svc.entryStationIndex === 'function') {
      const idx = Math.round(cityrailNum(svc.entryStationIndex(line), -1));
      if (idx >= 0 && idx < line.stationIds.length) return idx;
    }
  } catch(e) {}
  const candidates = [
    train && train._depotEntryStationId,
    train && train.depotEntryStationId,
    line && line._lastDepotDispatchEntryStationId,
    line && line.depotEntryStationId
  ].filter(v => v != null);
  for (const id of candidates) {
    const idx = line.stationIds.findIndex(stId => String(stId) === String(id));
    if (idx >= 0) return idx;
  }
  const idx = Math.round(cityrailNum(train && train._depotEntryStationIdx, -1));
  return idx >= 0 && idx < line.stationIds.length ? idx : -1;
}

function returnTrainPassengersToStationPool(train, line, stationId) {
  if (!train || train._passengersAlreadyReturned) return 0;
  if (!state.stationWaitingPool[stationId]) {
    state.stationWaitingPool[stationId] = { waiting: 0, totalArrived: 0, totalBoarded: 0, totalDelivered: 0 };
  }
  const pool = state.stationWaitingPool[stationId];
  let returned = 0;
  if (Array.isArray(train._passengerIds)) {
    for (let k = 0; k < train._passengerIds.length; k++) {
      const p = state._batchMap ? state._batchMap[train._passengerIds[k]] : null;
      if (!p || p.state !== 'on_train') continue;
      p.state = 'waiting';
      p.trainId = null;
      const count = p.count || PASSENGER_BATCH_SCALE;
      returned += count;
      pool.waiting += count;
      try { addWaitingIndexV9(p); } catch(e) {}
    }
  }
  train._passengerIds = [];
  train.load = 0;
  train.passengers = 0;
  train.onboard = 0;
  train.overloaded = false;
  train._passengersAlreadyReturned = true;
  return returned;
}

function removeTrainMarker(train) {
  try {
    if (train && trainMarkers[train.id]) {
      map.removeLayer(trainMarkers[train.id]);
      delete trainMarkers[train.id];
    }
  } catch(e) {}
}

function isManualTrainLifecycleCore(train) {
  const text = [
    train && train._depotReturnReason,
    train && train._strictRetireReason,
    train && train._retireReason,
    train && train._dispatchCommand,
    train && train._atsCommandReason,
    train && train._manualReason
  ].map(v => String(v || '')).join(' ');
  return /ats|manual|user|command|调度|手动|扣车|跳停|清客|回库命令/i.test(text);
}

function depotReturnElapsedSec(train) {
  const nowSec = (Number(state && state.simulationHour) || 0) * 3600;
  const requested = Number(train && train._depotReturnRequestedAtSec);
  if (!Number.isFinite(requested)) return Infinity;
  return ((nowSec - requested) % 86400 + 86400) % 86400;
}

function depotReturnMaxSec(line) {
  let roundTrip = 3600;
  try { roundTrip = Math.max(600, Number(getRoundTripSeconds(line)) || 3600); } catch(e) {}
  return Math.max(1800, Math.min(14400, roundTrip * 1.1 + 600));
}

function shouldForceCompleteAutomaticDepotReturn(train, line) {
  if (!train || isManualTrainLifecycleCore(train)) return false;
  if (!(train._returnToDepotRequested || train._outOfServiceToDepot || train._depotState === 'pulling_in')) return false;
  const age = depotReturnElapsedSec(train);
  if (age <= depotReturnMaxSec(line)) return false;
  const text = [
    train._depotReturnReason,
    train._strictRetireReason,
    train._retireReason,
    train._strictSpawnReason,
    train._spawnReason,
    train._depotDispatchReason
  ].map(v => String(v || '')).join(' ');
  return /midnight|v300_surplus|v300_out_of_service|fleet_excess|line_fleet_cap|legacy|restore|schedule_restore|direction_bucket|strict_bucket/i.test(text) || age > 7200;
}

function resolveDepotReturnLifecycle(train, line, toRemove, reason) {
  if (train && train._depotConnectorVisualPhase === 'pulling_in') {
    if (cityrailSimElapsedSec(train._depotConnectorVisualStartSec || train._depotInSec) < cityrailDepotConnectorVisualDurationSec(train)) return true;
    train._depotConnectorVisualPhase = '';
    train._depotState = 'returned';
    train.state = 'done';
    if (Array.isArray(toRemove) && !toRemove.includes(train)) toRemove.push(train);
    return true;
  }
  if (!train || !line || !(train._returnToDepotRequested || train._outOfServiceToDepot || train._depotState === 'pulling_in')) return false;
  const entryIdx = depotEntryIndexForTrain(line, train);
  const currentIdx = Math.max(0, Math.min(line.stationIds.length - 1, Math.round(cityrailNum(train.nextStationIdx, entryIdx))));
  if (entryIdx >= 0 && currentIdx === entryIdx) {
    return completeTrainDepotReturn(train, line, train._depotReturnReason || reason || 'arrived_depot_entry', toRemove || null);
  }
  if (shouldForceCompleteAutomaticDepotReturn(train, line)) {
    train._depotReturnExpiredAt = Date.now();
    train._depotReturnExpiredAgeSec = Math.round(depotReturnElapsedSec(train));
    return completeTrainDepotReturn(train, line, train._depotReturnReason || reason || 'expired_auto_depot_return', toRemove || null);
  }
  return false;
}

function completeTrainDepotReturn(train, line, reason, toRemove) {
  if (!train) return false;
  const entryIdx = depotEntryIndexForTrain(line, train);
  const stationId = line && Array.isArray(line.stationIds)
    ? line.stationIds[Math.max(0, Math.min(line.stationIds.length - 1, entryIdx >= 0 ? entryIdx : Math.round(cityrailNum(train.nextStationIdx, 0))))]
    : null;
  if (stationId != null) returnTrainPassengersToStationPool(train, line, stationId);
  try {
    const svc = window.CityRailDepotService || window.DepotService || DepotService;
    if (svc && typeof svc.returnTrain === 'function') svc.returnTrain(train, reason || train._strictRetireReason || train._retireReason || 'return_to_depot');
  } catch(e) {}
  train._passengersAlreadyReturned = true;
  train._returnToDepotRequested = false;
  train._outOfServiceToDepot = false;
  if (cityrailNormalizeDepotConnectorPath(train._depotConnectorPath).length >= 2) {
    train._depotLifecycle = 'returning_on_depot_connector';
    train._depotConnectorVisualPhase = 'pulling_in';
    train._depotConnectorVisualStartSec = cityrailNum(train._depotInSec, cityrailNum(state && state.simulationHour, 0) * 3600);
    train._depotConnectorVisualDurationSec = cityrailDepotConnectorVisualDurationSec(train);
    train.state = 'depot_pulling_in';
    train.speed = 0;
    return true;
  }
  train._depotLifecycle = 'returned_to_depot';
  train.state = 'done';
  removeTrainMarker(train);
  if (Array.isArray(toRemove)) {
    if (!toRemove.includes(train)) toRemove.push(train);
  } else if (state && Array.isArray(state.trains)) {
    state.trains = state.trains.filter(t => t !== train && String(t && t.id) !== String(train.id));
  }
  return true;
}

function requestTrainDepotReturn(train, line, reason, toRemove) {
  if (!train || !line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
  const entryIdx = depotEntryIndexForTrain(line, train);
  if (entryIdx < 0) return completeTrainDepotReturn(train, line, reason || 'return_without_entry', toRemove);
  const currentIdx = Math.max(0, Math.min(line.stationIds.length - 1, Math.round(cityrailNum(train.nextStationIdx, entryIdx))));
  returnTrainPassengersToStationPool(train, line, line.stationIds[currentIdx]);
  train._retireOnTerminal = false;
  train._returnToDepotRequested = true;
  train._outOfServiceToDepot = true;
  train._depotReturnEntryStationIdx = entryIdx;
  train._depotReturnEntryStationId = line.stationIds[entryIdx];
  train._depotReturnReason = reason || train._strictRetireReason || train._retireReason || 'return_to_depot';
  train._depotReturnRequestedAtSec = cityrailNum(state && state.simulationHour, 0) * 3600;
  train._depotLifecycle = 'returning_to_depot_entry';
  if (currentIdx === entryIdx || train.state === 'waiting' || train.state === 'done') {
    return completeTrainDepotReturn(train, line, train._depotReturnReason, toRemove);
  }
  return true;
}

window.cityrailRequestTrainDepotReturn = requestTrainDepotReturn;
window.cityrailCompleteTrainDepotReturn = completeTrainDepotReturn;
window.cityrailResolveDepotReturnLifecycle = resolveDepotReturnLifecycle;

// ═══ 列车退役：不在线路上凭空消失，先回到车辆段接轨站再入段 ═══
function retireTrain(train, toRemove) {
  const line = train ? cityrailLineByIdFast(train.lineId) : null;
  if (requestTrainDepotReturn(train, line, train && (train._strictRetireReason || train._retireReason) || 'retire', toRemove)) return;
  if (train) train._retireOnTerminal = false;
}

// ═══ 平滑调整列车数量：增量方式，不中断运营中的列车 ═══
// 对比当前活跃列车数与目标数，多退少补
function adjustTrainCountForLine(line) {
  const authority = window.CityRailDispatchAuthorityV300;
  if (authority && typeof authority.adjustLine === 'function') return authority.adjustLine(line);
  if (!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return;
  const active = (state.trains || []).filter(t =>
    t &&
    t.lineId === line.id &&
    t.state !== 'done' &&
    !t._retireOnTerminal &&
    !t._returnToDepotRequested &&
    !t._outOfServiceToDepot
  ).length;
  const target = Math.max(0, cityrailTargetFleetFromHeadway(getRoundTripSeconds(line), getCurrentHeadway(line)));
  line._strictTargetFleet = target;
  line._strictFleetShortage = Math.max(0, target - active);
  line._strictFleetShortageReason = line._strictFleetShortage ? 'dispatch_authority_unavailable' : '';
  line._strictFleetShortageUpdatedAt = Date.now();
}

function handleTrainArrival(train, line) {
  const stationId = line.stationIds[train.nextStationIdx];
  const station = cityrailStationByIdFast(stationId);
  if (!station) return false;

  const capacity = train.maxLoad;
  const arrivingIdx = train.nextStationIdx;

  // 确保该站有候车池
  if (!state.stationWaitingPool[stationId]) {
    state.stationWaitingPool[stationId] = { waiting: 0, totalArrived: 0, totalBoarded: 0, totalDelivered: 0 };
  }
  const pool = state.stationWaitingPool[stationId];

  // 初始化列车的乘客ID列表
  if (!train._passengerIds) train._passengerIds = [];

  if (train._returnToDepotRequested || train._outOfServiceToDepot) {
    const entryIdx = depotEntryIndexForTrain(line, train);
    returnTrainPassengersToStationPool(train, line, stationId);
    if (entryIdx >= 0 && arrivingIdx === entryIdx) {
      return completeTrainDepotReturn(train, line, train._depotReturnReason || 'arrived_depot_entry', null);
    }
    train.overloaded = false;
    return false;
  }

  // ════════════════════════════════════════
  // ① 下车 — 乘客级：按预计算路径判断是否在此站下车
  //    并在下车前记录本段断面的实际通过人数
  // ════════════════════════════════════════
  // 记录断面：列车刚经过的区间
  let prevSegIdx = train.direction === 0 ? arrivingIdx - 1 : arrivingIdx;
  if (isLoopLine(line) && train.direction === 0 && arrivingIdx === 0) prevSegIdx = line.stationIds.length - 1;
  const flowSegmentCount = (line.stationIds.length - 1) + (isLoopLine(line) ? 1 : 0);
  if (prevSegIdx >= 0 && prevSegIdx < flowSegmentCount) {
    const segKey = line.id + '_' + prevSegIdx;
    const loadBeforeAlight = train.load || 0;
    if (!state._segmentActualFlow[segKey]) state._segmentActualFlow[segKey] = 0;
    state._segmentActualFlow[segKey] += loadBeforeAlight;
  }

  let totalAlightedScale = 0;
  const stillOnBoard = [];

  for (let k = 0; k < train._passengerIds.length; k++) {
    const pid = train._passengerIds[k];
    const p = state._batchMap ? state._batchMap[pid] : null;
    if (!p || p.state !== 'on_train' || p.trainId !== train.id) { /* stale entry */ continue; }

    const leg = p.legs[p.currentLeg];
    if (!leg) { stillOnBoard.push(pid); continue; }

    // 该乘客当前段的下车站 == 本次到达站 → 下车！
    if (leg.alightIdx === arrivingIdx) {
      totalAlightedScale += (p.count || PASSENGER_BATCH_SCALE);
      p.trainId = null;

      if (p.currentLeg >= p.legs.length - 1) {
        // ★ 最后一段 → 抵达最终目的地 → 出站！计入送达客流
        p.state = 'arrived';
        state._totalDelivered += (p.count || PASSENGER_BATCH_SCALE);
        pool.totalDelivered += (p.count || PASSENGER_BATCH_SCALE);
      } else {
        // 换乘/继续下一段旅程 → 在此站转为候车状态
        p.currentLeg++;
        p.state = 'waiting';
        addWaitingIndexV9(p);
        pool.waiting += (p.count || PASSENGER_BATCH_SCALE);
      }
    } else {
      // 还没到下车站，继续乘车
      stillOnBoard.push(pid);
    }
  }
  train._passengerIds = stillOnBoard;
  train.load = Math.max(0, train.load - totalAlightedScale);

  // ════════════════════════════════════════
  // ② 上车 — 乘客级：路径方向+线路必须匹配才上
  // ════════════════════════════════════════
  const availableSpace = capacity - train.load;
  if (availableSpace > 0) {
    boardFromWaitingIndexV41(train, line, arrivingIdx, pool, availableSpace);
  }

  // Set overload flag
  train.overloaded = train.load >= capacity * 0.95;
}

// ═══ 停站期间持续接客：每帧调用，只要未满员就带走本方向候车乘客 ═══
// 独立于 handleTrainArrival，在 dwelling 状态的每一帧执行
function boardPassengersDuringDwell(train, line) {
  if (train && (train._returnToDepotRequested || train._outOfServiceToDepot || train.state === 'done')) return 0;
  const arrivingIdx = train.nextStationIdx;
  // 防御性检查：nextStationIdx 必须合法
  if (arrivingIdx < 0 || arrivingIdx >= line.stationIds.length) return;
  const curStnId = line.stationIds[arrivingIdx];
  if (!curStnId) return;

  if (!state.stationWaitingPool[curStnId]) {
    state.stationWaitingPool[curStnId] = { waiting: 0, totalArrived: 0, totalBoarded: 0, totalDelivered: 0 };
  }
  const pool = state.stationWaitingPool[curStnId];
  const capacity = train.maxLoad;
  const availableSpace = capacity - train.load;

  if (availableSpace <= 0) return;

  boardFromWaitingIndexV41(train, line, arrivingIdx, pool, availableSpace);
  train.overloaded = train.load >= capacity * 0.95;
}

// 生成列车点击弹窗的 HTML
function buildTrainPopupHTML(train, line) {
  const speed = train.speed ? train.speed.toFixed(1) : '0.0';
  const load = train.load ?? 0;
  const maxLoad = train.maxLoad ?? 0;
  const loadPct = maxLoad > 0 ? Math.round((load / maxLoad) * 100) : 0;
  const overloaded = loadPct >= 95 ? ' · 超载' : '';
  const holdingNote = train.state === 'holding_short' ? '<div class="ti-row" style="color:#FF9F0A;">机外等待（前车占用车站）</div>' : '';
  return `<div style="font-weight:600;margin-bottom:4px;">${line.name || line.id}</div>
<div class="ti-row"><span class="ti-label">时速</span><span class="ti-value">${speed} km/h</span></div>
<div class="ti-row"><span class="ti-label">载客</span><span class="ti-value">${load} / ${maxLoad} (${loadPct}%)${overloaded}</span></div>${holdingNote}`;
}


// v56: compute train nose direction ONLY from service direction / path geometry.
// Do not use last-frame movement vector: map drag, station snapping, dense-node switching and float error
// make that vector jitter, which is exactly why the train head was shaking.
function computeTrainHeadingV48(train, line, nodes, nodeA, nodeB, lat, lng) {
  if (!train || !line || !Array.isArray(line.stationIds) || !Array.isArray(nodes)) {
    return train && train.direction === 0 ? 90 : 270;
  }

  const total = line.stationIds.length;
  let dir = train.direction;
  let targetStationIdx = train.nextStationIdx;

  // If the train is dwelling at a terminal, its nose must already point to the post-turnback outbound direction.
  if (train.state === 'dwelling' || train.state === 'turning_back') {
    if (train.nextStationIdx >= total - 1 && train.direction === 0) {
      dir = 1;
      targetStationIdx = total - 2;
    } else if (train.nextStationIdx <= 0 && train.direction === 1) {
      dir = 0;
      targetStationIdx = 1;
    }
  }

  // Prefer the current physical segment while running.
  if (nodeA && nodeB && train.state !== 'dwelling') {
    return dir === 0
      ? bearing(nodeA.lat, nodeA.lng, nodeB.lat, nodeB.lng)
      : bearing(nodeB.lat, nodeB.lng, nodeA.lat, nodeA.lng);
  }

  // Dwelling/created marker: find the first path segment leaving the current station in the outbound direction.
  const currentStationIdx = (train.state === 'dwelling' || train.state === 'turning_back')
    ? train.nextStationIdx
    : (dir === 0 ? Math.max(0, targetStationIdx - 1) : Math.min(total - 1, targetStationIdx + 1));
  const currentStationId = line.stationIds[currentStationIdx];
  let currentNodeIndex = -1;
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i] && nodes[i].type === 'station' && nodes[i].id === currentStationId) { currentNodeIndex = i; break; }
  }
  if (currentNodeIndex >= 0) {
    if (dir === 0 && nodes[currentNodeIndex + 1]) {
      return bearing(nodes[currentNodeIndex].lat, nodes[currentNodeIndex].lng, nodes[currentNodeIndex + 1].lat, nodes[currentNodeIndex + 1].lng);
    }
    if (dir === 1 && nodes[currentNodeIndex - 1]) {
      return bearing(nodes[currentNodeIndex].lat, nodes[currentNodeIndex].lng, nodes[currentNodeIndex - 1].lat, nodes[currentNodeIndex - 1].lng);
    }
  }

  if (nodeA && nodeB) {
    return dir === 0
      ? bearing(nodeA.lat, nodeA.lng, nodeB.lat, nodeB.lng)
      : bearing(nodeB.lat, nodeB.lng, nodeA.lat, nodeA.lng);
	  }
	  return dir === 0 ? 90 : 270;
	}

function cityrailResolveTrainMarkerPosition(train, line, nodes, stationMap) {
  const depotVisual = cityrailDepotConnectorTrainVisual(train);
  if (depotVisual) {
    return {
      lat:depotVisual.lat,
      lng:depotVisual.lng,
      nodeA:depotVisual.nodeA,
      nodeB:depotVisual.nodeB,
      heading:depotVisual.heading,
      depotVisual
    };
  }
  const segIdx = Math.round(Number(train && train.segIndex) || 0);
  const segOk = Array.isArray(nodes) && !(segIdx < 0 || segIdx >= nodes.length - 1);
  const nodeA = segOk ? nodes[segIdx] : null;
  const nodeB = segOk ? nodes[segIdx + 1] : null;
  let lat;
  let lng;
	  if (train && (train.state === 'dwelling' || train.state === 'turning_back')) {
	    const stnId = Array.isArray(line && line.stationIds) ? line.stationIds[train.nextStationIdx] : null;
	    const station = stationMap && typeof stationMap.get === 'function'
	      ? stationMap.get(String(stnId))
	      : (stationMap && stationMap[stnId]);
	    if (station) {
	      const stnPos = getStationPosition(station, line.id);
	      lat = stnPos.lat;
	      lng = stnPos.lng;
    }
  }
  if (lat == null || lng == null) {
    if (!segOk) return null;
    const progress = Math.max(0, Math.min(1, Number(train && train.segProgress) || 0));
    lat = nodeA.lat + (nodeB.lat - nodeA.lat) * progress;
    lng = nodeA.lng + (nodeB.lng - nodeA.lng) * progress;
  }
  return { lat, lng, nodeA, nodeB };
}

function cityrailTrainMarkerRouteLine(train, baseLine) {
  const route = train && train.routePlan && Array.isArray(train.routePlan.stationIds) && train.routePlan.stationIds.length >= 2
    ? train.routePlan
    : null;
  if (!route || !baseLine) return baseLine;
  return Object.assign({}, baseLine, {
    stationIds: route.stationIds.slice(),
    waypoints: Array.isArray(route.waypoints) ? route.waypoints.map(w => Object.assign({}, w)) : [],
    expressService: route.expressService || baseLine.expressService,
    pathMode: 'ordered',
    _runtimeParentLineId: baseLine.id,
    _runtimeRouteId: route.routeId || ('train-route:' + String(train.id || '') + ':' + String(route.connectorLineId || route.branchLineId || ''))
  });
}

function cityrailTrainRouteTouchesLine(train, line) {
  if (!train || !line) return false;
  const lineId = String(line.id);
  if (String(train.lineId) === lineId) return true;
  const route = train.routePlan || {};
  return [
    route.connectorLineId,
    route.branchLineId,
    route.parentLineId,
    route.targetLineId,
    train._connectorLineId,
    train._throughRouteBranchId
  ].some(id => id != null && String(id) === lineId);
}

function applyTrainHeadingV48(marker, heading) {
  if (!marker || !Number.isFinite(heading)) return;
  if (!marker._cachedPolygon) {
    const el = marker.getElement && marker.getElement();
    if (el) marker._cachedPolygon = el.querySelector('polygon');
  }
  if (!marker._cachedPolygon) return;
  const last = Number(marker._lastHeading);
  if (!Number.isFinite(last) || Math.abs(heading - last) > 0.5) {
    marker._cachedPolygon.setAttribute('transform', `rotate(${heading})`);
    marker._lastHeading = heading;
  }
}

// Render all train markers — 优化版：缓存 DOM 引用，减少 querySelector
// 列车已与 visual polyline 共用同一 dense path，位置精确贴合
function renderAllTrainMarkers() {
  if (!cityrailShouldRenderTrainsAtCurrentZoom()) {
    Object.values(trainMarkers).forEach(m => map.removeLayer(m));
    trainMarkers = {};
    return;
  }
	  const activeIds = new Set();
	  const runtimeIndexes = cityrailGetRuntimeIndexes();
	  const lineMap = runtimeIndexes.lineById;
	  const stationMap = runtimeIndexes.stationById;
	  const lineNodesMap = {};
	  for (const line of state.lines) {
	    if (line && line.id != null) lineNodesMap[String(line.id)] = getLineTrainNodes(line);
	  }

  state.trains.forEach(train => {
    if (train.state === 'waiting' || train.state === 'done') return;
    activeIds.add(train.id);

	    const line = lineMap.get(String(train.lineId));
    if (!line) return;

    const markerLine = cityrailTrainMarkerRouteLine(train, line);
    const nodes = markerLine === line
      ? lineNodesMap[line.id]
      : getLineTrainNodes(markerLine);
    const markerPos = cityrailResolveTrainMarkerPosition(train, markerLine, nodes, stationMap);
    if (!markerPos) return;
    const { lat, lng, nodeA, nodeB } = markerPos;

    let marker = trainMarkers[train.id];
    if (marker) {
      // 更新位置
      marker.setLatLng([lat, lng]);

      // v48: 停站、折返、快慢车跳站时也要持续校正车头，确保永远朝向实际运行方向。
      const heading = Number.isFinite(markerPos.heading) ? markerPos.heading : computeTrainHeadingV48(train, markerLine, nodes, nodeA, nodeB, lat, lng);
      applyTrainHeadingV48(marker, heading);
      train._lastRenderLatV48 = lat;
      train._lastRenderLngV48 = lng;

      // 超载状态变更
      if (train.overloaded !== marker._wasOverloaded) {
        const el = marker.getElement();
        if (el) {
          el.classList.toggle('train-marker-overload', train.overloaded);
        }
        marker._wasOverloaded = train.overloaded;
      }

      // 若弹窗已打开，实时刷新内容
      if (marker._popupOpen) {
        marker.setPopupContent(buildTrainPopupHTML(train, markerLine));
      }
    } else {
      // 仅创建一次 marker
      // v48: 初次创建也按实际运动/下一目标站方向确定车头，避免停站或折返时反向。
      let heading = Number.isFinite(markerPos.heading) ? markerPos.heading : computeTrainHeadingV48(train, markerLine, nodes, nodeA, nodeB, lat, lng);
      train._lastRenderLatV48 = lat;
      train._lastRenderLngV48 = lng;
      const triangleSVG = `<svg width="12" height="12" viewBox="-6 -6 12 12" style="display:block;">
        <polygon points="0,-5.5 -4,2.5 0,0 4,2.5" fill="${markerLine.color}" stroke="#fff" stroke-width="0.7"
          transform="rotate(${heading})"
          style="filter:drop-shadow(0 0 1.5px ${markerLine.color}88);" />
      </svg>`;
      const divIcon = L.divIcon({
        className: 'train-marker' + (train.overloaded ? ' train-marker-overload' : ''),
        iconSize: [12, 12],
        iconAnchor: [6, 6],
        html: triangleSVG,
      });
      marker = L.marker([lat, lng], {
        icon: divIcon,
        interactive: true,
        zIndexOffset: 8000,
      }).addTo(map);
      marker._wasOverloaded = train.overloaded;
      marker._lastHeading = heading;
      // 缓存 polygon 引用
      const el = marker.getElement();
      if (el) marker._cachedPolygon = el.querySelector('polygon');

      // 点击列车显示信息弹窗
      const popupContent = buildTrainPopupHTML(train, markerLine);
      marker.bindPopup(popupContent, { className: 'train-info-popup', closeButton: true, autoClose: false });
      marker.on('click', () => {
        marker._popupOpen = true;
        marker.openPopup();
      });
      marker.on('popupclose', () => { marker._popupOpen = false; });

      trainMarkers[train.id] = marker;
    }
  });

  // 移除失效的 marker
  for (const tid in trainMarkers) {
    if (!activeIds.has(tid)) {
      map.removeLayer(trainMarkers[tid]);
      delete trainMarkers[tid];
    }
  }
}

// ==================== LINE STATS ====================
function computeLineLengths() {
  state.lines.forEach(line => {
    if (state.lineLengthCache[line.id] !== undefined) return; // already cached
    const nodes = getLineNodes(line);
    let total = 0;
    for (let i = 0; i < nodes.length - 1; i++) {
      total += haversine(nodes[i].lat, nodes[i].lng, nodes[i + 1].lat, nodes[i + 1].lng);
    }
    state.lineLengthCache[line.id] = total;
  });
}

function recomputeLineLengthsNow() {
  if (!state || !Array.isArray(state.lines)) return 0;
  state.lineLengthCache = state.lineLengthCache || {};
  let networkTotal = 0;
  state.lines.forEach(line => {
    const nodes = getLineNodes(line);
    let total = 0;
    for (let i = 0; i < nodes.length - 1; i++) {
      total += haversine(nodes[i].lat, nodes[i].lng, nodes[i + 1].lat, nodes[i + 1].lng);
    }
    state.lineLengthCache[line.id] = total;
    line.lengthKm = total;
    networkTotal += total;
  });
  state._networkLengthKmLive = networkTotal;
  return networkTotal;
}
try { window.recomputeLineLengthsNow = recomputeLineLengthsNow; } catch(e) {}
function cityrailLineLengthTopologySignature(st) {
  st = st || state || {};
  const stationMap = new Map((Array.isArray(st.stations) ? st.stations : []).map(function(station) {
    return [String(station && station.id), station];
  }));
  return (Array.isArray(st.lines) ? st.lines : []).map(function(line) {
    if (!line) return '';
    const stationCoordSig = Array.isArray(line.stationIds) ? line.stationIds.map(function(id) {
      const station = stationMap.get(String(id));
      if (!station) return String(id) + ':missing';
      return [
        String(id),
        Math.round(Number(station.lat || 0) * 1e6),
        Math.round(Number(station.lng || 0) * 1e6),
        station._geometryVersion || 0,
        station._topologyVersion || 0
      ].join(':');
    }).join(',') : '';
    return [
      line.id,
      Array.isArray(line.stationIds) ? line.stationIds.join(',') : '',
      stationCoordSig,
      Array.isArray(line.waypoints) ? line.waypoints.map(function(w) {
        return [w && w.id, w && w.segIdx, w && w.order, Math.round(Number(w && w.lat || 0) * 1e6), Math.round(Number(w && w.lng || 0) * 1e6)].join(':');
      }).join('.') : '',
      line._topologyVersion || 0,
      line._geometryVersion || 0
    ].join('|');
  }).join('||');
}
function cityrailEnsureLineLengthCache(reason) {
  const st = state || {};
  if (!Array.isArray(st.lines)) return { total:0, byLine:Object.create(null), sig:'' };
  st.lineLengthCache = st.lineLengthCache || {};
  const cache = st.__cityrailFastLineLengthCache;
  const now = Date.now();
  const sig = cityrailLineLengthTopologySignature(st);
  if (cache && cache.cacheRef === st.lineLengthCache && cache.sig === sig && cache.lineCount === st.lines.length && now - Number(cache.checkedAt || 0) < 500) {
    cache.checkedAt = now;
    cache.quickHits = (cache.quickHits || 0) + 1;
    return cache;
  }
  const missing = st.lines.some(function(line) {
    return line && !(Number(st.lineLengthCache[line.id]) > 0);
  });
  if (cache && cache.sig === sig && !missing) {
    cache.checkedAt = now;
    cache.cacheRef = st.lineLengthCache;
    cache.lineCount = st.lines.length;
    cache.sigHits = (cache.sigHits || 0) + 1;
    return cache;
  }
  if (missing || !cache || cache.sig !== sig) {
    try {
      if (typeof recomputeLineLengthsNow === 'function') recomputeLineLengthsNow();
      else if (typeof computeLineLengths === 'function') computeLineLengths();
    } catch(e) {}
  }
  const byLine = Object.create(null);
  let total = 0;
  st.lines.forEach(function(line) {
    if (!line) return;
    const len = Number(st.lineLengthCache && st.lineLengthCache[line.id]);
    if (Number.isFinite(len) && len > 0) {
      byLine[String(line.id)] = len;
      total += len;
    }
  });
  st.__cityrailFastLineLengthCache = { sig, total, byLine, at:now, checkedAt:now, cacheRef:st.lineLengthCache, lineCount:st.lines.length, reason:reason || '', quickHits:0, sigHits:0 };
  return st.__cityrailFastLineLengthCache;
}
function cityrailFastNetworkLengthKm(reason) {
  return cityrailEnsureLineLengthCache(reason).total || 0;
}
function cityrailFastLineLengthKm(line, reason) {
  if (!line) return 0;
  const cache = cityrailEnsureLineLengthCache(reason);
  return Math.max(0, Number(cache.byLine && cache.byLine[String(line.id)]) || 0);
}
try {
  window.cityrailFastNetworkLengthKm = cityrailFastNetworkLengthKm;
  window.cityrailFastLineLengthKm = cityrailFastLineLengthKm;
  window.cityrailEnsureLineLengthCache = cityrailEnsureLineLengthCache;
} catch(e) {}

function toggleLineStats() {
  state.showLineStats = !state.showLineStats;
  const overlay = document.getElementById('line-stats-overlay');
  const btn = document.getElementById('btn-line-stats');
  if (state.showLineStats) {
    overlay.classList.remove('hidden');
    btn.classList.add('active');
    renderLineStats();
  } else {
    overlay.classList.add('hidden');
    btn.classList.remove('active');
  }
}

function renderLineStats() {
  const tbody = document.getElementById('line-stats-tbody');
  if (state.lineStatsData.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--text-dim);padding:16px">暂无线路数据</td></tr>';
    return;
  }
  const maxIntensity = Math.max(1, ...state.lineStatsData.map(d => d.intensity));
  tbody.innerHTML = state.lineStatsData.map(d => {
    const capUtil = d.bidirCap > 0 ? (d.demandFlow / d.bidirCap * 100) : 0;
    let capClass = '';
    if (capUtil >= 100) capClass = 'intensity-high';
    else if (capUtil >= 70) capClass = 'intensity-mid';
    const capLabel = capUtil >= 100
      ? '⚠️ ' + Math.round(capUtil) + '%'
      : Math.round(capUtil) + '%';
    const intensityClass = d.intensity > maxIntensity * 0.7 ? 'intensity-high'
      : d.intensity > maxIntensity * 0.35 ? 'intensity-mid' : 'intensity-low';
    const trainTypeLabel = (TRAIN_TYPES[d.trainType]?.name || d.trainType || 'A型车');
    const trainDesc = d.trainType + d.cars + '节';
    return `<tr>
      <td><span class="line-color-dot" style="background:${d.color}"></span>${d.name}</td>
      <td><span class="formation-badge" onclick="event.stopPropagation();openLineConfig('${d.id}')" title="点击配置车型/编组/速度">${trainDesc}</span></td>
      <td>${d.speed || 80}km/h</td>
      <td>${d.length.toFixed(1)}</td>
      <td>${formatNumber(d.flow)}</td>
      <td class="${capClass}" title="需求/运能: ${formatNumber(d.demandFlow)} / ${formatNumber(d.bidirCap)}">${capLabel}</td>
      <td><button class="stats-del-btn" onclick="event.stopPropagation();deleteLineWithStations('${d.id}')" title="删除线路及站点">×</button></td>
    </tr>`;
  }).join('');
}

function cycleFormation(lineId) {
  // Legacy compat — redirect to config panel
  openLineConfig(lineId);
}

// ==================== LINE CONFIG PANEL ====================
function cfgLineFlowEsc(value) {
  return String(value == null ? '' : value).replace(/[&<>"]/g, c => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;' }[c] || c));
}

function cfgLineFlowNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cfgLineFlowFmt(value) {
  const n = Math.max(0, Math.round(cfgLineFlowNumber(value)));
  try { return typeof formatNumber === 'function' ? formatNumber(n) : n.toLocaleString(); }
  catch(e) { return String(n); }
}

function cfgLineStationDirWaiting(line, stationId, stationIdx, dir) {
  return cityrailWaitingCountForLineStationDirection(line, stationIdx, dir);
}

function cfgLineStationFlowRows(line) {
  const ids = Array.isArray(line && line.stationIds) ? line.stationIds : [];
  return ids.map((stationId, index) => {
    const station = state.stations.find(s => String(s.id) === String(stationId));
    const pool = (state.stationWaitingPool && state.stationWaitingPool[stationId]) || (state.stationWaitingPool && state.stationWaitingPool[String(stationId)]) || {};
    const up = cfgLineStationDirWaiting(line, stationId, index, 0);
    const down = cfgLineStationDirWaiting(line, stationId, index, 1);
    return {
      id: String(stationId),
      index,
      name: (station && station.name) || `站点${index + 1}`,
      up,
      down,
      waiting: up + down,
      arrived: cfgLineFlowNumber(pool.totalArrived || pool.arrived || pool.inbound),
      boarded: cfgLineFlowNumber(pool.totalBoarded || pool.boarded || pool.boardedTotal),
      delivered: cfgLineFlowNumber(pool.totalDelivered || pool.deliveredTotal || pool.outbound, cfgLineFlowNumber(station && (station.totalDelivered || station.delivered))),
    };
  });
}

function renderConfigLineStationFlow(line) {
  const box = document.getElementById('cfg-line-station-flow');
  if (!box || !line) return;
  const rows = cfgLineStationFlowRows(line);
  const list = rows.length ? rows.map(row => `
    <div class="cfg-line-station-flow-row" data-config-station-flow="${cfgLineFlowEsc(row.id)}">
      <button type="button" class="cfg-line-station-flow-name cfg-station-rename" data-station-rename="${cfgLineFlowEsc(row.id)}" title="点击修改车站名称"><span>${row.index + 1}</span><span class="cityrail-station-rename-text">${cfgLineFlowEsc(row.name)}</span><small class="cityrail-line-panel-rename-hint">点击以修改站名</small></button>
      <div class="cfg-line-station-flow-metrics">
        <div><span>上行</span><b>${cfgLineFlowFmt(row.up)}</b></div>
        <div><span>下行</span><b>${cfgLineFlowFmt(row.down)}</b></div>
      </div>
    </div>
  `).join('') : '<div class="cfg-time-hint">本线路暂无车站</div>';
  box.innerHTML = `<div class="cfg-line-station-flow-title"><span>本线路站点客流</span><span>${cfgLineFlowFmt(rows.length)}站</span></div><div class="cfg-line-station-flow-list">${list}</div>`;
}

function openLineConfig(lineId) {
  const line = state.lines.find(l => l.id === lineId);
  if (!line) return;
  const linePanel = document.getElementById('line-config-panel');
  if (linePanel) linePanel.style.setProperty('--cr-object-accent', normalizeHexColor(line.color || '#0a84ff'));
  cityrailSetLineNodeFocus(line.id, 'openLineConfig');
  const overlay = document.getElementById('line-config-overlay');
  overlay.classList.remove('hidden');
  if(window.CityRailDepotService && typeof CityRailDepotService.closeDepotPanel === 'function') CityRailDepotService.closeDepotPanel();

  // 关闭站点设置面板（互斥）
  closeStationDetail();

  // Reset edit mode
  exitEditMode();

  // Populate form
  normalizeLineTrainType(line);
  normalizeLineServiceConfig(line);
  const ttSelect = document.getElementById('cfg-train-type');
  ttSelect.innerHTML = Object.entries(TRAIN_TYPES).map(([key, t]) =>
    `<option value="${key}" ${line.trainType === key ? 'selected' : ''}>${t.name} — ${t.desc} (${t.capPerCar}人/节)</option>`
  ).join('');

  const carSelect = document.getElementById('cfg-cars');
  carSelect.innerHTML = CAR_COUNTS.map(n =>
    `<option value="${n}" ${(line.cars || 6) === n ? 'selected' : ''}>${n}节编组</option>`
  ).join('');

  const speedSelect = document.getElementById('cfg-speed');
  speedSelect.innerHTML = SPEED_LEVELS.map(v =>
    `<option value="${v}" ${(line.speed || 80) === v ? 'selected' : ''}>${v} km/h</option>`
  ).join('');

  // Populate headway sliders
  document.getElementById('cfg-headway-offpeak').value = line.offPeakHeadwayMin;
  document.getElementById('cfg-headway-offpeak-val').textContent = line.offPeakHeadwayMin + ' 分钟';
  document.getElementById('cfg-headway-normal').value = line.normalHeadwayMin;
  document.getElementById('cfg-headway-normal-val').textContent = line.normalHeadwayMin + ' 分钟';
  document.getElementById('cfg-headway-peak').value = line.peakHeadwayMin;
  document.getElementById('cfg-headway-peak-val').textContent = line.peakHeadwayMin + ' 分钟';

  // Populate first/last train time
  const firstTrain = line.firstTrain;
  const lastTrain = line.lastTrain;
  document.getElementById('cfg-first-train').value = firstTrain;
  document.getElementById('cfg-first-train-val').textContent = formatTime(firstTrain);
  document.getElementById('cfg-last-train').value = lastTrain;
  document.getElementById('cfg-last-train-val').textContent = formatTime(lastTrain);
  updateTimeHint();

  // Show line name with color
  const nameEl = document.getElementById('cfg-line-name');
  nameEl.textContent = line.name;
  nameEl.style.color = line.color;
  nameEl.style.textShadow = '';

  // Populate name editor color picker & hide editor
  document.getElementById('cfg-edit-color').value = line.color;
  document.getElementById('cfg-name-editor').classList.add('hidden');

  // Store line ID for save
  document.getElementById('line-config-overlay').dataset.lineId = lineId;
  renderConfigLineStationFlow(line);

  opsCurrentLineId = null;
}

// ==================== LINE OPS PANEL (线路运营) ====================
let opsCurrentLineId = null;
let opsCurrentDir = 0;
let opsLastRefresh = 0;

function renderLineOpsPanel(lineId, dir) {
  const line = state.lines.find(l => l.id === lineId);
  if (line) renderConfigLineStationFlow(line);
  opsCurrentLineId = null;
  opsCurrentDir = dir || 0;
}


// ==================== LINE EDIT MODE ====================
function enterEditMode(mode) {
  editLineId = document.getElementById('line-config-overlay').dataset.lineId;
  editModeType = mode;

  const btnSta = document.getElementById('cfg-btn-add-station');
  const btnWp = document.getElementById('cfg-btn-add-waypoint');
  const hint = document.getElementById('cfg-edit-hint');

  btnSta.classList.toggle('active-edit', mode === 'station');
  btnWp.classList.toggle('active-edit', mode === 'waypoint');

  if (mode === 'station') {
    hint.textContent = '▸ 点击地图选择站点位置';
  } else {
    hint.textContent = '▸ 点击地图选择节点位置';
  }

  map.getContainer().style.cursor = 'crosshair';
}

function exitEditMode() {
  editLineId = null;
  editModeType = null;
  const hint = document.getElementById('cfg-edit-hint');
  if (hint) hint.textContent = '';
  map.getContainer().style.cursor = '';
  // Reset button states
  const btnSta = document.getElementById('cfg-btn-add-station');
  const btnWp = document.getElementById('cfg-btn-add-waypoint');
  if (btnSta) btnSta.classList.remove('active-edit');
  if (btnWp) btnWp.classList.remove('active-edit');
}

// Handle map click in edit mode
function handleEditMapClick(e) {
  if (!editLineId || !editModeType) return;
  const line = state.lines.find(l => l.id === editLineId);
  if (!line) return;

  const ll = cityrailEventDataLatLng(e);
  if (!ll) return;
  const { lat, lng } = ll;

  if (editModeType === 'station') {
    insertStationOnLine(line, lat, lng);
  } else if (editModeType === 'waypoint') {
    insertWaypointOnLine(line, lat, lng);
  }

  // Stay in edit mode for continuous adding
  // User must re-click the edit button to exit
}

function insertStationOnLine(line, lat, lng) {
  // Create the station
  const station = addStation(lat, lng);
  if (!station) return;

  // Find where to insert in the stationIds array
  const segIdx = findClosestSegmentIndex(line, lat, lng);
  const insertIdx = segIdx + 1;
  const originalWaypoints = Array.isArray(line.waypoints) ? line.waypoints.slice() : [];
  const beforeStation = state.stations.find(s => s.id === line.stationIds[segIdx]);
  const afterStation = state.stations.find(s => s.id === line.stationIds[Math.min(segIdx + 1, line.stationIds.length - 1)]);
  const splitRatio = (beforeStation && afterStation)
    ? projectRatioOnSegmentPx(lat, lng, beforeStation.lat, beforeStation.lng, afterStation.lat, afterStation.lng)
    : 0.5;

  line.stationIds.splice(insertIdx, 0, station.id);

  // Re-index waypoints after station insertion without deleting nodes from the split segment.
  // Nodes before the new station stay on segIdx; nodes after it move to segIdx + 1.
  line.waypoints = originalWaypoints.map(w => {
    const next = Object.assign({}, w);
    const oldSeg = Math.round(Number(next.segIdx));
    if (!Number.isFinite(oldSeg)) return next;
    if (oldSeg > segIdx) next.segIdx = oldSeg + 1;
    else if (oldSeg === segIdx) {
      const ratio = (beforeStation && afterStation)
        ? projectRatioOnSegmentPx(next.lat, next.lng, beforeStation.lat, beforeStation.lng, afterStation.lat, afterStation.lng)
        : 0;
      next.segIdx = ratio <= splitRatio ? segIdx : segIdx + 1;
    } else next.segIdx = oldSeg;
    return next;
  });
  normalizeLineWaypoints(line, 'insertStationOnLine');

  rebuildLineTopology(line, 'insertStationOnLine');
  markTransferReviewRequired([station.id], 'insertStationOnLine');

  if (state.isSimulating) setTimeout(() => { runSimulation(); }, 0);
  return station;
}

function insertWaypointOnLine(line, lat, lng) {
  // Ensure waypoints array exists
  if (!line.waypoints) line.waypoints = [];

  // Find which segment this waypoint belongs to
  const segIdx = findClosestSegmentIndex(line, lat, lng);

  // Determine order within this segment
  const segWps = line.waypoints.filter(w => w.segIdx === segIdx).sort((a, b) => a.order - b.order);

  // Find where the click is closest along the segment to determine order
  const sidA = line.stationIds[segIdx];
  const sidB = line.stationIds[Math.min(segIdx + 1, line.stationIds.length - 1)];
  const sa = state.stations.find(s => s.id === sidA);
  const sb = state.stations.find(s => s.id === sidB);
  if (!sa || !sb) return;

  // Compute true projection ratio along the segment. Distance-to-A alone is unstable on angled/curved edits
  // and was the root cause of waypoint order inversion after extending a line.
  const ratio = projectRatioOnSegmentPx(lat, lng, sa.lat, sa.lng, sb.lat, sb.lng);

  // Insert into waypoints in sorted order
  let insertOrder = 0;
  for (let i = 0; i < segWps.length; i++) {
    const wpRatio = projectRatioOnSegmentPx(segWps[i].lat, segWps[i].lng, sa.lat, sa.lng, sb.lat, sb.lng);
    if (ratio > wpRatio) insertOrder = i + 1;
  }

  const newWp = {
    id: genId(),
    lat,
    lng,
    segIdx,
    order: insertOrder,
  };

  // Shift orders for waypoints after insertion point
  segWps.filter(w => w.order >= insertOrder).forEach(w => w.order++);

  line.waypoints.push(newWp);
  normalizeLineWaypoints(line, 'insertWaypointOnLine');

  rebuildLineTopology(line, 'insertWaypointOnLine');
  if (state.isSimulating) setTimeout(() => { runSimulation(); }, 0);
  return newWp;
}

// Find which segment index the click is closest to
function findClosestSegmentIndex(line, lat, lng) {
  let minDist = Infinity;
  let bestIdx = 0;

  for (let i = 0; i < line.stationIds.length - 1; i++) {
    const sa = state.stations.find(s => s.id === line.stationIds[i]);
    const sb = state.stations.find(s => s.id === line.stationIds[i + 1]);
    if (!sa || !sb) continue;

    // Find closest point on segment SA→SB to click
    const dist = pointToSegmentDist(lat, lng, sa.lat, sa.lng, sb.lat, sb.lng);
    if (dist < minDist) {
      minDist = dist;
      bestIdx = i;
    }
  }
  // If only one station or no segments, default to 0
  return bestIdx;
}

// Point-to-segment distance (in approximate degrees)
function pointToSegmentDist(px, py, ax, ay, bx, by) {
  const dx = bx - ax, dy = by - ay;
  const len2 = dx * dx + dy * dy;
  if (len2 < 1e-12) return Math.hypot(px - ax, py - ay);
  let t = ((px - ax) * dx + (py - ay) * dy) / len2;
  t = Math.max(0, Math.min(1, t));
  const cx = ax + t * dx, cy = ay + t * dy;
  return Math.hypot(px - cx, py - cy);
}

function normalizeHexColor(color) {
  const fallback = '#ffffff';
  if (!color) return fallback;
  let text = String(color).trim();
  const named = {
    red: '#ff3b30',
    blue: '#0a84ff',
    green: '#30d158',
    yellow: '#ffd60a',
    orange: '#ff9f0a',
    purple: '#bf5af2',
    pink: '#ff2d55',
    cyan: '#64d2ff',
    white: '#ffffff',
    black: '#000000',
  };
  if (named[text.toLowerCase()]) text = named[text.toLowerCase()];
  if (/^#[0-9a-f]{3}$/i.test(text)) {
    return '#' + text.slice(1).split('').map(ch => ch + ch).join('');
  }
  if (/^#[0-9a-f]{6}$/i.test(text)) return text;
  const rgb = text.match(/rgba?\(\s*(\d+)[,\s]+(\d+)[,\s]+(\d+)/i);
  if (rgb) {
    return '#' + [rgb[1], rgb[2], rgb[3]].map(v => Math.max(0, Math.min(255, Number(v) || 0)).toString(16).padStart(2, '0')).join('');
  }
  return fallback;
}

// ==================== TOGGLE LINE NODES (X KEY) ====================
function cityrailLineById(lineId) {
  const id = String(lineId == null ? '' : lineId);
  if (!id || !state || !Array.isArray(state.lines)) return null;
  return state.lines.find(l => l && String(l.id) === id) || null;
}

function cityrailSetLineNodeFocus(lineId, reason) {
  const line = cityrailLineById(lineId);
  if (!line) return null;
  state.currentLineId = line.id;
  state.__cityrailLineNodeFocusId = line.id;
  window.__cityrailLineNodeFocusId = line.id;
  window.__cityrailLineNodeFocusReason = reason || 'set';
  try {
    const overlay = document.getElementById('line-config-overlay');
    if (overlay && !overlay.classList.contains('hidden')) overlay.dataset.lineId = line.id;
  } catch(e) {}
  return line;
}

function cityrailClearLineNodeFocus(lineId, reason) {
  const target = lineId == null ? '' : String(lineId);
  const focused = String(state && state.__cityrailLineNodeFocusId || '');
  const globalFocused = String(window.__cityrailLineNodeFocusId || '');
  const current = String(state && state.currentLineId || '');
  const shouldClear = !target || current === target || focused === target || globalFocused === target;
  if (!shouldClear) return;
  if (!target || current === target) state.currentLineId = null;
  if (!target || focused === target) delete state.__cityrailLineNodeFocusId;
  if (!target || globalFocused === target) {
    delete window.__cityrailLineNodeFocusId;
    delete window.__cityrailLineNodeFocusReason;
  }
}

function cityrailResolveLineNodeFocus() {
  const focused = cityrailLineById(state && state.__cityrailLineNodeFocusId) || cityrailLineById(window.__cityrailLineNodeFocusId);
  if (focused) return focused;
  const overlay = document.getElementById('line-config-overlay');
  const cfgLineId = overlay && overlay.dataset && overlay.dataset.lineId;
  const cfgLine = cityrailLineById(cfgLineId);
  if (cfgLine) return cityrailSetLineNodeFocus(cfgLine.id, 'line-config-overlay');
  const current = cityrailLineById(state && state.currentLineId);
  if (current) return cityrailSetLineNodeFocus(current.id, 'state-current-line');
  if ((state.lines || []).length === 1) return cityrailSetLineNodeFocus(state.lines[0].id, 'single-line');
  return null;
}
window.cityrailSetLineNodeFocus = cityrailSetLineNodeFocus;
window.cityrailClearLineNodeFocus = cityrailClearLineNodeFocus;
window.cityrailResolveLineNodeFocus = cityrailResolveLineNodeFocus;

function toggleLineNodes() {
  const line = cityrailResolveLineNodeFocus();
  if (!line) return;

  if (state.showCurrentLineNodes) {
    hideCurrentLineNodes();
    state.showCurrentLineNodes = false;
  } else {
    showCurrentLineNodes(line);
    state.showCurrentLineNodes = true;
  }
}

function cityrailNodePopupEscape(value) {
  return String(value == null ? '' : value).replace(/[&<>"]/g, c => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;' }[c]));
}

