function cityrailFormatSpeedLabel(speed) {
  const value = Math.max(1, Math.min(50, Math.round(Number(speed || 1) * 10) / 10));
  return (Number.isInteger(value) ? String(value) : value.toFixed(1)) + 'x';
}

