(function installCityRailInteractiveSurfaceGuard(){
  if (window.__cityrailInteractiveSurfaceGuard) return;
  window.__cityrailInteractiveSurfaceGuard = true;
  const exclusiveIds = [
    'splash-screen','invite-code-screen','auth-screen','workshop-screen','product-intro-screen',
    'register-screen','login-screen','city-select-screen','payment-screen','payment-success-screen'
  ];
  const overlayIds = [
    'settings-overlay','vt-overlay','line-stats-overlay','line-config-overlay',
    'station-detail-overlay','ctrl-center-overlay','new-line-dialog-overlay','nav-overlay'
  ];
  const appRootIds = ['app-logo','city-badge','topbar','bottombar','map'];
  const isVisible = el => {
    if (!el) return false;
    const s = getComputedStyle(el);
    const r = el.getBoundingClientRect();
    return s.display !== 'none' && s.visibility !== 'hidden' && Number(s.opacity || 1) !== 0 && r.width > 0 && r.height > 0;
  };
  const setInactive = (el, inactive) => {
    if (!el) return;
    if (inactive) {
      el.setAttribute('aria-hidden', 'true');
      try { el.inert = true; } catch(e) { el.setAttribute('inert', ''); }
    } else {
      el.removeAttribute('aria-hidden');
      try { el.inert = false; } catch(e) {}
      el.removeAttribute('inert');
    }
  };
  function refresh() {
    const exclusiveVisible = exclusiveIds.some(id => isVisible(document.getElementById(id)));
    exclusiveIds.concat(overlayIds).forEach(id => {
      const el = document.getElementById(id);
      if (el) setInactive(el, !isVisible(el));
    });
    appRootIds.forEach(id => setInactive(document.getElementById(id), exclusiveVisible));
  }
  let raf = 0;
  const schedule = () => {
    if (raf) return;
    raf = requestAnimationFrame(() => { raf = 0; refresh(); });
  };
  window.cityrailRefreshInteractiveSurfaces = schedule;
  if (document.body) {
    new MutationObserver(schedule).observe(document.body, { attributes:true, childList:true, subtree:true, attributeFilter:['class','style','hidden'] });
  }
  schedule();
})();

