// Keyboard shortcuts
document.addEventListener('keydown', (e) => {
  // ESC: close settings overlay
  if (e.key.toLowerCase() === 'escape' && !settingsOverlay.classList.contains('hidden')) {
    e.preventDefault();
    closeSettings();
    return;
  }
  // ESC in add mode: always exit, even when focused on inputs
  if (e.key.toLowerCase() === 'escape' && editLineId && editModeType) {
    e.preventDefault();
    closeLineConfig();
    return;
  }

  // Ignore if typing in an input/textarea/select
  const tag = document.activeElement?.tagName?.toLowerCase();
  if (tag === 'input' || tag === 'textarea' || tag === 'select') return;

  switch (e.key.toLowerCase()) {
    case ' ':
      e.preventDefault();
      toggleSimulation();
      return;
    case 'escape':
      if (state.currentLineId) {
        const cfgOverlay2 = document.getElementById('line-config-overlay');
        if (cfgOverlay2 && !cfgOverlay2.classList.contains('hidden')) {
          closeLineConfig();
          e.preventDefault();
          return;
        }
      }
      if (state.showLineStats) {
        state.showLineStats = false;
        document.getElementById('line-stats-overlay').classList.add('hidden');
        document.getElementById('btn-line-stats').classList.remove('active');
      }
      const mmOverlay = document.getElementById('metro-map-overlay');
      if (mmOverlay && !mmOverlay.classList.contains('hidden')) {
        toggleMetroMap();
        e.preventDefault();
        return;
      }
      const ccOverlay = document.getElementById('ctrl-center-overlay');
      if (ccOverlay && !ccOverlay.classList.contains('hidden')) {
        toggleCtrlCenter();
        e.preventDefault();
        return;
      }
      cityrailClearLineNodeFocus(null, 'escape-key');
      hideCurrentLineNodes();
      state.showCurrentLineNodes = false;
      break;
    case 'x':
      e.preventDefault();
      toggleLineNodes();
      return;
    default: return;
  }
  updateUI();
});

