// ==================== STATION DETAIL ====================
let stationDetailId = null;
let stationDetailLineId = null;  // Track which line's polygon was clicked

function stationCanonicalNameForStats(station) {
  const name = String(station && station.name || station && station.id || '').trim();
  return name || String(station && station.id || '');
}

function stationTransferGroupIdsForStats(stationId) {
  const station = state.stations.find(s => String(s.id) === String(stationId));
  if (!station) return [String(stationId)];
  const name = stationCanonicalNameForStats(station);
  const ids = state.stations
    .filter(s => stationCanonicalNameForStats(s) === name)
    .map(s => String(s.id));
  return ids.length ? Array.from(new Set(ids)) : [String(stationId)];
}

function stationDailyPoolTotals(stationId) {
  const ids = stationTransferGroupIdsForStats(stationId);
  let inbound = 0;
  let outbound = 0;
  let waiting = 0;
  ids.forEach(id => {
    const pool = state.stationWaitingPool && (state.stationWaitingPool[id] || state.stationWaitingPool[String(id)]);
    if (!pool) return;
    inbound += Number(pool.totalArrived || pool.arrivedTotal || pool.inbound || 0) || 0;
    outbound += Number(pool.totalDelivered || pool.deliveredTotal || pool.outbound || 0) || 0;
    waiting += Number(pool.waiting || pool.count || 0) || 0;
  });
  return { stationIds: ids, inbound, outbound, waiting };
}

function getRealtimeStationOD(stationId) {
  const id = String(stationId);
  const groupIds = new Set(stationTransferGroupIdsForStats(stationId));
  const dailyTotals = stationDailyPoolTotals(stationId);
  const version = state.__realtimeStationODVersion || 0;
  const groupKey = groupIds.size > 1 ? Array.from(groupIds).sort().join('|') : '';
  if (groupIds.size <= 1 && state.__realtimeStationODByStation && state.__realtimeStationODByStation.version === version && state.__realtimeStationODByStation.rows && state.__realtimeStationODByStation.rows[id]) {
    return Object.assign({}, state.__realtimeStationODByStation.rows[id], {
      inboundTotal: dailyTotals.inbound,
      outboundTotal: dailyTotals.outbound,
      stationIds: dailyTotals.stationIds
    });
  }
  if (groupKey && state.__realtimeStationODGroupCache && state.__realtimeStationODGroupCache.version === version && state.__realtimeStationODGroupCache.rows && state.__realtimeStationODGroupCache.rows[groupKey]) {
    return {
      inboundTotal: dailyTotals.inbound,
      outboundTotal: dailyTotals.outbound,
      pairs: state.__realtimeStationODGroupCache.rows[groupKey].pairs.slice(),
      stationIds: dailyTotals.stationIds
    };
  }
  const byId = {};
  state.stations.forEach(s => { byId[String(s.id)] = s; });
  const byStation = Object.create(null);
  function ensure(id0) {
    const key = String(id0);
    if (!byStation[key]) byStation[key] = { inboundTotal:0, outboundTotal:0, pairs:[] };
    return byStation[key];
  }
  const ledger = state.__realtimeStationOD || {};
  Object.keys(ledger).forEach(key => {
    const row = ledger[key];
    if (!row || !Number.isFinite(Number(row.count)) || Number(row.count) <= 0) return;
    const originId = String(row.originId || '');
    const destId = String(row.destinationId || '');
    if (!originId || !destId) return;
    const count = Number(row.count);
    const out = ensure(originId);
    out.outboundTotal += count;
    out.pairs.push({ station: byId[destId], stationId: destId, flow: count, dir: 'out', lastAt: row.lastAt || 0 });
    const inbound = ensure(destId);
    inbound.inboundTotal += count;
    inbound.pairs.push({ station: byId[originId], stationId: originId, flow: count, dir: 'in', lastAt: row.lastAt || 0 });
  });
  Object.keys(byStation).forEach(stationKey => {
    const snap = byStation[stationKey];
    snap.pairs.sort((a, b) => b.flow - a.flow || b.lastAt - a.lastAt);
    snap.pairs = snap.pairs.slice(0, 10);
  });
  state.__realtimeStationODByStation = { version, rows:byStation };
  const mergedPairs = [];
  Object.keys(ledger).forEach(key => {
    const row = ledger[key];
    if (!row || !Number.isFinite(Number(row.count)) || Number(row.count) <= 0) return;
    const originId = String(row.originId || '');
    const destId = String(row.destinationId || '');
    if (!originId || !destId) return;
    const count = Number(row.count);
    if (groupIds.has(destId) && !groupIds.has(originId)) mergedPairs.push({ station: byId[originId], stationId: originId, flow: count, dir: 'in', lastAt: row.lastAt || 0 });
    if (groupIds.has(originId) && !groupIds.has(destId)) mergedPairs.push({ station: byId[destId], stationId: destId, flow: count, dir: 'out', lastAt: row.lastAt || 0 });
  });
  const pairMap = new Map();
  mergedPairs.forEach(pair => {
    const key = pair.dir + ':' + pair.stationId;
    const old = pairMap.get(key);
    if (old) {
      old.flow += pair.flow;
      old.lastAt = Math.max(old.lastAt || 0, pair.lastAt || 0);
    } else {
      pairMap.set(key, Object.assign({}, pair));
    }
  });
  const pairs = Array.from(pairMap.values()).sort((a, b) => b.flow - a.flow || b.lastAt - a.lastAt).slice(0, 10);
  const displayPairs = pairs.length ? pairs : ((byStation[id] && byStation[id].pairs) || []);
  if (groupKey) {
    if (!state.__realtimeStationODGroupCache || state.__realtimeStationODGroupCache.version !== version) {
      state.__realtimeStationODGroupCache = { version, rows: Object.create(null) };
    }
    state.__realtimeStationODGroupCache.rows[groupKey] = { pairs: displayPairs.slice() };
  }
  return {
    inboundTotal: dailyTotals.inbound,
    outboundTotal: dailyTotals.outbound,
    pairs: displayPairs,
    stationIds: dailyTotals.stationIds
  };
}

function renderStationRealtimeOD(stationId) {
  const snap = getRealtimeStationOD(stationId);
  const maxFlow = Math.max(snap.inboundTotal, snap.outboundTotal, 1);
  const inboundPct = Math.round((snap.inboundTotal / maxFlow) * 100);
  const outboundPct = Math.round((snap.outboundTotal / maxFlow) * 100);
  const inboundBar = document.getElementById('sd-inbound-bar');
  const inboundVal = document.getElementById('sd-inbound-val');
  const outboundBar = document.getElementById('sd-outbound-bar');
  const outboundVal = document.getElementById('sd-outbound-val');
  if (inboundBar) inboundBar.style.width = inboundPct + '%';
  if (inboundVal) inboundVal.textContent = formatNumber(Math.round(snap.inboundTotal));
  if (outboundBar) outboundBar.style.width = outboundPct + '%';
  if (outboundVal) outboundVal.textContent = formatNumber(Math.round(snap.outboundTotal));
}

function cityrailStationPanelEsc(value) {
  return String(value == null ? '' : value).replace(/[&<>"']/g, ch => ({ '&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;' }[ch]));
}

function cityrailStationPanelWaitingRows(stationId, contextLineId) {
  const targetId = String(stationId);
  const station = typeof cityrailGetStationById === 'function'
    ? cityrailGetStationById(targetId)
    : (state.stations || []).find(item => String(item && item.id) === targetId);
  if (!station) return [];
  const lineById = id => (state.lines || []).find(line => String(line && line.id) === String(id)) || null;
  const stationById = id => typeof cityrailGetStationById === 'function'
    ? cityrailGetStationById(id)
    : (state.stations || []).find(item => String(item && item.id) === String(id)) || null;
  const localLines = (getStationLines(targetId) || []).filter(line => line && !cityrailIsConnectorLine(line));
  const selectedLine = contextLineId
    ? localLines.find(line => String(line.id) === String(contextLineId))
    : null;
  const rows = [];
  const seen = new Set();
  const add = (line, waitStation, relationStation, source) => {
    if (!line || !waitStation || !Array.isArray(line.stationIds)) return;
    const waitStationId = String(waitStation.id);
    const idx = line.stationIds.map(String).indexOf(waitStationId);
    if (idx < 0) return;
    const key = String(line.id) + '|' + waitStationId;
    if (seen.has(key)) return;
    seen.add(key);
    rows.push({ line, station: waitStation, relationStation: relationStation || waitStation, stationIdx: idx, source: source || 'local' });
  };

  if (selectedLine) add(selectedLine, station, station, 'selected-line');
  else localLines.forEach(line => add(line, station, station, 'local-line'));

  const transferRows = [];
  (state.virtualTransfers || []).forEach(vt => {
    const aId = vt && (vt.stationA || vt.fromStationId || vt.from);
    const bId = vt && (vt.stationB || vt.toStationId || vt.to);
    if (String(aId) !== targetId && String(bId) !== targetId) return;
    const stationA = stationById(aId);
    const stationB = stationById(bId);
    const lineA = lineById(vt.lineAId || vt.fromLineId || vt.lineA);
    const lineB = lineById(vt.lineBId || vt.toLineId || vt.lineB);
    if (stationA && stationB && lineA && lineB) transferRows.push({ stationA, stationB, lineA, lineB, sameStation: String(stationA.id) === String(stationB.id), virtualTransfer: vt });
  });

  transferRows.forEach(row => {
    if (!row || !row.stationA || !row.stationB || !row.lineA || !row.lineB) return;
    const allowed = typeof cityrailIsTransferAllowed === 'function'
      ? cityrailIsTransferAllowed(row.stationA.id, row.stationB.id, row.lineA.id, row.lineB.id)
      : true;
    if (!allowed) return;
    const touchesA = String(row.stationA.id) === targetId;
    const touchesB = String(row.stationB.id) === targetId;
    if (touchesA) {
      add(row.lineA, row.stationA, station, 'transfer-local');
      add(row.lineB, row.stationB, station, row.sameStation ? 'transfer-local' : 'transfer-peer');
    }
    if (touchesB) {
      add(row.lineB, row.stationB, station, 'transfer-local');
      add(row.lineA, row.stationA, station, row.sameStation ? 'transfer-local' : 'transfer-peer');
    }
  });

  const sorter = typeof window.cityrailCompareLinesByNumber === 'function'
    ? (a, b) => window.cityrailCompareLinesByNumber(a.line, b.line) || String(a.station && a.station.name || '').localeCompare(String(b.station && b.station.name || ''), 'zh-CN', { numeric:true, sensitivity:'base' })
    : (a, b) => String(a.line && a.line.name || '').localeCompare(String(b.line && b.line.name || ''), 'zh-CN', { numeric:true, sensitivity:'base' });
  return rows.sort(sorter);
}

function renderStationWaitingSection(stationId, contextLineId) {
  const waitingSection = document.getElementById('sd-waiting-section');
  if (!waitingSection) return;
  const rows = cityrailStationPanelWaitingRows(stationId, contextLineId);
  if (!rows.length) {
    waitingSection.innerHTML = '<div class="sd-waiting-empty">无已开启换乘关系的线路</div>';
    return;
  }
  waitingSection.innerHTML = rows.map(row => {
    const line = row.line;
    const waitStation = row.station;
    const stationIds = line.stationIds || [];
    const stnIdxOnLine = row.stationIdx;
    const forwardStationIds = stationIds.slice(stnIdxOnLine + 1);
    const backwardStationIds = stationIds.slice(0, stnIdxOnLine).reverse();
    const fwdRealWaiting = cityrailWaitingCountForLineStationDirection(line, stnIdxOnLine, 0);
    const bwdRealWaiting = cityrailWaitingCountForLineStationDirection(line, stnIdxOnLine, 1);
    const fwdTo = forwardStationIds.length > 0
      ? ((state.stations || []).find(s => String(s.id) === String(forwardStationIds[forwardStationIds.length - 1]))?.name || '—')
      : '终点';
    const bwdTo = backwardStationIds.length > 0
      ? ((state.stations || []).find(s => String(s.id) === String(backwardStationIds[backwardStationIds.length - 1]))?.name || '—')
      : '起点';
    const peerLabel = String(waitStation.id) === String(stationId) ? '' : ` · ${waitStation.name || waitStation.id}`;
    if (window.__CITYRAIL_WAITING_DEBUG__) {
      console.log('[CityRail候车实时统计] 车站面板按已开启换乘关系显示线路候车', {
        stationId, waitingStationId: waitStation.id, line: line.name, forward: fwdRealWaiting, backward: bwdRealWaiting, source: row.source
      });
    }
    return `<div class="sd-waiting-entry" data-waiting-line="${cityrailStationPanelEsc(line.id)}" data-waiting-station="${cityrailStationPanelEsc(waitStation.id)}">
      <div class="sd-waiting-entry-header">
        <span class="sd-waiting-line-dot" style="background:${cityrailStationPanelEsc(line.color || '#9aa0a6')};color:${cityrailStationPanelEsc(line.color || '#9aa0a6')}"></span>
        <span class="sd-waiting-line-name">${cityrailStationPanelEsc((line.name || line.id || '线路') + peerLabel)}</span>
      </div>
      <div class="sd-waiting-dir-row">
        <span class="sd-waiting-dir-label sd-waiting-dir-forward">上行</span>
        <span class="sd-waiting-dir-to">往 ${cityrailStationPanelEsc(fwdTo)}</span>
        <span class="sd-waiting-dir-count">${formatNumber(fwdRealWaiting)} 人</span>
      </div>
      <div class="sd-waiting-dir-row">
        <span class="sd-waiting-dir-label sd-waiting-dir-backward">下行</span>
        <span class="sd-waiting-dir-to">往 ${cityrailStationPanelEsc(bwdTo)}</span>
        <span class="sd-waiting-dir-count">${formatNumber(bwdRealWaiting)} 人</span>
      </div>
    </div>`;
  }).join('');
}

let stationAngleRefreshRaf = 0;

function ensureStationAngleStyle() {
  if (document.getElementById('cityrail-station-angle-style')) return;
  const style = document.createElement('style');
  style.id = 'cityrail-station-angle-style';
  style.textContent = `
    .sd-angle-control{margin:0 0 12px;padding:10px 12px;border:1px solid rgba(255,255,255,.12);border-radius:8px;background:rgba(255,255,255,.045);}
    .sd-angle-head{display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px;}
    .sd-angle-title{font-size:12px;font-weight:700;color:rgba(255,255,255,.86);}
    .sd-angle-mode{font-size:11px;padding:3px 8px;border-radius:999px;border:1px solid rgba(255,255,255,.14);background:rgba(255,255,255,.06);color:rgba(255,255,255,.72);cursor:pointer;}
    .sd-angle-mode:hover{border-color:var(--accent);color:var(--accent);}
    .sd-angle-wrap{display:grid;grid-template-columns:minmax(0,1fr) 74px;gap:10px;align-items:center;}
    .sd-angle-wrap input[type="range"]{width:100%;accent-color:var(--accent);cursor:pointer;}
    .sd-angle-wrap input[type="number"]{width:74px;padding:5px 7px;border-radius:7px;border:1px solid rgba(255,255,255,.14);background:rgba(0,0,0,.22);color:var(--text);font-size:12px;outline:none;}
    .sd-angle-wrap input[type="number"]:focus{border-color:var(--accent);box-shadow:0 0 0 2px rgba(79,195,247,.16);}
    .sd-angle-note{margin-top:6px;font-size:11px;line-height:1.35;color:rgba(255,255,255,.48);}
    html.cityrail-light-ui .sd-angle-control{background:rgba(255,255,255,.78);border-color:rgba(15,23,42,.12);}
    html.cityrail-light-ui .sd-angle-title{color:rgba(15,23,42,.82);}
    html.cityrail-light-ui .sd-angle-mode{background:rgba(15,23,42,.045);border-color:rgba(15,23,42,.14);color:rgba(15,23,42,.62);}
    html.cityrail-light-ui .sd-angle-wrap input[type="number"]{background:#fff;color:#172033;border-color:rgba(15,23,42,.16);}
    html.cityrail-light-ui .sd-angle-note{color:rgba(15,23,42,.52);}
  `;
  document.head.appendChild(style);
}

function stationPanelAngleValue(station) {
  if (!station) return 0;
  if (stationHasManualAngle(station)) return normalizeStationAngleDeg(station.angleDeg);
  const lines = getStationLines(station.id) || [];
  const line = lines[0];
  return line ? normalizeStationAngleDeg(getLineStationAngle(station.id, line)) : 0;
}

function refreshStationAngleGeometry(stationId, options = {}) {
  const station = state.stations.find(s => s.id === stationId);
  if (!station) return false;
  const lines = getStationLines(station.id) || [];
  const allPolys = stationTransferPolygons[station.id] || [];
  allPolys.forEach(poly => {
    const line = lines.find(l => String(l.id) === String(poly._lineId));
    if (!line) return;
    const pos = getStationPosition(station, line.id);
    const len = getLinePlatformLength(station.id, line);
    const angle = getLineStationAngle(station.id, line);
    poly.setLatLngs(computeStationCorners(pos.lat, pos.lng, len, STATION_WIDTH, angle));
  });
  if (options.refreshLines !== false) {
    lines.forEach(line => {
      try { refreshLinePolyline(line); } catch(e) {}
    });
  }
  try { refreshTransferCorridorsNow(); } catch(e) {}
  try { renderAllTrainMarkers(); } catch(e) {}
  allPolys.forEach(poly => { try { poly.bringToFront(); } catch(e) {} });
  return true;
}

function scheduleStationAngleGeometryRefresh(stationId, options = {}) {
  if (stationAngleRefreshRaf) cancelAnimationFrame(stationAngleRefreshRaf);
  stationAngleRefreshRaf = requestAnimationFrame(() => {
    stationAngleRefreshRaf = 0;
    refreshStationAngleGeometry(stationId, options);
  });
}

function renderStationAngleControl(station) {
  if (!station) return;
  ensureStationAngleStyle();
  const slot = document.getElementById('sd-angle-slot');
  if (!slot) return;
  let wrap = document.getElementById('sd-angle-control');
  if (!wrap) {
    wrap = document.createElement('div');
    wrap.id = 'sd-angle-control';
    wrap.className = 'sd-angle-control';
  }
  if (wrap.parentNode !== slot) slot.appendChild(wrap);
  const manual = stationHasManualAngle(station);
  const angle = stationPanelAngleValue(station);
  wrap.innerHTML =
    '<div class="sd-angle-head">' +
      '<div class="sd-angle-title">站台角度</div>' +
      '<button type="button" id="sd-angle-reset" class="sd-angle-mode" title="恢复为沿线路自动计算的方向">' + (manual ? '恢复自动' : '自动方向') + '</button>' +
    '</div>' +
    '<div class="sd-angle-wrap">' +
      '<input id="sd-station-angle" type="range" min="0" max="359" step="1" value="' + angle + '" title="滑动调整车站模型方向">' +
      '<input id="sd-station-angle-num" type="number" min="0" max="359" step="1" value="' + angle + '" title="输入车站模型角度">' +
    '</div>' +
    '<div class="sd-angle-note">' + (manual ? '已使用手动角度，连接线路会跟随刷新。' : '当前跟随线路方向，可滑动改为手动角度。') + '</div>';

  const range = document.getElementById('sd-station-angle');
  const num = document.getElementById('sd-station-angle-num');
  const reset = document.getElementById('sd-angle-reset');
  const applyAngle = (value, persist) => {
    const next = normalizeStationAngleDeg(value);
    station.angleDeg = next;
    station.angleManual = true;
    if (range) range.value = String(next);
    if (num) num.value = String(next);
    scheduleStationAngleGeometryRefresh(station.id, { refreshLines: true });
    invalidateFlowCache();
    if (persist) {
      try { buildODMatrix(); } catch(e) {}
      saveState();
    }
  };
  if (range) {
    range.addEventListener('input', () => applyAngle(range.value, false));
    range.addEventListener('change', () => applyAngle(range.value, true));
  }
  if (num) {
    num.addEventListener('input', () => applyAngle(num.value, false));
    num.addEventListener('change', () => applyAngle(num.value, true));
  }
  if (reset) {
    reset.addEventListener('click', () => {
      delete station.angleDeg;
      delete station.angleManual;
      refreshStationAngleGeometry(station.id, { refreshLines: true });
      invalidateFlowCache();
      try { buildODMatrix(); } catch(e) {}
      saveState();
      renderStationAngleControl(station);
    });
  }
}

function cityrailRenderStationTransferPanel(station) {
  const transferSection = document.getElementById('sd-transfer-section');
  const transferToggles = document.getElementById('sd-transfer-toggles');
  if (!transferSection || !transferToggles || !station) return;

  const stationId = String(station.id);
  const stationName = station.name || station.id || '车站';
  const lineByLocalId = id => (state.lines || []).find(line => String(line && line.id) === String(id)) || null;
  const stationByLocalId = id => (state.stations || []).find(item => String(item && item.id) === String(id)) || null;
  const relationKeyFor = (a, b, la, lb) => {
    if (typeof cityrailTransferRelationKey === 'function') return cityrailTransferRelationKey(a, b, la, lb);
    return [String(a), String(b)].sort().join('~') + '|' + [String(la), String(lb)].sort().join('|');
  };
  const formatDistance = meters => Number.isFinite(Number(meters)) ? Math.round(Number(meters)) + ' m' : '';
  const transferTypeLabel = type => ({
    platform_same: '同站换乘',
    short_corridor: '短通道',
    long_corridor: '长通道',
    virtual: '虚拟换乘'
  }[String(type || '')] || '换乘');
  const rows = new Map();
  const pushRow = row => {
    if (!row || !row.stationA || !row.stationB || !row.lineA || !row.lineB) return;
    const key = relationKeyFor(row.stationA.id, row.stationB.id, row.lineA.id, row.lineB.id);
    if (!rows.has(key) || row.source === 'existing') rows.set(key, Object.assign({ key }, row));
  };

  const stationLines = (getStationLines(station.id) || []).filter(line =>
    line && !cityrailIsConnectorLine(line) && Array.isArray(line.stationIds) && line.stationIds.map(String).includes(stationId)
  );
  const seenLineIds = new Set();
  const uniqueLines = stationLines.filter(line => {
    const id = String(line.id);
    if (seenLineIds.has(id)) return false;
    seenLineIds.add(id);
    return true;
  });
  for (let i = 0; i < uniqueLines.length; i++) {
    for (let j = i + 1; j < uniqueLines.length; j++) {
      const lineA = uniqueLines[i];
      const lineB = uniqueLines[j];
      const info = typeof cityrailGetLinePairTransferInfo === 'function'
        ? cityrailGetLinePairTransferInfo(station.id, station.id, lineA.id, lineB.id)
        : null;
      pushRow({
        stationA: station,
        stationB: station,
        lineA,
        lineB,
        sameStation: true,
        source: 'same-station',
        info: info || { distanceM: 0, type: 'platform_same', label: '同站换乘', penaltyMin: TRANSFER_PENALTY_MIN }
      });
    }
  }

  (state.virtualTransfers || []).forEach(vt => {
    const aId = vt && (vt.stationA || vt.fromStationId || vt.from);
    const bId = vt && (vt.stationB || vt.toStationId || vt.to);
    if (String(aId) !== stationId && String(bId) !== stationId) return;
    const stationA = stationByLocalId(aId);
    const stationB = stationByLocalId(bId);
    const lineA = lineByLocalId(vt.lineAId || vt.fromLineId || vt.lineA);
    const lineB = lineByLocalId(vt.lineBId || vt.toLineId || vt.lineB);
    if (!stationA || !stationB || !lineA || !lineB) return;
    pushRow({
      stationA,
      stationB,
      lineA,
      lineB,
      sameStation: String(stationA.id) === String(stationB.id),
      source: 'existing',
      virtualTransfer: vt,
      info: {
        distanceM: Number(vt.distanceM),
        type: vt.type || 'virtual',
        label: transferTypeLabel(vt.type || 'virtual'),
        penaltyMin: Number(vt.penaltyMin || vt.penalty || TRANSFER_PENALTY_MIN)
      }
    });
  });

  if (typeof cityrailGetTransferCandidateRows === 'function') {
    cityrailGetTransferCandidateRows(station.id).forEach(row => {
      pushRow(Object.assign({}, row, { source: row.sameStation ? 'same-station' : 'candidate' }));
    });
  }

  transferToggles.innerHTML = '';
  const list = Array.from(rows.values()).sort((a, b) => {
    const da = Number(a.info && a.info.distanceM);
    const db = Number(b.info && b.info.distanceM);
    return (Number.isFinite(da) ? da : 999999) - (Number.isFinite(db) ? db : 999999);
  });
  const needsReview = station._transferNeedsReview || (state.transferReselectNeeded && state.transferReselectNeeded[station.id]);
  if (!list.length && !needsReview) {
    transferSection.style.display = 'none';
    return;
  }
  transferSection.style.display = 'block';
  if (needsReview) {
    const review = document.createElement('div');
    review.className = 'sd-transfer-review';
    review.style.cssText = 'font-size:12px;line-height:1.45;color:rgba(255,204,102,.95);background:rgba(255,204,102,.12);border:1px solid rgba(255,204,102,.22);border-radius:10px;padding:8px 10px;margin-bottom:6px;';
    review.textContent = '站位或线路拓扑已变化，请重新确认本站相关换乘关系。';
    transferToggles.appendChild(review);
  }
  if (!list.length) {
    const empty = document.createElement('div');
    empty.className = 'sd-waiting-empty';
    empty.textContent = '暂无可配置换乘关系';
    transferToggles.appendChild(empty);
    return;
  }

  list.forEach(row => {
    const allowed = typeof cityrailIsTransferAllowed === 'function'
      ? cityrailIsTransferAllowed(row.stationA.id, row.stationB.id, row.lineA.id, row.lineB.id)
      : true;
    const peer = String(row.stationA.id) === stationId ? row.stationB : row.stationA;
    const title = row.sameStation
      ? `${row.lineA.name || row.lineA.id} ↔ ${row.lineB.name || row.lineB.id}`
      : `${stationName} · ${row.lineA.name || row.lineA.id} ↔ ${(peer && (peer.name || peer.id)) || '车站'} · ${row.lineB.name || row.lineB.id}`;
    const meta = [
      row.sameStation ? '同站' : ((peer && (peer.name || peer.id)) || '相邻站'),
      transferTypeLabel(row.info && row.info.type),
      formatDistance(row.info && row.info.distanceM),
      Number.isFinite(Number(row.info && row.info.penaltyMin)) ? `罚时 ${Number(row.info.penaltyMin)} 分钟` : ''
    ].filter(Boolean).join(' · ');
    const item = document.createElement('div');
    item.className = 'sd-transfer-row';
    item.style.cssText = 'display:grid;grid-template-columns:minmax(0,1fr)auto;gap:8px;align-items:center;padding:8px 9px;border-radius:8px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);';
    const text = document.createElement('div');
    text.style.cssText = 'min-width:0;';
    const name = document.createElement('div');
    name.textContent = title;
    name.style.cssText = 'font-size:12px;font-weight:760;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
    const sub = document.createElement('div');
    sub.textContent = meta;
    sub.style.cssText = 'margin-top:3px;font-size:11px;color:rgba(255,255,255,.55);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
    text.appendChild(name);
    text.appendChild(sub);

    const actions = document.createElement('div');
    actions.style.cssText = 'display:flex;gap:6px;align-items:center;';
    const toggle = document.createElement('button');
    toggle.type = 'button';
    toggle.textContent = allowed ? '已开启' : '已关闭';
    toggle.setAttribute('aria-pressed', allowed ? 'true' : 'false');
    toggle.title = allowed ? '点击关闭这组换乘关系' : '点击开启这组换乘关系';
    toggle.style.cssText =
      'height:26px;padding:0 10px;border-radius:7px;border:1px solid ' + (allowed ? 'rgba(52,199,89,.35)' : 'rgba(255,69,58,.35)') + ';cursor:pointer;font-size:11px;font-weight:760;' +
      'background:' + (allowed ? 'rgba(52,199,89,.16)' : 'rgba(255,69,58,.14)') + ';color:' + (allowed ? '#8fe7a0' : '#ffb4ad') + ';';
    toggle.addEventListener('click', e => {
      e.preventDefault();
      e.stopPropagation();
      const nextAllowed = !allowed;
      if (typeof cityrailSetTransferAllowed === 'function') cityrailSetTransferAllowed(row.stationA.id, row.stationB.id, row.lineA.id, row.lineB.id, nextAllowed);
      if (nextAllowed && !row.sameStation && !row.virtualTransfer) {
        state.virtualTransfers = Array.isArray(state.virtualTransfers) ? state.virtualTransfers : [];
        state.virtualTransfers.push({
          stationA: row.stationA.id,
          stationB: row.stationB.id,
          lineAId: row.lineA.id,
          lineBId: row.lineB.id,
          type: row.info && row.info.type || 'virtual',
          penaltyMin: row.info && row.info.penaltyMin || TRANSFER_PENALTY_MIN,
          distanceM: Math.round(Number(row.info && row.info.distanceM) || 0),
          source: 'station-panel',
          updatedAt: Date.now()
        });
      }
      try { saveState(); } catch (err) {}
      openStationDetail(station.id, stationDetailLineId);
    });
    actions.appendChild(toggle);

    if (row.virtualTransfer) {
      const remove = document.createElement('button');
      remove.type = 'button';
      remove.textContent = '删除';
      remove.style.cssText = 'height:26px;padding:0 9px;border-radius:7px;border:1px solid rgba(255,69,58,.30);background:rgba(255,69,58,.10);color:#ffb4ad;cursor:pointer;font-size:11px;font-weight:760;';
      remove.addEventListener('click', e => {
        e.preventDefault();
        e.stopPropagation();
        state.virtualTransfers = (state.virtualTransfers || []).filter(vt => vt !== row.virtualTransfer);
        if (typeof cityrailSetTransferAllowed === 'function') cityrailSetTransferAllowed(row.stationA.id, row.stationB.id, row.lineA.id, row.lineB.id, false);
        try { saveState(); } catch (err) {}
        openStationDetail(station.id, stationDetailLineId);
      });
      actions.appendChild(remove);
    }
    item.appendChild(text);
    item.appendChild(actions);
    transferToggles.appendChild(item);
	  });
	}

let cityrailCoreStationPanelSectionsInstalled = false;
function cityrailInstallCoreStationPanelSections() {
  if (cityrailCoreStationPanelSectionsInstalled) return true;
  const api = window.CityRailStationPanelControl;
  if (!api || typeof api.registerSection !== 'function') return false;
  api.registerSection('station-angle', context => {
    if (context && context.renderAngle !== false) renderStationAngleControl(context.station);
    return true;
  }, { order:10 });
  api.registerSection('station-transfer', context => {
    cityrailRenderStationTransferPanel(context && context.station);
    return true;
  }, { order:20 });
  api.registerSection('station-actions', context => {
    const station = context && context.station;
    if (!station) return false;
    renderStationLineActions(station.id);
    cityrailRefreshStationExternalPassengerButton(station);
    return true;
  }, { order:30 });
  cityrailCoreStationPanelSectionsInstalled = true;
  return true;
}

function cityrailRenderStationPanelUnified(station, options = {}) {
  if (!station) return false;
  const lineId = options.lineId != null ? options.lineId : stationDetailLineId;
  try {
    cityrailInstallCoreStationPanelSections();
    const api = window.CityRailStationPanelControl;
    if (api && typeof api.render === 'function') {
      api.render(station.id, lineId, Object.assign({ phase: options.phase || 'render' }, options));
    }
  } catch(e) {}
  return true;
}

function openStationDetail(stationId, lineId) {
  if (drawNewLine) return;
  const station = state.stations.find(s => s.id === stationId);
  if (!station) return;
  const stationPanel = document.getElementById('station-detail-panel');
  const accentLine = (lineId != null ? state.lines.find(l => String(l.id) === String(lineId)) : null)
    || getStationLines(stationId)[0]
    || null;
  if (stationPanel) stationPanel.style.setProperty('--cr-object-accent', normalizeHexColor(accentLine && accentLine.color || '#0a84ff'));

  stationDetailId = stationId;
  stationDetailLineId = lineId || null;
  window.stationDetailId = stationDetailId;
  window.stationDetailLineId = stationDetailLineId;
  document.getElementById('station-detail-overlay').classList.remove('hidden');

  // 关闭线路配置面板（互斥）
  closeLineConfig();

  // Update station name & hide editor
  const nameEl = document.getElementById('sd-station-name');
  if (nameEl) nameEl.textContent = station.name;
  document.getElementById('sd-name-editor').classList.add('hidden');

  // Render zone type buttons - v138.8: 一个车站可同时选择多个功能区，OD 采用权重混合而不是单一类型覆盖。
  const zoneRow = document.getElementById('sd-zone-row');
  if (zoneRow) {
    zoneRow.classList.add('sd-zone-grid');
    zoneRow.innerHTML = '';
    const syncZoneButtons = () => {
      const set = new Set(getStationZoneTypes(station));
      zoneRow.querySelectorAll('button[data-zone]').forEach(b => {
        const on = set.has(b.dataset.zone);
        b.classList.toggle('on', on);
        b.setAttribute('aria-pressed', on ? 'true' : 'false');
      });
    };
    ZONE_ORDER.forEach(type => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'sd-zone-btn';
      btn.textContent = ZONE_TYPES[type] ? ZONE_TYPES[type].label : type;
      btn.dataset.zone = type;
      btn.title = '切换 ' + btn.textContent + ' 功能区';
      btn.addEventListener('click', () => {
        const set = new Set(getStationZoneTypes(station));
        if (set.has(type) && set.size > 1) set.delete(type);
        else set.add(type);
        station.zoneTypes = Array.from(set).filter(z => ZONE_TYPES[z]);
        station.zoneType = station.zoneTypes[0] || 'residential';
        station.__manualZoneTypes = true;
        odMatrixCache = null;
        buildODMatrix();
        try {
          if (typeof window.cityrailRefreshDemandAndPanels === 'function') {
            window.cityrailRefreshDemandAndPanels('station-zone-change', { stationId: station.id, lineId });
          }
        } catch(e) {}
        syncZoneButtons();
        saveState();
      });
      zoneRow.appendChild(btn);
    });
    const hint = document.createElement('div');
    hint.className = 'sd-zone-hint';
    hint.textContent = '可多选：客流按所有已选功能区混合计算。至少保留一个功能区。';
    zoneRow.appendChild(hint);
    syncZoneButtons();
  }
  cityrailRenderStationPanelUnified(station, { lineId, phase: 'open-frame' });

  renderStationRealtimeOD(stationId);
  renderStationWaitingSection(stationId, lineId);

  // Reset move mode
		  const moveBtn = document.getElementById('sd-btn-move');
		  moveBtn.classList.remove('active-action');
		  moveBtn.textContent = '移动车站';
		  document.getElementById('sd-move-hint').style.display = 'none';

  // Remember which line was clicked (for extend/branch context)
  stationDetailLineId = lineId || null;

  cityrailRenderStationPanelUnified(station, { lineId, phase: 'ready', renderAngle: false });
}

function closeStationDetail() {
  document.getElementById('station-detail-overlay').classList.add('hidden');
  // Cancel any in-progress drag
  finishStationDrag(false);
  stationDetailId = null;
  stationDetailLineId = null;
  window.stationDetailId = null;
  window.stationDetailLineId = null;
  moveLineId = null;
  const moveBtn = document.getElementById('sd-btn-move');
  if (moveBtn) { moveBtn.classList.remove('active-action'); moveBtn.textContent = '移动车站'; }
  const hint = document.getElementById('sd-move-hint');
  if (hint) hint.style.display = 'none';
  const picker = document.getElementById('sd-line-picker');
  if (picker) picker.style.display = 'none';
  // Hide branch config
  const branchCfg = document.getElementById('sd-branch-config');
  if (branchCfg) branchCfg.style.display = 'none';
}

// Render extend / branch buttons based on station position on each line
function renderStationLineActions(stationId) {
  const extendBtn = document.getElementById('sd-btn-extend-line');
  const branchBtn = document.getElementById('sd-btn-branch-line');
  const branchCfg = document.getElementById('sd-branch-config');
  if (!extendBtn || !branchBtn) return;

  if (branchCfg) branchCfg.style.display = 'none';

  const lines = getStationLines(stationId);
  const selectedLine = stationDetailLineId
    ? lines.find(line => String(line.id) === String(stationDetailLineId))
    : null;
  const endpointLines = lines
    .map(line => ({ line, idx: line.stationIds.indexOf(stationId) }))
    .filter(item => item.idx === 0 || item.idx === item.line.stationIds.length - 1);
  const selectedEndpoint = selectedLine
    ? endpointLines.find(item => String(item.line.id) === String(selectedLine.id))
    : null;
  const extendTarget = selectedEndpoint || endpointLines[0] || null;
  const branchTarget = selectedLine || lines[0] || null;

  extendBtn.disabled = !extendTarget;
  extendBtn.dataset.stationId = stationId;
  extendBtn.dataset.lineId = extendTarget ? extendTarget.line.id : '';
  extendBtn.textContent = '延长线路';
  extendBtn.title = !lines.length
    ? '接入线路后可延长线路'
    : (extendTarget ? `从本站继续延长「${extendTarget.line.name || extendTarget.line.id}」` : '只有线路端点站可以延长线路');
  extendBtn.onclick = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (!extendTarget) return;
    startExtendLine(extendTarget.line.id, stationId, extendTarget.idx);
  };

  branchBtn.disabled = !branchTarget;
  branchBtn.dataset.stationId = stationId;
  branchBtn.dataset.lineId = branchTarget ? branchTarget.id : '';
  branchBtn.textContent = '建设支线';
  branchBtn.title = branchTarget
    ? (lines.length > 1 ? `从「${branchTarget.name || branchTarget.id}」分出支线` : '从本站为当前线路建设支线')
    : '接入线路后可从本站建设支线';
  branchBtn.onclick = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (!branchTarget) return;
    showBranchConfig(branchTarget, stationId);
  };
}

// ---------- EXTEND LINE ----------
function startExtendLine(lineId, stationId, stationIdx) {
  const line = state.lines.find(l => l.id === lineId);
  if (!line) return;
  const station = state.stations.find(s => s.id === stationId);
  if (!station) return;

  // Close station detail
  closeStationDetail();

  // Enter draw mode for extension
  const fromStart = (stationIdx === 0);
  drawNewLine = {
    name: line.name + (fromStart ? '（延长）' : ''),
    color: line.color,
    tempStations: [station],
    tempWaypoints: [],
    previewLine: null,
    waypointMarkers: [],
    createdStationIds: [],
    extendLineId: lineId,
    startFromStation: stationId,
    extendFromStart: fromStart,
  };

  document.getElementById('draw-line-indicator').classList.remove('hidden');
  document.getElementById('draw-line-hint').textContent =
    `▸ 延长线路「${line.name}」· 左键放置车站 · 右键放置节点`;
  document.getElementById('draw-tooltip').classList.remove('hidden');
  map.getContainer().style.cursor = 'crosshair';
}

// ---------- BRANCH LINE ----------
let branchConfigParentLineId = null;
let branchConfigStationId = null;

function scrollStationPanelToBranchConfig() {
  const cfg = document.getElementById('sd-branch-config');
  if (!cfg) return;
  cfg.style.display = 'block';
  cfg.classList.remove('hidden');

  const panel = document.getElementById('station-detail-panel');
  const scrollRootFor = () => {
    const candidates = [];
    let node = cfg.parentElement;
    while (node && node !== document.body) {
      candidates.push(node);
      if (node === panel) break;
      node = node.parentElement;
    }
    if (panel && !candidates.includes(panel)) candidates.push(panel);
    for (const el of candidates) {
      const style = window.getComputedStyle ? getComputedStyle(el) : null;
      const canScroll = !style || /(auto|scroll)/.test(style.overflowY || style.overflow || '');
      if (canScroll && el.scrollHeight > el.clientHeight + 2) return el;
    }
    const body = panel && panel.querySelector('.cityrail-object-panel-body');
    return body || panel || cfg.parentElement;
  };
  const run = () => {
    try {
      const scrollRoot = scrollRootFor();
      if (scrollRoot && typeof scrollRoot.scrollTo === 'function') {
        const panelRect = scrollRoot.getBoundingClientRect();
        const cfgRect = cfg.getBoundingClientRect();
        const targetTop = Math.max(0, scrollRoot.scrollTop + cfgRect.top - panelRect.top - 14);
        scrollRoot.scrollTo({ top: targetTop, behavior: 'smooth' });
      } else if (typeof cfg.scrollIntoView === 'function') {
        cfg.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
      }
      cfg.classList.add('cityrail-branch-config-focus');
      clearTimeout(cfg.__cityrailBranchFocusTimer);
      cfg.__cityrailBranchFocusTimer = setTimeout(() => {
        cfg.classList.remove('cityrail-branch-config-focus');
      }, 1200);
      const firstControl = document.getElementById('branch-train-type');
      if (firstControl && typeof firstControl.focus === 'function') {
        setTimeout(() => {
          try { firstControl.focus({ preventScroll: true }); }
          catch (err) { firstControl.focus(); }
        }, 220);
      }
    } catch (err) {
      if (typeof cfg.scrollIntoView === 'function') {
        cfg.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
      }
    }
  };

  if (typeof requestAnimationFrame === 'function') requestAnimationFrame(run);
  else setTimeout(run, 0);
}
window.cityrailScrollToBranchConfig = scrollStationPanelToBranchConfig;

function showBranchConfig(parentLine, stationId) {
  normalizeLineTrainType(parentLine);
  cityrailSetLineNodeFocus(parentLine.id, 'showBranchConfig');
  branchConfigParentLineId = parentLine.id;
  branchConfigStationId = stationId;

  const cfg = document.getElementById('sd-branch-config');
  cfg.style.display = 'block';
  document.getElementById('branch-config-name').textContent = parentLine.name + '支线';

  // Populate train type
  const ttSelect = document.getElementById('branch-train-type');
  ttSelect.innerHTML = Object.entries(TRAIN_TYPES).map(([key, t]) =>
    `<option value="${key}" ${parentLine.trainType === key ? 'selected' : ''}>${t.name} — ${t.desc} (${t.capPerCar}人/节)</option>`
  ).join('');

  // Populate cars
  const carSelect = document.getElementById('branch-cars');
  carSelect.innerHTML = CAR_COUNTS.map(n =>
    `<option value="${n}" ${(parentLine.cars || 6) === n ? 'selected' : ''}>${n}节编组</option>`
  ).join('');

  // Populate speed
  const speedSelect = document.getElementById('branch-speed');
  speedSelect.innerHTML = SPEED_LEVELS.map(v =>
    `<option value="${v}" ${(parentLine.speed || 80) === v ? 'selected' : ''}>${v} km/h</option>`
  ).join('');

  scrollStationPanelToBranchConfig();
}

function startBranchLine(trainType, cars, speed, parentLineId, stationId) {
  const parentLine = state.lines.find(l => l.id === parentLineId);
  if (!parentLine) return;
  const station = state.stations.find(s => s.id === stationId);
  if (!station) return;

  // Close station detail
  closeStationDetail();

  const branchName = parentLine.name + '支线';
  drawNewLine = {
    name: branchName,
    color: parentLine.color,
    tempStations: [station],
    tempWaypoints: [],
    previewLine: null,
    waypointMarkers: [],
    createdStationIds: [],
    parentLineId: parentLine.id,
    startFromStation: stationId,
    branchTrainType: trainType,
    branchCars: cars,
    branchSpeed: speed,
    // 支线与主线的换乘时间为2分钟（默认5分钟）
    branchTransferPenalty: 2,
  };

  document.getElementById('draw-line-indicator').classList.remove('hidden');
  document.getElementById('draw-line-hint').textContent =
    `▸ 建设支线「${branchName}」· 左键放置车站 · 右键放置节点`;
  document.getElementById('draw-tooltip').classList.remove('hidden');
  map.getContainer().style.cursor = 'crosshair';
}

// Branch config dialog buttons
document.getElementById('branch-config-cancel').addEventListener('click', () => {
  document.getElementById('sd-branch-config').style.display = 'none';
  branchConfigParentLineId = null;
  branchConfigStationId = null;
});

document.getElementById('branch-config-start').addEventListener('click', () => {
  const trainType = document.getElementById('branch-train-type').value;
  const cars = parseInt(document.getElementById('branch-cars').value);
  const speed = parseInt(document.getElementById('branch-speed').value);
  startBranchLine(trainType, cars, speed, branchConfigParentLineId, branchConfigStationId);
});

function refreshStationDetail(stationId) {
  const moveBtn = document.getElementById('sd-btn-move');
  const stationMoveActive = (moveBtn && moveBtn.classList.contains('active-action')) || !!dragStationId;
  // Do not re-render the detail panel while station move mode is active.
  // Re-rendering calls openStationDetail(), which resets the move button and
  // makes “移动车站” look like it does nothing before the user can drag.
  if (stationMoveActive) return;
  if (stationDetailId === stationId && !document.getElementById('station-detail-overlay').classList.contains('hidden')) {
    openStationDetail(stationId);
  }
}

