function deleteCurrentConfigLine() {
  exitEditMode();
  const overlay = document.getElementById('line-config-overlay');
  const lineId = overlay && overlay.dataset ? overlay.dataset.lineId : '';
  if (!lineId) return;
  const api = window.CityRailTopologyEditAuthority;
  const result = api && typeof api.deleteLine === 'function'
    ? api.deleteLine(lineId)
    : (typeof deleteLineWithStations === 'function' ? deleteLineWithStations(lineId) : null);
  const finish = out => {
    if (out && out.cancelled) return;
    closeLineConfig();
  };
  if (result && typeof result.then === 'function') result.then(finish);
  else finish(result);
}
