function getOpenRailwayOverlay() {
  if (typeof L === 'undefined' || typeof map === 'undefined' || !map) return null;
  const ormPane = cityrailEnsureOpenRailwayPane();
  if (window.__cityrailOrmOverlay) {
    const currentPane = String(window.__cityrailOrmOverlay.options && window.__cityrailOrmOverlay.options.pane || '');
    const containerPane = window.__cityrailOrmOverlay._container && window.__cityrailOrmOverlay._container.parentNode;
    const wantedPane = map.getPane && map.getPane(ormPane);
    if (currentPane !== ormPane || (wantedPane && containerPane && containerPane !== wantedPane)) {
      try { if (map.hasLayer(window.__cityrailOrmOverlay)) map.removeLayer(window.__cityrailOrmOverlay); } catch(e) {}
      window.__cityrailOrmOverlay = null;
    }
  }
  if (!window.__cityrailOrmOverlay) {
    window.__cityrailOrmOverlay = L.tileLayer(cityrailMapTileProxyUrl('openrailway'), {
      attribution: '&copy; OpenStreetMap contributors & OpenRailwayMap',
      subdomains: 'abc',
      maxZoom: 19,
      opacity: 0.86,
      updateWhenZooming: CITYRAIL_MAP_ZOOM_PROFILE.tileUpdateWhenZooming,
      updateWhenIdle: CITYRAIL_MAP_ZOOM_PROFILE.tileUpdateWhenIdle,
      updateInterval: CITYRAIL_MAP_ZOOM_PROFILE.overlayTileUpdateInterval,
      keepBuffer: CITYRAIL_MAP_ZOOM_PROFILE.overlayKeepBuffer,
      fadeAnimation: false,
      pane: ormPane,
      className: 'cityrail-openrailway-overlay',
      cityrailOverlay: 'openrailway',
      cityrailOpenRailwayOverlay: true,
      cityrailCoord: CITYRAIL_COORD_WGS84,
      coordSystem: CITYRAIL_COORD_WGS84,
      coordinateSystem: CITYRAIL_COORD_WGS84
    });
    cityrailSetTileLayerZ(window.__cityrailOrmOverlay, CITYRAIL_OVERLAY_TILE_Z);
  } else if (window.__cityrailOrmOverlay.options) {
    window.__cityrailOrmOverlay.options.pane = ormPane;
    window.__cityrailOrmOverlay.options.cityrailOverlay = 'openrailway';
    window.__cityrailOrmOverlay.options.cityrailOpenRailwayOverlay = true;
    window.__cityrailOrmOverlay.options.cityrailCoord = CITYRAIL_COORD_WGS84;
    window.__cityrailOrmOverlay.options.coordSystem = CITYRAIL_COORD_WGS84;
    window.__cityrailOrmOverlay.options.coordinateSystem = CITYRAIL_COORD_WGS84;
  }
  return window.__cityrailOrmOverlay;
}
window.__cityrailGetOpenRailwayOverlay = getOpenRailwayOverlay;
function setOpenRailwayEnabled(on) {
  state.showOpenRailway = !!on;
  const layer = getOpenRailwayOverlay();
  if (layer && typeof map !== 'undefined' && map) {
    if (on && !map.hasLayer(layer)) layer.addTo(map);
    if (!on && map.hasLayer(layer)) map.removeLayer(layer);
    cityrailSetTileLayerZ(layer, CITYRAIL_OVERLAY_TILE_Z);
    try {
      const pane = map.getPane && map.getPane(CITYRAIL_OPENRAILWAY_PANE);
      if (pane) {
        pane.style.setProperty('z-index', String(CITYRAIL_OVERLAY_TILE_Z), 'important');
        pane.style.setProperty('pointer-events', 'none', 'important');
      }
    } catch(e) {}
    cityrailRestoreActiveBaseLayerCoordinate('openrailway-toggle');
  }
  try { localStorage.setItem('cityrail_orm_overlay', on ? '1' : '0'); } catch(e) {}
  const toggle = document.getElementById('st-openrailway');
  if (toggle) { toggle.classList.toggle('on', !!on); toggle.classList.toggle('off', !on); }
  return !!on;
}
function syncOpenRailwayBasemapCycle() {
  // OpenRailway 是覆盖图层，不参与底图循环。
  try {
    if (typeof layerKeys !== 'undefined' && Array.isArray(layerKeys)) {
      for (let i = layerKeys.length - 1; i >= 0; i--) {
        if (String(layerKeys[i]).toLowerCase() === 'openrailway' || String(layerKeys[i]).toLowerCase() === 'gray') layerKeys.splice(i, 1);
      }
      if (typeof currentLayerIdx !== 'undefined' && currentLayerIdx >= layerKeys.length) currentLayerIdx = 0;
    }
    if (typeof tileLayers !== 'undefined' && tileLayers.openrailway) {
      try {
        if (!window.__cityrailOrmOverlay) window.__cityrailOrmOverlay = tileLayers.openrailway;
        cityrailSetTileLayerZ(window.__cityrailOrmOverlay, CITYRAIL_OVERLAY_TILE_Z);
        if (!state.showOpenRailway && typeof map !== 'undefined' && map.hasLayer(window.__cityrailOrmOverlay)) map.removeLayer(window.__cityrailOrmOverlay);
      } catch(e) {}
    }
    cityrailRefreshOpenRailwayOverlay('sync-cycle');
  } catch(e) {}
}

function updateSettingsUI() {
  syncOpenRailwayBasemapCycle();
  ['trains','labels','openrailway','light-ui'].forEach(key => {
    const el = document.getElementById(key === 'openrailway' ? 'st-openrailway' : (key === 'light-ui' ? 'st-light-ui' : `st-${key}`));
    if (!el) return;
    const on = key === 'trains' ? state.showTrains : (key === 'labels' ? state.showLabels : (key === 'light-ui' ? !!state.lightUi : !!state.showOpenRailway));
    el.className = 'settings-toggle ' + (on ? 'on' : 'off');
  });
}

