let drawNewLine = null; // { name, color, tempStations: [{id,lat,lng,name}], tempWaypoints: [{id,lat,lng,segIdx}], previewLine, waypointMarkers: [L.circleMarker] }
let cityrailDrawVirtualTransferTimer = 0;
let cityrailDrawVirtualTransferQueue = new Set();

function cityrailLineHasLiveTrains(line) {
  if (!line || line.id == null || !Array.isArray(state.trains)) return false;
  const lineId = String(line.id);
  return state.trains.some(train => train && train.state !== 'done' && String(train.lineId) === lineId);
}

function cityrailScheduleDrawVirtualTransferReview(stationIds, reason) {
  const ids = (Array.isArray(stationIds) ? stationIds : [stationIds])
    .map(id => String(id == null ? '' : id))
    .filter(Boolean);
  if (!ids.length) return;
  ids.forEach(id => cityrailDrawVirtualTransferQueue.add(id));
  if (cityrailDrawVirtualTransferTimer) clearTimeout(cityrailDrawVirtualTransferTimer);
  cityrailDrawVirtualTransferTimer = setTimeout(async () => {
    cityrailDrawVirtualTransferTimer = 0;
    const pending = Array.from(cityrailDrawVirtualTransferQueue);
    cityrailDrawVirtualTransferQueue = new Set();
    let changed = false;
    for (const stationId of pending) {
      try {
        const before = Array.isArray(state.virtualTransfers) ? state.virtualTransfers.length : 0;
        const result = await checkAndPromptVirtualTransfer(stationId);
        const after = Array.isArray(state.virtualTransfers) ? state.virtualTransfers.length : 0;
        if ((result && (result.created > 0 || result.prompted > 0)) || after !== before) changed = true;
      } catch(e) {
        if (window.__CITYRAIL_DEBUG__) console.warn('[CityRail Draw] virtual transfer review failed', reason, stationId, e);
      }
    }
    if (changed) {
      invalidateFlowCache();
      updateUI();
      if (state.isSimulating) runSimulation();
      saveState();
    }
  }, 450);
}

function cityrailCommitDrawLineMutation(reason, line, options) {
  options = options || {};
  const stationIds = Array.isArray(options.stationIds)
    ? options.stationIds.slice()
    : (line && Array.isArray(line.stationIds) ? line.stationIds.slice() : []);
  invalidateFlowCache();
  updateUI();
  if (options.refreshTrains !== false && cityrailLineHasLiveTrains(line)) {
    cityrailRefreshTrainsAfterTopologyEdit(reason || 'drawLineMutation', [line]);
  }
  if (state.isSimulating) runSimulation();
  saveState();
  cityrailScheduleDrawVirtualTransferReview(stationIds, reason || 'drawLineMutation');
}

function setNewBuildMode(mode){
  const title = document.querySelector('#new-line-dialog h2');
  const choice = document.getElementById('new-build-choice');
  const form = document.getElementById('new-line-form');
  const start = document.getElementById('new-line-start');
  const back = document.getElementById('new-line-back');
  if(mode === 'line'){
    if(title) title.textContent = '新建线路';
    if(choice) choice.classList.add('hidden');
    if(form) form.classList.remove('hidden');
    if(start) start.classList.remove('hidden');
    if(back) back.classList.remove('hidden');
    const input = document.getElementById('new-line-name');
    if(input) setTimeout(() => input.focus(), 0);
    return;
  }
  if(title) title.textContent = '新建';
  if(choice) choice.classList.remove('hidden');
  if(form) form.classList.add('hidden');
  if(start) start.classList.add('hidden');
  if(back) back.classList.add('hidden');
}

