// Cancel drawing
function cancelDrawLine() {
  if (cityrailDrawVirtualTransferTimer) {
    clearTimeout(cityrailDrawVirtualTransferTimer);
    cityrailDrawVirtualTransferTimer = 0;
  }
  cityrailDrawVirtualTransferQueue = new Set();
  if (drawNewLine && drawNewLine.tempStations.length > 0) {
    // When extending/branching, skip the starting station (it's an existing station)
    const stationsToRemove = drawNewLine.startFromStation
      ? drawNewLine.tempStations.slice(1)
      : drawNewLine.tempStations;
    stationsToRemove.forEach(s => {
      state.stations = state.stations.filter(ss => ss.id !== s.id);
      removeStationPolygons(s.id);
    });
    if (stationsToRemove.length > 0) {
      invalidateFlowCache();
      updateUI();
      saveState();
    }
  }
  if (drawNewLine && drawNewLine.previewLine) {
    map.removeLayer(drawNewLine.previewLine);
  }
  // Remove waypoint markers
  if (drawNewLine && drawNewLine.waypointMarkers) {
    drawNewLine.waypointMarkers.forEach(m => map.removeLayer(m));
  }
  drawNewLine = null;
  document.getElementById('draw-line-indicator').classList.add('hidden');
  document.getElementById('draw-tooltip').classList.add('hidden');
  map.getContainer().style.cursor = '';
  try { if (window.CityRailMapGameInputV326 && typeof window.CityRailMapGameInputV326.refreshMode === 'function') window.CityRailMapGameInputV326.refreshMode('draw-cancel'); } catch(e) {}
}

