// Map click handler for drawing new line — LEFT CLICK = station
map.on('click', (e) => {
  if (!drawNewLine) return;
  if (window.CityRailMapGameInputV326 && typeof window.CityRailMapGameInputV326.shouldSuppressBuildClick === 'function' && window.CityRailMapGameInputV326.shouldSuppressBuildClick(e)) return;
  if (triangleClicked) return;
  const ll = cityrailEventDataLatLng(e);
  if (!ll) return;
  const { lat, lng } = ll;
  const snappedStation = findDrawSnapStation(lat, lng);
  if (snappedStation && handleDrawExistingStation(snappedStation)) {
    return;
  }

  // Create station
  const usedNames = state.stations.map(s => s.name);
  const rank = state.stations.length + 1;
  const population = cityrailInitialStationPopulation(lat, lng, rank);
  const name = getRandomName(usedNames);
  const station = {
    id: genId(),
    name,
    lat, lng,
    population,
    zoneTypes: inferZoneTypesByArea(lat, lng, { name }),
    zoneType: inferZoneTypeByArea(lat, lng),
  };
  station.zoneType = station.zoneTypes[0] || station.zoneType || 'residential';
  station.__cityrailAutoZoneVersion = 'v302-realistic-multi-zone';
  applyCityStationRealism(station);
  const previousStation = drawNewLine.tempStations[drawNewLine.tempStations.length - 1];
  if (previousStation) {
    setDrawCompletedStationDistance(previousStation, station, Math.max(0, drawNewLine.tempStations.length - 1));
  }
  state.stations.push(station);
  renderStation(station);
  if (typeof window.cityrailRequestAutoStationName === 'function') {
    setTimeout(() => window.cityrailRequestAutoStationName(station, lat, lng), 0);
  }
  drawNewLine.tempStations.push(station);
  drawNewLine.createdStationIds = drawNewLine.createdStationIds || [];
  drawNewLine.createdStationIds.push(station.id);

  // Update preview line (including waypoints between stations)
  updateDrawPreview();

  // Update hint
  const cnt = drawNewLine.tempStations.length;
  const wpCnt = drawNewLine.tempWaypoints.length;
  document.getElementById('draw-line-hint').textContent =
    `▸ 已放置 ${cnt} 个车站${wpCnt > 0 ? ' · ' + wpCnt + ' 个节点' : ''}${previousStation ? ' · ' + drawLastCompletedDistanceText() : ''} · 继续点击或点「完成」`;
  refreshDrawTooltipContent();

  drawNewLine.hasUncommittedChanges = true;
});

