// Helper: rebuild preview polyline from stations + waypoints
function updateDrawPreview() {
  if (!drawNewLine) return;

  // Build ordered points: station 0 → [waypoints seg0] → station 1 → [waypoints seg1] → ...
  const pts = [];
  for (let i = 0; i < drawNewLine.tempStations.length; i++) {
    pts.push([drawNewLine.tempStations[i].lat, drawNewLine.tempStations[i].lng]);
    if (i < drawNewLine.tempStations.length - 1) {
      const segWps = drawNewLine.tempWaypoints
        .filter(w => w.segIdx === i)
        .sort((a, b) => drawNewLine.tempWaypoints.indexOf(a) - drawNewLine.tempWaypoints.indexOf(b));
      segWps.forEach(w => pts.push([w.lat, w.lng]));
    }
  }
  if (drawNewLine.cursorLatLng && drawNewLine.tempStations.length > 0) {
    const i = drawNewLine.tempStations.length - 1;
    const segWps = drawNewLine.tempWaypoints
      .filter(w => w.segIdx === i)
      .sort((a, b) => drawNewLine.tempWaypoints.indexOf(a) - drawNewLine.tempWaypoints.indexOf(b));
    segWps.forEach(w => pts.push([w.lat, w.lng]));
    pts.push([drawNewLine.cursorLatLng.lat, drawNewLine.cursorLatLng.lng]);
  }

  if (pts.length >= 2) {
    const curvePts = bezierDensePath(pts, 12);
    if (drawNewLine.previewLine && typeof drawNewLine.previewLine.setLatLngs === 'function') {
      drawNewLine.previewLine.setLatLngs(curvePts);
    } else {
      drawNewLine.previewLine = L.polyline(curvePts, cityrailStaticGeometryOptions({
        color: drawNewLine.color,
        weight: 3,
        opacity: 0.7,
        dashArray: '10 6',
        lineCap: 'round',
        lineJoin: 'round',
        interactive: false,
      })).addTo(map);
    }
  } else if (drawNewLine.previewLine) {
    map.removeLayer(drawNewLine.previewLine);
    drawNewLine.previewLine = null;
  }
}

function scheduleDrawPreview(latlng) {
  if (!drawNewLine) return;
  if (latlng) drawNewLine.cursorLatLng = { lat: latlng.lat, lng: latlng.lng };
  if (drawNewLine.previewRaf) return;
  drawNewLine.previewRaf = requestAnimationFrame(() => {
    if (!drawNewLine) return;
    drawNewLine.previewRaf = 0;
    updateDrawPreview();
    refreshDrawTooltipContent();
  });
}

