      picker.style.display = 'none';
      // Find the matching polygon and enter move mode
      const allPolys = stationTransferPolygons[station.id] || [];
      const targetPoly = allPolys.find(p => p._lineId === lineId) || allPolys[0];
      const moveBtn = document.getElementById('sd-btn-move');
      const moveHint = document.getElementById('sd-move-hint');
      enterMoveMode(targetPoly, moveBtn, moveHint, picker);
