function enterMoveMode(polygon, btn, hint, picker) {
  if (picker) picker.style.display = 'none';
  btn.classList.add('active-action');
  btn.textContent = '拖动中...';
  hint.style.display = 'block';
  polygon.setStyle({ fillOpacity: 0.55, weight: 2, color: '#fff', opacity: 1 });
  // Start the drag session immediately. Historical CSS and SVG ownership patches
  // can swallow the polygon mousedown event, leaving the move button active but
  // never assigning dragStationId. Map mousemove now has one reliable owner.
  dragStationId = stationDetailId;
  dragLineId = moveLineId || polygon._lineId || null;
  dragPolygon = polygon;
  map.dragging.disable();
  map.getContainer().style.cursor = 'grabbing';
}

