;/* ===== bundled module: js/legacy/91-real-flow-display.js ===== */
/* Extracted from original index.html during low-risk modular refactor. Execution order is preserved. */
(function(){
"use strict";

/*
显示口径修正：
控制中心所有客流显示使用真实 PassengerBatch 统计：
- 全网总客流 = max(累计生成客流, 累计送达客流 + 当前候车 + 当前车载)
- 全网候车 = 当前 stationWaitingPool.waiting
- 出站客流/客票收入 = 到达最终 destinationId 后的真实出站批次
- 控制中心线路表“客流量” = 当日累计乘坐该线的乘客人数，来自 _lineRidership / lineStatsData
*/

function n(v){ return Number.isFinite(Number(v)) ? Number(v) : 0; }
function fmt(v){
  try{ return typeof formatNumber === "function" ? formatNumber(Math.round(v)) : Math.round(v).toLocaleString(); }
  catch(e){ return Math.round(v).toLocaleString(); }
}

function realStats(){
  let waiting = 0;
  let onboard = 0;
  let exited = n(state._exitFlow || state._totalDelivered);
  let entered = n(state._totalGenerated);

  if(state.stationWaitingPool){
    for(const sid in state.stationWaitingPool){
      waiting += n(state.stationWaitingPool[sid].waiting);
    }
  }

  if(Array.isArray(state.trains)){
    for(const t of state.trains){
      if(t && t.state !== "done"){
        if(typeof window.getRealTrainPassengerLoad === "function") onboard += n(window.getRealTrainPassengerLoad(t));
        else onboard += n(t.load || t.passengerCount);
      }
    }
  }

  const total = window.cityrailCanonicalPassengerVolume
    ? window.cityrailCanonicalPassengerVolume(state, waiting, onboard)
    : Math.max(entered, exited);
  return {waiting,onboard,exited,entered,total,current:waiting+onboard};
}

function updateRealFlowDisplay(){
  if(!window.state) return;
  const s = realStats();

  const total = document.getElementById("cct-total-flow");
  if(total) total.textContent = fmt(s.total);

  const bigFlow = document.getElementById("cct-big-flow");
  if(bigFlow){
    bigFlow.textContent = fmt(s.total);
    const sub = bigFlow.parentElement && bigFlow.parentElement.querySelector(".ctrl-big-sub");
    if(sub) sub.textContent = "全网总客流";
  }

  const inbound = document.getElementById("cct-big-inbound");
  if(inbound){
    inbound.textContent = fmt(s.total);
    const sub = inbound.parentElement && inbound.parentElement.querySelector(".ctrl-big-sub");
    if(sub) sub.textContent = "全网总客流";
  }

  // cct-big-outbound may be客票收入 patch; do not overwrite if it says 客票收入.
  const out = document.getElementById("cct-big-outbound");
  if(out){
    const sub = out.parentElement && out.parentElement.querySelector(".ctrl-big-sub");
    if(sub && sub.textContent !== "客票收入"){
      out.textContent = fmt(s.exited);
      sub.textContent = "出站客流";
    }
  }

  const intensity = document.getElementById("cct-intensity");
  if(intensity){
    let len = 0;
    if(state.lineLengthCache && state.lines){
      state.lines.forEach(l => len += n(state.lineLengthCache[l.id]));
    }
    if(len > 0) intensity.textContent = fmt(s.total / len) + "/km";
  }
}

const oldRender = window.renderCtrlCenter;
if(!window.__CITYRAIL_DISABLE_LEGACY_CONTROL_CENTER__ && typeof oldRender === "function" && !oldRender.__realFlowDisplayWrapped){
  window.renderCtrlCenter = function(){
    const r = oldRender.apply(this, arguments);
    updateRealFlowDisplay();
    return r;
  };
  window.renderCtrlCenter.__realFlowDisplayWrapped = true;
}

window.cityrailRealPassengerStats = realStats;
})();

