;/* CityRail Apple-style city badge owner */
(function(){
  'use strict';
  const W = window;
  const D = document;
  const lightLayers = [];
  function badge(){ return D.getElementById('city-badge'); }
  function cityName(city){
    return String((city && (city.zh || city.name || city.cityName)) || (W.state && (W.state.cityName || W.state.activeCityName)) || '').trim();
  }
  function setBadge(city){
    const el = badge();
    const text = el && el.querySelector('.city-cn');
    if(!el || !text) return;
    const name = cityName(city);
    text.textContent = name;
    el.classList.toggle('visible', !!name);
  }
  function syncTheme(key){
    const el = badge();
    if(!el) return;
    el.classList.remove('map-light', 'map-satellite');
    if(key === 'satellite') el.classList.add('map-satellite');
    else if(lightLayers.includes(String(key || ''))) el.classList.add('map-light');
  }
  function currentLayerKey(){
    try{ if(Array.isArray(W.layerKeys) && typeof W.currentLayerIdx === 'number') return W.layerKeys[W.currentLayerIdx]; }catch(e){}
    return '';
  }
  function syncCurrent(){
    setBadge(W.__cityrailCurrentCityProfile || (W.state && W.state.cityProfile) || null);
    syncTheme(currentLayerKey());
  }
  W.cityrailSetCityBadge = setBadge;
  W.cityrailSyncCityBadgeTheme = syncTheme;
  if(D.readyState === 'loading') D.addEventListener('DOMContentLoaded', syncCurrent, { once:true });
  else syncCurrent();
  setTimeout(syncCurrent, 400);
  setTimeout(syncCurrent, 1400);
})();

