    const ctrl=byId('btn-ctrl-center'), newLine=byId('btn-new-line');
    if(ctrl && ctrl.parentNode===top){ if(btn.parentNode!==top) top.insertBefore(btn,ctrl.nextSibling); else if(btn.previousElementSibling!==ctrl) top.insertBefore(btn,ctrl.nextSibling); }
