  function bindScroll(lineId,mode){ const ov=byId('line-config-v137-overlay')||byId('line-config-v135-overlay'); if(!ov) return; const sc=ov.querySelector('.cr135-scroll'), rg=ov.querySelector('.cr135-range'); if(!sc||!rg) return; const key=sid(lineId)+'|'+sid(mode); const max=Math.max(0,sc.scrollWidth-sc.clientWidth); rg.max=String(Math.max(1,max)); rg.value=String(Math.min(max,num(owner.scroll[key],sc.scrollLeft))); sc.scrollLeft=Math.min(max,num(owner.scroll[key],sc.scrollLeft)); sc.onscroll=()=>{owner.scroll[key]=sc.scrollLeft; rg.value=String(sc.scrollLeft);}; rg.oninput=()=>{sc.scrollLeft=num(rg.value,0); owner.scroll[key]=sc.scrollLeft;}; }
