  function selectedTrainPanel(line,selected){ if(!selected) return '<section class="cr135-selected-panel" data-ats-side-section="selected-train"><div class="cr135-panel-head"><h3>列车选择</h3><span class="cr135-pill">待选择</span></div><div class="cr135-note">未选择列车。</div></section>'; const cmd=selected._dispatchTurnbackNext?'折返待命':(selected._dispatchHold?'扣车':(selected._dispatchSkipNext?'跳停':'常规')),load=num(selected.passengers||selected.load,0); return `<section class="cr135-selected-panel" data-ats-side-section="selected-train"><div class="cr135-panel-head"><h3>已选列车</h3><span class="cr135-pill">${esc(cmd)}</span></div><div class="cr135-selected-grid"><div><span>种别</span><b>${esc(trainServiceLabel(selected))}</b></div><div><span>方向</span><b>${trainDir(selected)===0?'上行':'下行'}</b></div><div><span>当前位置</span><b>${esc(trainStationName(line,selected,'currentStationId'))}</b></div><div><span>下一站</span><b>${esc(trainStationName(line,selected,'nextStationId'))}</b></div><div><span>运行状态</span><b>${esc(trainStateLabel(selected))}</b></div><div><span>载客</span><b>${fmt(load)}人</b></div></div></section>`; }
