  function atsDot(a,b){ return a&&b ? a.x*b.x+a.y*b.y : Infinity; }
  function atsBranchOutVector(branchIds,parentIds,parentIdx,branchIdx){
    const junctionId=parentIds[parentIdx];
    if(branchIdx===0) return atsVectorBetween(junctionId,branchIds[1]);
    if(branchIdx===branchIds.length-1) return atsVectorBetween(junctionId,branchIds[branchIds.length-2]);
    return atsVectorBetween(junctionId,branchIds[branchIdx+1]);
  }
  function atsThroughMainSide(parentIds,branchIds,parentIdx,branchIdx){
    const junctionId=parentIds[parentIdx], bv=atsBranchOutVector(branchIds,parentIds,parentIdx,branchIdx);
    if(!bv) return parentIdx>0?'start':'end';
    const prev=parentIdx>0 ? atsVectorBetween(junctionId,parentIds[parentIdx-1]) : null;
    const next=parentIdx<parentIds.length-1 ? atsVectorBetween(junctionId,parentIds[parentIdx+1]) : null;
    if(prev&&!next) return 'start';
    if(next&&!prev) return 'end';
    return atsDot(bv,next)<atsDot(bv,prev) ? 'end' : 'start';
  }
  function throughAtsInfo(line){
    if(!line) return null;
    let parent=line, branch=null;
    if(line.throughOperationEnabled && line.throughBranchLineId){
      branch=lineById(line.throughBranchLineId);
    }else{
      const p=lineById(line.throughParentLineId||line.parentLineId);
      if(p && p.throughOperationEnabled && sid(p.throughBranchLineId)===sid(line.id)){ parent=p; branch=line; }
    }
    if(!parent||!branch) return null;
    const parentIds=lineStations(parent), branchIds=lineStations(branch);
    if(parentIds.length<2||branchIds.length<2) return null;
    let parentIdx=-1, branchIdx=-1;
    for(let i=0;i<parentIds.length;i++){
      const j=branchIds.findIndex(id=>sid(id)===sid(parentIds[i]));
      if(j>=0){ parentIdx=i; branchIdx=j; break; }
    }
    if(parentIdx<0||branchIdx<0) return null;
    let tail=[];
    if(branchIdx===0) tail=branchIds.slice(1);
    else if(branchIdx===branchIds.length-1) tail=branchIds.slice(0,-1).reverse();
    else tail=branchIds.slice(branchIdx+1);
    if(!tail.length) return null;
    const side=atsThroughMainSide(parentIds,branchIds,parentIdx,branchIdx);
    const parentDisplayIds=side==='end' ? parentIds.slice().reverse() : parentIds.slice();
    const displayJunctionIdx=parentDisplayIds.findIndex(id=>sid(id)===sid(parentIds[parentIdx]));
    const routeIds=parentDisplayIds.slice(0,displayJunctionIdx+1).concat(tail);
    return {
      parent, branch, parentIds:parentDisplayIds, branchIds, branchRouteIds:routeIds,
      parentIdx:displayJunctionIdx, originalParentIdx:parentIdx, branchIdx, junctionId:parentIds[parentIdx],
      displayJunctionIdx:sid(line.id)===sid(branch.id)?branchIdx:displayJunctionIdx,
      throughMainSide:side
    };
  }
