    try { if (m.boxZoom && typeof m.boxZoom.disable === 'function') m.boxZoom.disable(); } catch(e) {}
    try { if (m.touchZoom && typeof m.touchZoom.enable === 'function') m.touchZoom.enable(); } catch(e) {}
