/* ===== CityRail storage siding service ===== */
(function(){
  'use strict';
  const W = window, D = document, VERSION = 'storage-siding-v4';
  const MAX_CAPACITY = 2;
  const DIRECTION_MODES = ['auto','up','down'];
  const sid = v => String(v == null ? '' : v);
  const num = (v, d = 0) => { const n = Number(v); return Number.isFinite(n) ? n : d; };
  const S = () => W.state || {};
  const report = { version:VERSION, dispatches:0, returns:0, overflowRetired:0, clearedPassengers:0, last:null };
  let recordSerial = 0;

  function stations(){ return Array.isArray(S().stations) ? S().stations : []; }
  function lines(){ return Array.isArray(S().lines) ? S().lines : []; }
  function trains(){ const st = S(); if(!Array.isArray(st.trains)) st.trains = []; return st.trains; }
  function stationById(id){ return stations().find(st => sid(st && st.id) === sid(id)) || null; }
  function lineById(id){ return lines().find(line => sid(line && line.id) === sid(id)) || null; }
  function lineContainsStation(line, stationId){ return !!(line && Array.isArray(line.stationIds) && line.stationIds.some(id => sid(id) === sid(stationId))); }
  function clampCapacity(value){ return Math.max(0, Math.min(MAX_CAPACITY, Math.round(num(value, 0)))); }
  function normalizeDirectionMode(value){ return DIRECTION_MODES.includes(sid(value)) ? sid(value) : 'auto'; }
  function nowSec(){ return ((num(S().simulationHour, 0) * 3600) % 86400 + 86400) % 86400; }
  function firstSec(line){ return ((num(line && line.firstTrain, 6) * 3600) % 86400 + 86400) % 86400; }
  function lastSec(line){ return ((num(line && line.lastTrain, 22) * 3600) % 86400 + 86400) % 86400; }
  function inService(line, sec = nowSec()){
    const first = firstSec(line), last = lastSec(line);
    if(first === last) return true;
    return first < last ? sec >= first && sec < last : (sec >= first || sec < last);
  }
  function serviceJustEnded(line, sec){
    const prev = !!(line && line._storageSidingInService);
    const current = inService(line, sec);
    if(line) line._storageSidingInService = current;
    return prev && !current;
  }

  function byLine(station){
    if(!station || typeof station !== 'object') return {};
    if(!station.storageSidingsByLine || typeof station.storageSidingsByLine !== 'object') station.storageSidingsByLine = {};
    return station.storageSidingsByLine;
  }
  function configFor(stationId, lineId, create){
    const station = stationById(stationId);
    if(!station) return null;
    const map = byLine(station);
    const key = sid(lineId);
    if(!map[key] && create) map[key] = { capacity:0, storedTrains:[], updatedAt:Date.now() };
    const cfg = map[key] || null;
    if(cfg){
      cfg.capacity = clampCapacity(cfg.capacity);
      cfg.directionMode = normalizeDirectionMode(cfg.directionMode);
      if(!Array.isArray(cfg.storedTrains)) cfg.storedTrains = [];
      cfg.storedTrains = cfg.storedTrains.filter(Boolean).slice(0, cfg.capacity);
    }
    return cfg;
  }
  function capacityForStationLine(stationId, lineId){
    const cfg = configFor(stationId, lineId, false);
    return cfg ? clampCapacity(cfg.capacity) : 0;
  }
  function storedTrains(stationId, lineId){
    const cfg = configFor(stationId, lineId, false);
    return cfg && Array.isArray(cfg.storedTrains) ? cfg.storedTrains.slice() : [];
  }
  function directionModeForStationLine(stationId, lineId){
    const cfg = configFor(stationId, lineId, false);
    return cfg ? normalizeDirectionMode(cfg.directionMode) : 'auto';
  }
  function stationStorageLines(stationId){
    const station = stationById(stationId);
    const map = station && byLine(station);
    return Object.keys(map || {}).map(lineId => ({ line:lineById(lineId), lineId, config:map[lineId] }))
      .filter(item => item.line && lineContainsStation(item.line, stationId) && clampCapacity(item.config && item.config.capacity) > 0);
  }
  function storageStationsForLine(line){
    if(!line) return [];
    return stations().map(st => ({ station:st, config:configFor(st.id, line.id, false) }))
      .filter(item => item.config && clampCapacity(item.config.capacity) > 0 && lineContainsStation(line, item.station.id));
  }
  function activeStorageCount(stationId, lineId){
    return trains().filter(train =>
      train &&
      train._storageSidingOrigin &&
      !['done','removed','archived','inactive'].includes(sid(train.state)) &&
      sid(train._storageSidingStationId) === sid(stationId) &&
      sid(train.lineId) === sid(lineId)
    ).length;
  }
  function dispatchSpacingSec(line){
    let headway = 240;
    try {
      if(W.CityRailDispatchAuthorityV300 && typeof W.CityRailDispatchAuthorityV300.headwaySec === 'function') headway = W.CityRailDispatchAuthorityV300.headwaySec(line);
      else if(typeof getCurrentHeadway === 'function') headway = getCurrentHeadway(line);
    } catch(e) {}
    return Math.max(90, Math.min(600, num(headway, 240)));
  }
  function defaultDirection(line, stationId, slot){
    const ids = Array.isArray(line && line.stationIds) ? line.stationIds.map(sid) : [];
    const idx = ids.indexOf(sid(stationId));
    if(idx <= 0) return 0;
    if(idx >= ids.length - 1) return 1;
    return slot % 2 === 0 ? 0 : 1;
  }
  function directionForSlot(line, stationId, slot, cfg){
    const mode = normalizeDirectionMode(cfg && cfg.directionMode);
    if(mode === 'up') return 0;
    if(mode === 'down') return 1;
    return defaultDirection(line, stationId, slot);
  }
  function startupDirectionOrdinalForRecord(line, stationId, cfg, rec, fallbackIndex){
    const slot = Math.max(0, Math.round(num(rec && rec.slot, fallbackIndex)));
    const dir = Number(rec && rec.direction) === 1 ? 1 : 0;
    let ordinal = 0;
    for(let prior = 0; prior < slot; prior++){
      if(directionForSlot(line, stationId, prior, cfg) === dir) ordinal++;
    }
    return ordinal;
  }
  function normalizeStoredRecords(station, line, cfg){
    if(!station || !line || !cfg) return [];
    cfg.directionMode = normalizeDirectionMode(cfg.directionMode);
    cfg.storedTrains = (cfg.storedTrains || [])
      .filter(rec => rec && sid(rec.lineId) === sid(line.id) && sid(rec.stationId) === sid(station.id))
      .slice(0, cfg.capacity)
      .map((rec, index) => {
        const slot = index;
        rec.slot = slot;
        rec.direction = directionForSlot(line, station.id, slot, cfg);
        rec.directionMode = cfg.directionMode;
        return rec;
      });
    return cfg.storedTrains;
  }
  function makeStoredRecord(station, line, slot, cfg){
    const serial = (++recordSerial).toString(36);
    return {
      id:'siding_' + sid(station && station.id) + '_' + sid(line && line.id) + '_' + slot + '_' + Date.now().toString(36) + '_' + serial,
      lineId:line.id,
      stationId:station.id,
      slot,
      direction:directionForSlot(line, station.id, slot, cfg),
      directionMode:normalizeDirectionMode(cfg && cfg.directionMode),
      trainType:line.trainType || 'A',
      cars:num(line.cars || line.carCount, 8),
      storedAtSec:nowSec(),
      storedAt:Date.now()
    };
  }
  function seedStationLine(station, line){
    const cfg = configFor(station && station.id, line && line.id, true);
    if(!cfg || !lineContainsStation(line, station && station.id)) return 0;
    cfg.capacity = clampCapacity(cfg.capacity);
    normalizeStoredRecords(station, line, cfg);
    let added = 0;
    while(cfg.storedTrains.length + activeStorageCount(station.id, line.id) < cfg.capacity){
      cfg.storedTrains.push(makeStoredRecord(station, line, cfg.storedTrains.length, cfg));
      added++;
    }
    cfg.updatedAt = Date.now();
    return added;
  }
  function setCapacity(stationId, lineId, capacity){
    const station = stationById(stationId), line = lineById(lineId);
    if(!station || !line || !lineContainsStation(line, stationId)) return false;
    const cfg = configFor(stationId, lineId, true);
    cfg.capacity = clampCapacity(capacity);
    cfg.storedTrains = (cfg.storedTrains || []).filter(Boolean).slice(0, cfg.capacity);
    seedStationLine(station, line);
    station._storageSidingUpdatedAt = Date.now();
    line._storageSidingUpdatedAt = Date.now();
    line._topologyVersion = (num(line._topologyVersion, 0) || 0) + 1;
    refreshViews('set-capacity');
    saveSoon();
    return true;
  }
  function setDirectionMode(stationId, lineId, mode){
    const station = stationById(stationId), line = lineById(lineId);
    if(!station || !line || !lineContainsStation(line, stationId)) return false;
    const cfg = configFor(stationId, lineId, true);
    cfg.directionMode = normalizeDirectionMode(mode);
    normalizeStoredRecords(station, line, cfg);
    cfg.updatedAt = Date.now();
    station._storageSidingUpdatedAt = Date.now();
    line._storageSidingUpdatedAt = Date.now();
    line._topologyVersion = (num(line._topologyVersion, 0) || 0) + 1;
    refreshViews('set-direction');
    saveSoon();
    return true;
  }
  function saveSoon(){
    try { if(typeof W.saveState === 'function') W.saveState(); else if(typeof saveState === 'function') saveState(); } catch(e) {}
  }
  function refreshViews(reason){
    try { if(W.CityRailAtsLiveV137 && typeof W.CityRailAtsLiveV137.markDirty === 'function') W.CityRailAtsLiveV137.markDirty('storage-siding-' + (reason || 'change')); } catch(e) {}
    try { if(typeof W.renderAllTrainMarkers === 'function') W.renderAllTrainMarkers(); else if(typeof renderAllTrainMarkers === 'function') renderAllTrainMarkers(); } catch(e) {}
    try { if(typeof W.updateControlCenter === 'function') W.updateControlCenter(); } catch(e) {}
  }
  function clearTrainPassengers(train){
    if(!train) return 0;
    const st = S();
    let cleared = 0;
    const ids = Array.isArray(train._passengerIds) ? train._passengerIds.slice() : [];
    const line = lineById(train.lineId);
    const idx = Math.max(0, Math.min((line && line.stationIds ? line.stationIds.length : 1) - 1, Math.round(num(train.nextStationIdx, 0))));
    const stationId = line && line.stationIds ? line.stationIds[idx] : train._storageSidingStationId;
    for(const pid of ids){
      const batch = st._batchMap && st._batchMap[pid];
      if(!batch || batch.state !== 'on_train') continue;
      const count = Math.max(0, Math.round(num(batch.count || batch.remaining || batch.passengers, 0)));
      batch.state = 'waiting';
      batch.trainId = null;
      batch.currentStationId = stationId || batch.currentStationId || batch.originId || null;
      if(batch.currentStationId){
        st.stationWaitingPool = st.stationWaitingPool || {};
        const pool = st.stationWaitingPool[batch.currentStationId] || (st.stationWaitingPool[batch.currentStationId] = { waiting:0, totalArrived:0, totalBoarded:0, totalDelivered:0 });
        pool.waiting = num(pool.waiting, 0) + count;
      }
      try { if(typeof addWaitingIndexV9 === 'function') addWaitingIndexV9(batch); } catch(e) {}
      cleared += count;
    }
    train._passengerIds = [];
    train.load = 0;
    train.passengers = 0;
    train.passengerCount = 0;
    train.onboard = 0;
    train.overloaded = false;
    return cleared;
  }
  function removeTrain(train){
    const st = S();
    try {
      const markers = W.trainMarkers || {};
      if(train && markers[train.id] && typeof map !== 'undefined') {
        map.removeLayer(markers[train.id]);
        delete markers[train.id];
      }
    } catch(e) {}
    if(Array.isArray(st.trains)) st.trains = st.trains.filter(t => t !== train && sid(t && t.id) !== sid(train && train.id));
  }
  function normalizeStorageTrainService(train){
    if(!train || !train._storageSidingOrigin) return false;
    train.serviceType = 'local';
    train.serviceKind = 'local';
    train._throughDepotServiceKind = 'local';
    if(train.routePlan && train.routePlan.expressService) delete train.routePlan.expressService;
    return true;
  }
  function normalizeActiveStorageServices(){
    let changed = 0;
    for(const train of trains()){
      if(normalizeStorageTrainService(train)) changed++;
    }
    return changed;
  }
  function dispatchRecord(line, station, cfg, rec, slotIndex, options = {}){
    if(!line || !station || !cfg || !rec) return false;
    const slot = Math.max(0, Math.round(num(rec.slot, slotIndex)));
    const elapsedSinceFirst = ((nowSec() - firstSec(line)) % 86400 + 86400) % 86400;
    const startupDirectionOrdinal = Math.max(0, Math.round(num(options.startupDirectionOrdinal, 0)));
    const requiredSpacing = (options.forceStartup ? startupDirectionOrdinal : slot) * dispatchSpacingSec(line);
    if(elapsedSinceFirst < requiredSpacing) return false;
    let nodes = [];
    try { if(typeof getLineTrainNodes === 'function') nodes = getLineTrainNodes(line); } catch(e) {}
    const dir = Number(rec.direction) === 1 ? 1 : 0;
    const train = typeof createTrainObj === 'function'
      ? createTrainObj(line, dir, nowSec(), nodes)
      : { id:'storage_train_' + Date.now(), lineId:line.id, direction:dir, state:'dwelling', load:0, maxLoad:1200, _passengerIds:[] };
    train.lineId = line.id;
    train.direction = dir;
    train.serviceType = 'local';
    train.serviceKind = 'local';
    train._throughDepotServiceKind = 'local';
    if(train.routePlan && train.routePlan.expressService) delete train.routePlan.expressService;
    train._spawnSource = 'storage_siding';
    train._storageSidingOrigin = true;
    train._storageSidingStationId = station.id;
    train._storageSidingRecordId = rec.id;
    train._strictHeadwayTrain = true;
    train._strictSpawnReason = 'storage_siding_service_start';
    train._cityrailGeneratedFromStorageSiding = true;
    train._depotPhysicalEntry = true;
    train._depotState = 'in_service';
    const idx = Math.max(0, (line.stationIds || []).map(sid).indexOf(sid(station.id)));
    let placed = false;
    try {
      if(typeof placeTrainAtStationBalanced === 'function') placed = placeTrainAtStationBalanced(train, line, nodes, idx, dir);
    } catch(e) {}
    if(!placed) {
      train.nextStationIdx = idx;
      train.state = 'dwelling';
      train.dwellRemaining = typeof cityrailFixedDwellSeconds === 'function' ? cityrailFixedDwellSeconds(line) : 30;
    }
    normalizeStorageTrainService(train);
    cfg.storedTrains = (cfg.storedTrains || []).filter(item => sid(item && item.id) !== sid(rec.id));
    if(!trains().some(t => sid(t && t.id) === sid(train.id))) trains().push(train);
    report.dispatches++;
    report.last = { type:'dispatch', lineId:line.id, stationId:station.id, at:Date.now(), hour:num(S().simulationHour, 0) };
    return true;
  }
  function returnTrainToSiding(train, reason){
    if(!train || !train._storageSidingOrigin) return false;
    const line = lineById(train.lineId);
    const station = stationById(train._storageSidingStationId);
    const cfg = configFor(station && station.id, line && line.id, false);
    if(!line || !station || !cfg || clampCapacity(cfg.capacity) <= 0) return false;
    normalizeStoredRecords(station, line, cfg);
    const cleared = clearTrainPassengers(train);
    const overflow = cfg.storedTrains.length >= clampCapacity(cfg.capacity);
    if(overflow) report.overflowRetired++;
    else cfg.storedTrains.push(makeStoredRecord(station, line, cfg.storedTrains.length, cfg));
    cfg.updatedAt = Date.now();
    train._storageSidingReturned = true;
    train._storageSidingReturnReason = reason || 'service_end';
    removeTrain(train);
    report.returns++;
    report.clearedPassengers += cleared;
    report.last = { type:'return', lineId:line.id, stationId:station.id, cleared, overflow, at:Date.now(), hour:num(S().simulationHour, 0) };
    return true;
  }
  function returnLine(line, reason){
    let count = 0;
    for(const train of trains().slice()){
      if(train && sid(train.lineId) === sid(line && line.id) && train._storageSidingOrigin) {
        if(returnTrainToSiding(train, reason || 'service_end')) count++;
      }
    }
    return count;
  }
  function serviceTick(reason){
    const sec = nowSec();
    let changed = normalizeActiveStorageServices();
    for(const line of lines()){
      if(!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) continue;
      const active = inService(line, sec);
      if(serviceJustEnded(line, sec)) changed += returnLine(line, 'service_end');
      if(!active) continue;
      const startupKey = [
        Math.floor(num(S().__cityrailServiceDay, 0)),
        sid(line.id),
        Math.round(firstSec(line)),
        Math.round(lastSec(line))
      ].join('|');
      const forceStartup = line._storageSidingStartupDispatchKey !== startupKey;
      for(const item of storageStationsForLine(line)){
        seedStationLine(item.station, line);
        const list = (item.config.storedTrains || []).slice().sort((a,b) => num(a.slot) - num(b.slot));
        for(let i = 0; i < list.length; i++){
          const startupDirectionOrdinal = startupDirectionOrdinalForRecord(line, item.station.id, item.config, list[i], i);
          if(dispatchRecord(line, item.station, item.config, list[i], i, { forceStartup, startupDirectionOrdinal })) changed++;
        }
      }
      if(forceStartup) line._storageSidingStartupDispatchKey = startupKey;
    }
    if(changed) refreshViews(reason || 'tick');
    return changed;
  }
  function installDispatchBridge(){
    const api = W.CityRailDispatchAuthorityV300;
    if(!api || typeof api.dispatchLoop !== 'function' || api.dispatchLoop.__storageSidingBridge) return false;
    const base = api.dispatchLoop;
    const wrapped = function(){
      serviceTick('before-dispatch');
      const result = base.apply(this, arguments);
      serviceTick('after-dispatch');
      return result;
    };
    wrapped.__storageSidingBridge = true;
    wrapped.__original = base;
    api.dispatchLoop = wrapped;
    try { W.dispatchLoop = wrapped; } catch(e) {}
    return true;
  }
  function installUpdateBridge(){
    const base = W.updateTrains || (typeof updateTrains === 'function' ? updateTrains : null);
    if(typeof base !== 'function' || base.__storageSidingServiceNormalize) return false;
    const wrapped = function(){
      normalizeActiveStorageServices();
      const result = base.apply(this, arguments);
      normalizeActiveStorageServices();
      return result;
    };
    wrapped.__storageSidingServiceNormalize = true;
    wrapped.__original = base;
    try { W.updateTrains = updateTrains = wrapped; } catch(e) { W.updateTrains = wrapped; }
    return true;
  }
  function storageLineChoices(station){
    return (Array.isArray(W.state && W.state.lines) ? W.state.lines : [])
      .filter(line => lineContainsStation(line, station && station.id))
      .sort((a,b) => sid(a.name || a.id).localeCompare(sid(b.name || b.id), 'zh-CN', { numeric:true, sensitivity:'base' }));
  }
  function esc(v){ return sid(v).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
  function fmt(v){ const n = Math.max(0, Math.round(num(v, 0))); try { return n.toLocaleString('zh-CN'); } catch(e) { return String(n); } }
  function directionLabel(mode){ return ({ auto:'自动', up:'上行', down:'下行' })[normalizeDirectionMode(mode)] || '自动'; }
  function directionHint(mode){
    mode = normalizeDirectionMode(mode);
    if(mode === 'up') return '存车线车辆优先向线路起点方向发车。';
    if(mode === 'down') return '存车线车辆优先向线路终点方向发车。';
    return '端点站按折返方向发车，中间站按车位均衡分配上下行。';
  }
  function renderStationPanel(stationId, lineId){
    const station = stationById(stationId);
    const panel = D.getElementById('station-detail-panel');
    if(!station || !panel) return false;
    let card = D.getElementById('sd-storage-siding-panel');
    if(!card){
      card = D.createElement('section');
      card.id = 'sd-storage-siding-panel';
    }
    const storageSlot = D.getElementById('sd-storage-siding-slot');
    if(!storageSlot) return false;
    if(card.parentNode !== storageSlot) storageSlot.appendChild(card);
    const choices = storageLineChoices(station);
    const selectedLine = lineById(lineId) && lineContainsStation(lineById(lineId), station.id)
      ? lineById(lineId)
      : choices[0];
    if(!selectedLine){
      card.innerHTML = '<div class="sd-section-title">存车线</div><div class="sd-storage-card"><div class="sd-storage-empty">接入线路后可设置存车线</div></div>';
      return true;
    }
    const cfg = configFor(station.id, selectedLine.id, false);
    const cap = cfg ? clampCapacity(cfg.capacity) : 0;
    const directionMode = directionModeForStationLine(station.id, selectedLine.id);
    const stored = storedTrains(station.id, selectedLine.id).length;
    const active = trains().filter(t => t && t._storageSidingOrigin && sid(t._storageSidingStationId) === sid(station.id) && sid(t.lineId) === sid(selectedLine.id)).length;
    card.innerHTML = `<div class="sd-section-title">存车线</div>
      <div class="sd-storage-card">
        <div class="sd-storage-segment" role="group" aria-label="存车线容量">
          ${[0,1,2].map(v => `<button type="button" data-storage-cap="${v}" data-line-id="${esc(selectedLine.id)}" class="${cap===v?'active':''}">${v===0?'关闭':v+'列'}</button>`).join('')}
        </div>
        <div class="sd-storage-direction" role="group" aria-label="存车线发车方向">
          ${DIRECTION_MODES.map(mode => `<button type="button" data-storage-dir="${esc(mode)}" data-line-id="${esc(selectedLine.id)}" class="${directionMode===mode?'active':''}">${esc(directionLabel(mode))}</button>`).join('')}
        </div>
        <div class="sd-storage-metrics">
          <div><span>存车线内</span><b>${fmt(stored)}</b></div>
          <div><span>已发出</span><b>${fmt(active)}</b></div>
          <div><span>容量上限</span><b>${fmt(cap)}</b></div>
          <div><span>发车方向</span><b>${esc(directionLabel(directionMode))}</b></div>
        </div>
        <div class="sd-storage-note">运营开始按车隔从存车线发车；末班后回存并清空载客。${esc(directionHint(directionMode))}</div>
      </div>`;
    card.querySelectorAll('[data-storage-cap]').forEach(btn => {
      btn.addEventListener('click', ev => {
        ev.preventDefault();
        ev.stopPropagation();
        setCapacity(station.id, btn.dataset.lineId, btn.dataset.storageCap);
        renderStationPanel(station.id, btn.dataset.lineId);
      });
    });
    card.querySelectorAll('[data-storage-dir]').forEach(btn => {
      btn.addEventListener('click', ev => {
        ev.preventDefault();
        ev.stopPropagation();
        setDirectionMode(station.id, btn.dataset.lineId, btn.dataset.storageDir);
        renderStationPanel(station.id, btn.dataset.lineId);
      });
    });
    return true;
  }
  function ensureStationPanelStyle(){
    if(!D.getElementById('cityrail-storage-siding-style')){
      const style = D.createElement('style');
      style.id = 'cityrail-storage-siding-style';
      style.textContent = `
        #sd-storage-siding-panel{margin:8px 0 12px;}
        .sd-storage-card{border:1px solid var(--cr-object-border,rgba(255,255,255,.13));border-left-color:var(--cr-object-accent,#0a84ff);background:var(--cr-object-card,rgba(18,21,27,.76));border-radius:12px;padding:12px;box-shadow:none;}
        .sd-storage-segment,.sd-storage-direction{display:grid;gap:6px;padding:4px;border-radius:10px;background:rgba(5,8,12,.28);border:1px solid var(--cr-object-line,rgba(255,255,255,.095));}
        .sd-storage-segment{grid-template-columns:repeat(3,minmax(0,1fr));}
        .sd-storage-direction{grid-template-columns:repeat(3,minmax(0,1fr));margin-top:7px;}
        .sd-storage-segment button,.sd-storage-direction button{height:30px;border:1px solid transparent;border-radius:8px;background:transparent;color:var(--cr-object-muted,rgba(235,241,248,.62));font-weight:780;cursor:pointer;font-size:12px;box-shadow:none;}
        .sd-storage-segment button.active,.sd-storage-direction button.active{background:var(--cr-object-accent,#0a84ff);border-color:var(--cr-object-accent,#0a84ff);color:#fff;box-shadow:none;}
        .sd-storage-metrics{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:7px;margin-top:10px;}
        .sd-storage-metrics div{border:1px solid var(--cr-object-line,rgba(255,255,255,.095));border-radius:10px;background:rgba(5,8,12,.28);padding:7px 8px;}
        .sd-storage-metrics span{display:block;font-size:10px;color:var(--cr-object-faint,rgba(235,241,248,.42));font-weight:800;}
        .sd-storage-metrics b{display:block;margin-top:2px;font-size:15px;color:var(--cr-object-text,#f8fafc);}
        .sd-storage-note,.sd-storage-empty{margin-top:9px;font-size:11px;line-height:1.45;color:var(--cr-object-muted,rgba(235,241,248,.62));}
        @media (max-width:560px){.sd-storage-metrics{grid-template-columns:repeat(2,minmax(0,1fr));}}
      `;
      D.head.appendChild(style);
    }
    return true;
  }
  function installStationPanelSection(){
    ensureStationPanelStyle();
    const api = W.CityRailStationPanelControl;
    if(!api || typeof api.registerSection !== 'function') return false;
    return api.registerSection('storage-siding', context => renderStationPanel(context && context.stationId, context && context.lineId), { order:55 });
  }
  function boot(reason){
    installDispatchBridge();
    installUpdateBridge();
    installStationPanelSection();
    serviceTick(reason || 'boot');
  }
  W.CityRailStorageSiding = {
    version:VERSION,
    maxCapacity:MAX_CAPACITY,
    setCapacity,
    setDirectionMode,
    capacityForStationLine,
    directionModeForStationLine,
    storedTrains,
    stationStorageLines,
    storageStationsForLine,
    seedStationLine,
    renderStationPanel,
    tick:serviceTick,
    returnTrain:returnTrainToSiding,
    report:() => Object.assign({}, report, {
      sidings:stations().reduce((sum, st) => sum + stationStorageLines(st.id).length, 0),
      stored:stations().reduce((sum, st) => {
        const map = st.storageSidingsByLine || {};
        return sum + Object.keys(map).reduce((a, lineId) => a + storedTrains(st.id, lineId).length, 0);
      }, 0),
      active:trains().filter(t => t && t._storageSidingOrigin).length,
      rows:stations().reduce((rows, st) => rows.concat(stationStorageLines(st.id).map(item => ({
        stationId:st.id,
        stationName:st.name || st.id,
        lineId:item.lineId,
        lineName:item.line && (item.line.name || item.line.id),
        capacity:clampCapacity(item.config && item.config.capacity),
        directionMode:directionModeForStationLine(st.id, item.lineId),
        stored:storedTrains(st.id, item.lineId).length,
        active:activeStorageCount(st.id, item.lineId)
      }))), [])
    })
  };
  if(D.readyState === 'loading') D.addEventListener('DOMContentLoaded', () => boot('dom'), { once:true }); else boot('immediate');
  ['cityrail-save-loaded','cityrail:runtime-integrity','cityrail:dailyPassengerReset'].forEach(name => {
    try { W.addEventListener(name, () => W.setTimeout(() => boot(name), 0)); } catch(e) {}
    try { D.addEventListener(name, () => W.setTimeout(() => boot(name), 0)); } catch(e) {}
  });
  [300,1200,3000,7000].forEach(ms => W.setTimeout(() => boot('timer-' + ms), ms));
})();
